import React, { useEffect, useState, Suspense } from "react";
import {
  BrowserRouter,
  Routes,
  Route,
  Navigate,
  useLocation,
} from "react-router-dom";
import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import ErrorBoundary from "./components/common/ErrorBoundary";
import TopProgressBar from "./components/common/TopProgressBar";
import { ReactQueryDevtools } from "@tanstack/react-query-devtools";
import { AppProvider } from "./contexts/AppContext";
import { ThemeProvider } from "./contexts/ThemeContext";
import { AuthProvider } from "./contexts/AuthContext";
import "./index.css";
import { LoginPage } from "./components/auth/LoginPage";
import { ResetPasswordPage } from "./components/auth/ResetPasswordPage";
import { ProtectedRoute } from "./components/auth/ProtectedRoute";
import { RoleBasedRedirect } from "./components/auth/RoleBasedRedirect";
import { useAppContext } from "./contexts/AppContext";
import { BottomNav, Nav } from "./components/layout";
import { ShopLayout } from "./components/layout/ShopLayout";
import Dashboard from "./components/dashboard/Dashboard";
import RepoErrorPanel from "./components/common/RepoErrorPanel";
import TetTheme from "./components/common/TetTheme";
import { lazyImport } from "./utils/lazyImport";

// Lazy load large components for code splitting
const SalesManager = lazyImport(() => import("./components/sales/SalesManager"));
const InventoryManager = lazyImport(
  () => import("./components/inventory/InventoryManager")
);
// InventoryManagerNew removed - folder moved to __DEPRECATED_backups

// Delivery Manager - Standalone page for delivery orders
const DeliveryManager = lazyImport(() => import("./components/sales/DeliveryManager").then(m => ({ default: m.DeliveryManager })));

// Shop pages - Public access for customers
const ProductCatalog = lazyImport(() => import("./pages/shop/ProductCatalog"));
const PromotionsPage = lazyImport(() => import("./pages/shop/PromotionsPage"));
const MaintenanceGallery = lazyImport(() => import("./pages/shop/MaintenanceGallery"));

// Admin pages - For managing shop content
const PromotionManager = lazyImport(() => import("./pages/admin/PromotionManager"));
const GalleryManager = lazyImport(() => import("./pages/admin/GalleryManager"));

// Delivery Test Page (for testing only)
const DeliveryTest = lazyImport(() => import("./pages/DeliveryTest").then(m => ({ default: m.DeliveryTest })));
const ServiceManager = lazyImport(
  () => import("./components/service/ServiceManager")
);
// ServiceManagerNew removed - folder moved to __DEPRECATED_backups
const ServiceHistory = lazyImport(() =>
  import("./components/service/ServiceHistory").then((m) => ({
    default: m.ServiceHistory,
  }))
);
const CustomerManager = lazyImport(
  () => import("./components/customer/CustomerManager")
);
// CustomerManagerNew removed - folder moved to __DEPRECATED_backups
const DebtManager = lazyImport(() => import("./components/debt/DebtManager"));
// DebtManagerNew removed - folder moved to __DEPRECATED_backups
const CashBook = lazyImport(() => import("./components/finance/CashBook"));
const LoansManager = lazyImport(() => import("./components/finance/LoansManager"));
const FinanceManager = lazyImport(
  () => import("./components/finance/FinanceManager")
);
const PayrollManager = lazyImport(
  () => import("./components/payroll/PayrollManager")
);
const ReportsManager = lazyImport(
  () => import("./components/reports/ReportsManager")
);
// ReportsManagerNew removed - folder moved to __DEPRECATED_backups
const TaxReportExport = lazyImport(
  () => import("./components/reports/TaxReportExport")
);
const EmployeeManager = lazyImport(
  () => import("./components/employee/EmployeeManager")
);
const CategoriesManager = lazyImport(
  () => import("./components/categories/CategoriesManager")
);
const LookupManager = lazyImport(() => import("./components/lookup/LookupManager"));
const AnalyticsDashboard = lazyImport(
  () => import("./components/analytics/AnalyticsDashboard")
);
const AuditLogsViewer = lazyImport(
  () => import("./components/admin/AuditLogsViewer")
);
const MigrationTool = lazyImport(() => import("./components/admin/MigrationTool"));
const SettingsManager = lazyImport(() =>
  import("./components/settings/SettingsManager").then((m) => ({
    default: m.SettingsManager,
  }))
);
const StaffDashboard = lazyImport(() =>
  import("./components/dashboard/StaffDashboard").then((m) => ({
    default: m.StaffDashboard,
  }))
);

// Loading component for Suspense fallback
const PageLoader = () => (
  <div className="flex items-center justify-center min-h-[50vh]">
    <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
  </div>
);

const Sales = () => (
  <Suspense fallback={<PageLoader />}>
    <SalesManager />
  </Suspense>
);
const Inventory = () => (
  <Suspense fallback={<PageLoader />}>
    <InventoryManager />
  </Suspense>
);
// InventoryNew removed - was using deprecated InventoryManagerNew
const Service = () => (
  <Suspense fallback={<PageLoader />}>
    <ServiceManager />
  </Suspense>
);
// ServiceNew removed - was using deprecated ServiceManagerNew
const ServiceHistoryPage = () => {
  const { currentBranchId } = useAppContext();
  return (
    <Suspense fallback={<PageLoader />}>
      <ServiceHistory currentBranchId={currentBranchId} />
    </Suspense>
  );
};
const Customers = () => (
  <Suspense fallback={<PageLoader />}>
    <CustomerManager />
  </Suspense>
);
// CustomersNew removed - was using deprecated CustomerManagerNew
const Debt = () => (
  <Suspense fallback={<PageLoader />}>
    <DebtManager />
  </Suspense>
);
// DebtNew removed - was using deprecated DebtManagerNew
const CashBookPage = () => (
  <Suspense fallback={<PageLoader />}>
    <CashBook />
  </Suspense>
);
const LoansPage = () => (
  <Suspense fallback={<PageLoader />}>
    <LoansManager />
  </Suspense>
);
const FinancePage = () => (
  <Suspense fallback={<PageLoader />}>
    <FinanceManager />
  </Suspense>
);
const PayrollPage = () => (
  <Suspense fallback={<PageLoader />}>
    <PayrollManager />
  </Suspense>
);
const ReportsPage = () => (
  <Suspense fallback={<PageLoader />}>
    <ReportsManager />
  </Suspense>
);
// ReportsPageNew removed - was using deprecated ReportsManagerNew
const TaxReportPage = () => (
  <Suspense fallback={<PageLoader />}>
    <TaxReportExport />
  </Suspense>
);
const EmployeesPage = () => (
  <Suspense fallback={<PageLoader />}>
    <EmployeeManager />
  </Suspense>
);
const CategoriesPage = () => (
  <Suspense fallback={<PageLoader />}>
    <CategoriesManager />
  </Suspense>
);
const LookupPage = () => (
  <Suspense fallback={<PageLoader />}>
    <LookupManager />
  </Suspense>
);
const AnalyticsPage = () => (
  <Suspense fallback={<PageLoader />}>
    <AnalyticsDashboard />
  </Suspense>
);
const SettingsPage = () => (
  <Suspense fallback={<PageLoader />}>
    <SettingsManager />
  </Suspense>
);
const StaffDashboardPage = () => (
  <Suspense fallback={<PageLoader />}>
    <StaffDashboard />
  </Suspense>
);

const queryClient = new QueryClient({
  defaultOptions: {
    queries: {
      staleTime: 2 * 60 * 1000,
      gcTime: 5 * 60 * 1000,
      refetchOnWindowFocus: false,
      refetchOnReconnect: "always",
      retry: 2,
    },
  },
});

// Attach global error handlers using built-in callbacks by extending QueryCache/MutationCache
// Simplified: we rely on per-query onError via a wrapper helper if needed; fallback here is noop.

const MainLayout: React.FC = () => {
  const location = useLocation();
  const isSalesPage = location.pathname === "/sales";
  const isShopPage = ['/san-pham', '/khuyen-mai', '/thu-vien'].includes(location.pathname);

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-900 transition-colors pb-20 md:pb-0 relative overflow-hidden">
      {/* Subtle background watermark logo - centered */}
      {!isShopPage && (
        <div
          className="fixed inset-0 flex items-center justify-center pointer-events-none z-0"
        >
          <img
            src="/logo-smartcare.png"
            alt=""
            className="w-[60vw] h-[60vh] max-w-[500px] max-h-[500px] object-contain opacity-[0.05] dark:opacity-[0.04]"
            style={{
              filter: 'grayscale(100%)',
            }}
          />
        </div>
      )}
      {/* <TetTheme /> */}
      {!isShopPage && <Nav />}
      <main
        className={`max-w-[1600px] mx-auto ${isSalesPage ? "p-0" : "p-0 md:p-6"
          }`}
      >
        <Routes>
          <Route path="/" element={<RoleBasedRedirect />} />
          <Route
            path="/dashboard"
            element={
              <ProtectedRoute requiredRoles={["owner", "manager"]}>
                <Dashboard />
              </ProtectedRoute>
            }
          />
          <Route
            path="/staff-dashboard"
            element={
              <ProtectedRoute requiredRoles={["staff"]}>
                <StaffDashboardPage />
              </ProtectedRoute>
            }
          />
          <Route path="/sales" element={<Sales />} />
          <Route path="/delivery" element={<DeliveryManager />} />
          <Route path="/delivery-test" element={<DeliveryTest />} />
          <Route
            path="/audit-logs"
            element={
              <ProtectedRoute requiredRoles={["owner"]}>
                <Suspense fallback={<PageLoader />}>
                  <AuditLogsViewer />
                </Suspense>
              </ProtectedRoute>
            }
          />
          <Route
            path="/inventory"
            element={
              <ProtectedRoute requiredRoles={["owner", "manager"]}>
                <Inventory />
              </ProtectedRoute>
            }
          />
          {/* /inventory-new route removed - deprecated */}
          <Route path="/categories" element={<CategoriesPage />} />
          <Route path="/lookup" element={<LookupPage />} />
          <Route path="/service" element={<Service />} />
          {/* /service-new route removed - deprecated */}
          <Route path="/service-history" element={<ServiceHistoryPage />} />
          <Route path="/customers" element={<Customers />} />
          {/* /customers-new route removed - deprecated */}
          <Route
            path="/debt"
            element={
              <ProtectedRoute requiredRoles={["owner", "manager"]}>
                <Debt />
              </ProtectedRoute>
            }
          />
          {/* /debt-new route removed - deprecated */}
          <Route
            path="/cashbook"
            element={
              <ProtectedRoute requiredRoles={["owner", "manager"]}>
                <CashBookPage />
              </ProtectedRoute>
            }
          />
          <Route
            path="/loans"
            element={
              <ProtectedRoute requiredRoles={["owner", "manager"]}>
                <LoansPage />
              </ProtectedRoute>
            }
          />
          <Route
            path="/payroll"
            element={
              <ProtectedRoute requiredRoles={["owner", "manager"]}>
                <PayrollPage />
              </ProtectedRoute>
            }
          />
          <Route
            path="/employees"
            element={
              <ProtectedRoute requiredRoles={["owner", "manager"]}>
                <EmployeesPage />
              </ProtectedRoute>
            }
          />
          <Route
            path="/finance"
            element={
              <ProtectedRoute requiredRoles={["owner", "manager"]}>
                <FinancePage />
              </ProtectedRoute>
            }
          />
          <Route
            path="/analytics"
            element={
              <ProtectedRoute requiredRoles={["owner", "manager"]}>
                <AnalyticsPage />
              </ProtectedRoute>
            }
          />
          <Route
            path="/reports"
            element={
              <ProtectedRoute requiredRoles={["owner", "manager"]}>
                <ReportsPage />
              </ProtectedRoute>
            }
          />
          {/* /reports-new route removed - deprecated */}
          <Route
            path="/tax-report"
            element={
              <ProtectedRoute
                requiredRoles={["owner", "manager", "accountant"]}
              >
                <TaxReportPage />
              </ProtectedRoute>
            }
          />
          <Route
            path="/settings"
            element={
              <ProtectedRoute requiredRoles={["owner", "manager"]}>
                <SettingsPage />
              </ProtectedRoute>
            }
          />
          {/* Admin Shop Pages - Manage shop content */}
          <Route
            path="/admin/khuyen-mai"
            element={
              <ProtectedRoute requiredRoles={["owner", "manager"]}>
                <Suspense fallback={<PageLoader />}>
                  <PromotionManager />
                </Suspense>
              </ProtectedRoute>
            }
          />
          <Route
            path="/admin/thu-vien"
            element={
              <ProtectedRoute requiredRoles={["owner", "manager"]}>
                <Suspense fallback={<PageLoader />}>
                  <GalleryManager />
                </Suspense>
              </ProtectedRoute>
            }
          />
          <Route
            path="/admin/migration"
            element={
              <ProtectedRoute requiredRoles={["owner"]}>
                <Suspense fallback={<PageLoader />}>
                  <MigrationTool />
                </Suspense>
              </ProtectedRoute>
            }
          />
        </Routes>
      </main>
      {/* Bottom Navigation for Mobile */}
      {!isShopPage && <BottomNav />}
    </div>
  );
};

export default function App() {
  return (
    <QueryClientProvider client={queryClient}>
      <ThemeProvider>
        <AuthProvider>
          <AppProvider>
            <BrowserRouter>
              <ErrorBoundary>
                <TopProgressBar />
                <Routes>
                  {/* Public Routes - No authentication */}
                  <Route path="/login" element={<LoginPage />} />
                  <Route
                    path="/reset-password"
                    element={<ResetPasswordPage />}
                  />

                  {/* Public Shop Pages - No authentication required */}
                  <Route
                    path="/san-pham"
                    element={
                      <ShopLayout>
                        <Suspense fallback={<PageLoader />}>
                          <ProductCatalog />
                        </Suspense>
                      </ShopLayout>
                    }
                  />
                  <Route
                    path="/khuyen-mai"
                    element={
                      <ShopLayout>
                        <Suspense fallback={<PageLoader />}>
                          <PromotionsPage />
                        </Suspense>
                      </ShopLayout>
                    }
                  />
                  <Route
                    path="/thu-vien"
                    element={
                      <ShopLayout>
                        <Suspense fallback={<PageLoader />}>
                          <MaintenanceGallery />
                        </Suspense>
                      </ShopLayout>
                    }
                  />

                  {/* Protected Routes - Require authentication */}
                  <Route
                    path="/*"
                    element={
                      <ProtectedRoute>
                        <MainLayout />
                      </ProtectedRoute>
                    }
                  />
                </Routes>
                <ReactQueryDevtools initialIsOpen={false} />
                {/* Dev-only repository error panel */}
                {import.meta.env.DEV && <RepoErrorPanel />}
              </ErrorBoundary>
            </BrowserRouter>
          </AppProvider>
        </AuthProvider>
      </ThemeProvider>
    </QueryClientProvider>
  );
}

import React, { useState } from "react";
import { supabase } from "../../supabaseClient";

interface MigrationResults {
  customers: { success: number; failed: number; skipped: number };
  parts: { success: number; failed: number; skipped: number };
  sales: { success: number; failed: number; skipped: number };
  paymentSources: { success: number; failed: number; skipped: number };
  suppliers: { success: number; failed: number; skipped: number };
  inventoryTransactions: { success: number; failed: number; skipped: number };
}

interface SupabaseCounts {
  customers: number;
  parts: number;
  sales: number;
  paymentSources: number;
  suppliers: number;
  inventoryTransactions: number;
  cashTransactions: number;
  workOrders: number;
}

export const MigrationTool: React.FC = () => {
  const [isRunning, setIsRunning] = useState(false);
  const [logs, setLogs] = useState<string[]>([]);
  const [results, setResults] = useState<MigrationResults | null>(null);
  const [localData, setLocalData] = useState<any>(null);
  const [supabaseCounts, setSupabaseCounts] = useState<SupabaseCounts | null>(
    null
  );

  const addLog = (msg: string) => {
    setLogs((prev) => [...prev, `[${new Date().toLocaleTimeString()}] ${msg}`]);
  };

  const loadLocalData = () => {
    const stored = localStorage.getItem("motocare-data");
    if (!stored) {
      addLog("Γ¥î Kh├┤ng t├¼m thß║Ñy dß╗» liß╗çu trong localStorage");
      return null;
    }
    try {
      const data = JSON.parse(stored);
      setLocalData(data);
      addLog(`≡ƒôª T├¼m thß║Ñy dß╗» liß╗çu localStorage:`);
      addLog(`   - Parts: ${data.parts?.length || 0}`);
      addLog(`   - Customers: ${data.customers?.length || 0}`);
      addLog(`   - Sales: ${data.sales?.length || 0}`);
      addLog(`   - Suppliers: ${data.suppliers?.length || 0}`);
      addLog(`   - PaymentSources: ${data.paymentSources?.length || 0}`);
      addLog(
        `   - InventoryTransactions: ${data.inventoryTransactions?.length || 0}`
      );
      return data;
    } catch (e) {
      addLog("Γ¥î Lß╗ùi parse dß╗» liß╗çu localStorage");
      return null;
    }
  };

  const runMigration = async () => {
    setIsRunning(true);
    setLogs([]);
    setResults(null);

    const data = loadLocalData();
    if (!data) {
      setIsRunning(false);
      return;
    }

    const res: MigrationResults = {
      customers: { success: 0, failed: 0, skipped: 0 },
      parts: { success: 0, failed: 0, skipped: 0 },
      sales: { success: 0, failed: 0, skipped: 0 },
      paymentSources: { success: 0, failed: 0, skipped: 0 },
      suppliers: { success: 0, failed: 0, skipped: 0 },
      inventoryTransactions: { success: 0, failed: 0, skipped: 0 },
    };

    // 1. CUSTOMERS
    addLog("\n≡ƒôï 1. Di chuyß╗ân KH├üCH H├ÇNG...");
    if (data.customers?.length > 0) {
      for (const customer of data.customers) {
        try {
          const { data: existing } = await supabase
            .from("customers")
            .select("id")
            .eq("id", customer.id)
            .maybeSingle();

          if (existing) {
            res.customers.skipped++;
            continue;
          }

          const payload = {
            id: customer.id,
            name: customer.name,
            phone: customer.phone || null,
            created_at: customer.created_at || new Date().toISOString(),
          };

          const { error } = await supabase.from("customers").insert([payload]);
          if (error) {
            addLog(`  Γ¥î Customer ${customer.name}: ${error.message}`);
            res.customers.failed++;
          } else {
            res.customers.success++;
          }
        } catch (e: any) {
          res.customers.failed++;
        }
      }
      addLog(
        `  Γ£à Customers: ${res.customers.success} OK, ${res.customers.skipped} skip, ${res.customers.failed} fail`
      );
    }

    // 2. SUPPLIERS
    addLog("\n≡ƒôï 2. Di chuyß╗ân NH├Ç CUNG Cß║ñP...");
    if (data.suppliers?.length > 0) {
      for (const supplier of data.suppliers) {
        try {
          const { data: existing } = await supabase
            .from("suppliers")
            .select("id")
            .eq("id", supplier.id)
            .maybeSingle();

          if (existing) {
            res.suppliers.skipped++;
            continue;
          }

          const payload = {
            id: supplier.id,
            name: supplier.name,
            phone: supplier.phone || null,
            email: supplier.email || null,
            address: supplier.address || null,
            created_at: supplier.created_at || new Date().toISOString(),
          };

          const { error } = await supabase.from("suppliers").insert([payload]);
          if (error) {
            addLog(`  Γ¥î Supplier ${supplier.name}: ${error.message}`);
            res.suppliers.failed++;
          } else {
            res.suppliers.success++;
          }
        } catch (e: any) {
          res.suppliers.failed++;
        }
      }
      addLog(
        `  Γ£à Suppliers: ${res.suppliers.success} OK, ${res.suppliers.skipped} skip, ${res.suppliers.failed} fail`
      );
    }

    // 3. PAYMENT SOURCES
    addLog("\n≡ƒôï 3. Di chuyß╗ân NGUß╗ÆN TIß╗ÇN...");
    if (data.paymentSources?.length > 0) {
      for (const ps of data.paymentSources) {
        try {
          const { data: existing } = await supabase
            .from("payment_sources")
            .select("id")
            .eq("id", ps.id)
            .maybeSingle();

          if (existing) {
            res.paymentSources.skipped++;
            continue;
          }

          const payload = {
            id: ps.id,
            name: ps.name,
            balance: ps.balance || {},
            created_at: new Date().toISOString(),
          };

          const { error } = await supabase
            .from("payment_sources")
            .insert([payload]);
          if (error) {
            addLog(`  Γ¥î PaymentSource ${ps.name}: ${error.message}`);
            res.paymentSources.failed++;
          } else {
            res.paymentSources.success++;
          }
        } catch (e: any) {
          res.paymentSources.failed++;
        }
      }
      addLog(
        `  Γ£à PaymentSources: ${res.paymentSources.success} OK, ${res.paymentSources.skipped} skip, ${res.paymentSources.failed} fail`
      );
    }

    // 4. PARTS
    addLog("\n≡ƒôï 4. Di chuyß╗ân PHß╗ñ T├ÖNG...");
    if (data.parts?.length > 0) {
      for (const part of data.parts) {
        try {
          const { data: existing } = await supabase
            .from("parts")
            .select("id")
            .eq("id", part.id)
            .maybeSingle();

          if (existing) {
            res.parts.skipped++;
            continue;
          }

          // Also check by SKU
          const { data: existingSku } = await supabase
            .from("parts")
            .select("id")
            .eq("sku", part.sku)
            .maybeSingle();

          if (existingSku) {
            res.parts.skipped++;
            continue;
          }

          const payload = {
            id: part.id,
            name: part.name,
            sku: part.sku,
            stock: part.stock || {},
            retailprice: part.retailPrice || {},
            wholesaleprice: part.wholesalePrice || {},
            category: part.category || null,
            description: part.description || null,
            warrantyperiod: part.warrantyPeriod || null,
            costprice: part.costPrice || {},
            created_at: part.created_at || new Date().toISOString(),
          };

          const { error } = await supabase.from("parts").insert([payload]);
          if (error) {
            addLog(`  Γ¥î Part ${part.name} (${part.sku}): ${error.message}`);
            res.parts.failed++;
          } else {
            res.parts.success++;
          }
        } catch (e: any) {
          res.parts.failed++;
        }
      }
      addLog(
        `  Γ£à Parts: ${res.parts.success} OK, ${res.parts.skipped} skip, ${res.parts.failed} fail`
      );
    }

    // 5. SALES
    addLog("\n≡ƒôï 5. Di chuyß╗ân ─É╞áN B├üN H├ÇNG...");
    if (data.sales?.length > 0) {
      for (const sale of data.sales) {
        try {
          const { data: existing } = await supabase
            .from("sales")
            .select("id")
            .eq("id", sale.id)
            .maybeSingle();

          if (existing) {
            res.sales.skipped++;
            continue;
          }

          const payload = {
            id: sale.id,
            date: sale.date || new Date().toISOString(),
            items: sale.items || [],
            subtotal: sale.subtotal || 0,
            discount: sale.discount || 0,
            total: sale.total || 0,
            customer: sale.customer || { name: "Kh├ích lß║╗" },
            paymentmethod: sale.paymentMethod || "cash",
            userid: sale.userId || "migrated",
            username: sale.userName || "Migrated User",
            branchid: sale.branchId || "CN1",
            cashtransactionid: sale.cashTransactionId || null,
            created_at:
              sale.created_at || sale.date || new Date().toISOString(),
          };

          const { error } = await supabase.from("sales").insert([payload]);
          if (error) {
            addLog(`  Γ¥î Sale ${sale.id}: ${error.message}`);
            res.sales.failed++;
          } else {
            res.sales.success++;
          }
        } catch (e: any) {
          res.sales.failed++;
        }
      }
      addLog(
        `  Γ£à Sales: ${res.sales.success} OK, ${res.sales.skipped} skip, ${res.sales.failed} fail`
      );
    }

    // 6. INVENTORY TRANSACTIONS
    addLog("\n≡ƒôï 6. Di chuyß╗ân GIAO Dß╗èCH KHO...");
    if (data.inventoryTransactions?.length > 0) {
      for (const tx of data.inventoryTransactions) {
        try {
          const { data: existing } = await supabase
            .from("inventory_transactions")
            .select("id")
            .eq("id", tx.id)
            .maybeSingle();

          if (existing) {
            res.inventoryTransactions.skipped++;
            continue;
          }

          const payload = {
            id: tx.id,
            type: tx.type,
