                </div>
            </div>

            {/* 2. Key Metrics Cards */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">

                {/* Active Customers */}
                <div className="bg-white dark:bg-slate-800/80 p-4 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm border-t-2 border-t-blue-500">
                    <div className="flex items-center gap-3 mb-2">
                        <div className="p-2 rounded-lg bg-blue-50 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400">
                            <Users size={20} />
                        </div>
                        <div className="text-sm font-medium text-slate-500 dark:text-slate-400">Kh├ích h├áng hoß║ít ─æß╗Öng</div>
                    </div>
                    <div className="text-2xl font-bold text-slate-900 dark:text-white">
                        {metrics.activeCount}
                    </div>
                    <div className="text-xs text-slate-500 mt-1">
                        Trong kß╗│ ─æ├ú chß╗ìn
                    </div>
                </div>

                {/* Retention Rate */}
                <div className="bg-white dark:bg-slate-800/80 p-4 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm border-t-2 border-t-emerald-500">
                    <div className="flex items-center gap-3 mb-2">
                        <div className="p-2 rounded-lg bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600 dark:text-emerald-400">
                            <UserCheck size={20} />
                        </div>
                        <div className="text-sm font-medium text-slate-500 dark:text-slate-400">Tß╗╖ lß╗ç quay lß║íi</div>
