export default FinancialAnalytics;

import React, { useMemo } from "react";
import {
  BarChart,
  Bar,
  LineChart,
  Line,
  PieChart,
  Pie,
  Cell,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
} from "recharts";
import { useAppContext } from "../../contexts/AppContext";
import { usePartsRepo } from "../../hooks/usePartsRepository";
import { useInventoryTxRepo } from "../../hooks/useInventoryTransactionsRepository";
import { formatCurrency } from "../../utils/format";

interface InventoryAnalyticsProps {
  sales: any[];
  workOrders: any[];
  parts: any[];
  inventoryTransactions: any[];
  currentBranchId: string;
  dateFilter?: string;
}

const InventoryAnalytics: React.FC<InventoryAnalyticsProps> = ({
  sales,
  workOrders,
  parts,
  inventoryTransactions,
  currentBranchId,
  dateFilter
}) => {
  const isLoading = false; // Data comes from parent

  // Stock value by category
  const categoryData = useMemo(() => {
    const categoryMap = new Map<
      string,
      { value: number; count: number; stock: number }
    >();

    parts.forEach((part) => {
      const category = part.category || "Kh├┤ng ph├ón loß║íi";
      const stock = part.stock[currentBranchId] || 0;
      const price = part.retailPrice[currentBranchId] || 0;
      const value = stock * price;

      const existing = categoryMap.get(category);
      if (existing) {
        existing.value += value;
        existing.count += 1;
        existing.stock += stock;
      } else {
        categoryMap.set(category, { value, count: 1, stock });
      }
    });

    return Array.from(categoryMap.entries())
      .map(([name, data]) => ({
        name,
        value: Math.round(data.value),
        count: data.count,
        stock: data.stock,
      }))
      .sort((a, b) => b.value - a.value);
  }, [parts, currentBranchId]);

  // Low stock alerts
  const lowStockItems = useMemo(() => {
    return parts
      .filter((p) => {
        const stock = p.stock[currentBranchId] || 0;
        return stock > 0 && stock <= 10;
      })
      .sort((a, b) => {
        const stockA = a.stock[currentBranchId] || 0;
        const stockB = b.stock[currentBranchId] || 0;
        return stockA - stockB;
      })
      .slice(0, 10);
  }, [parts, currentBranchId]);

  // Out of stock
  const outOfStockCount = useMemo(() => {
    return parts.filter((p) => (p.stock[currentBranchId] || 0) === 0).length;
  }, [parts, currentBranchId]);

  // Top value items
  const topValueItems = useMemo(() => {
    return parts
      .map((part) => {
        const stock = part.stock[currentBranchId] || 0;
        const price = part.retailPrice[currentBranchId] || 0;
        return {
          ...part,
          totalValue: stock * price,
        };
      })
      .filter((p) => p.totalValue > 0)
      .sort((a, b) => b.totalValue - a.totalValue)
      .slice(0, 10);
  }, [parts, currentBranchId]);

  // Total inventory value
  const totalInventoryValue = useMemo(() => {
    return parts.reduce((sum, part) => {
      const stock = part.stock[currentBranchId] || 0;
      const price = part.retailPrice[currentBranchId] || 0;
      return sum + stock * price;
    }, 0);
  }, [parts, currentBranchId]);

  // Total Inventory Quantity (Sum of all stock)
  const totalInventoryQty = useMemo(() => {
    return parts.reduce((sum, part) => {
      const stock = part.stock[currentBranchId] || 0;
      return sum + stock;
    }, 0);
  }, [parts, currentBranchId]);

  // Recent transactions (last 30 days)
  const recentTransactions = useMemo(() => {
    const thirtyDaysAgo = new Date();
    thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);

    const txByDate = new Map<string, { in: number; out: number }>();

    inventoryTransactions
      .filter((tx) => new Date(tx.date) >= thirtyDaysAgo)
      .forEach((tx) => {
        const date = tx.date.slice(0, 10);
        const existing = txByDate.get(date) || { in: 0, out: 0 };

        if (tx.type === "Nhß║¡p kho") {
          existing.in += tx.quantity;
        } else {
          existing.out += tx.quantity;
        }

        txByDate.set(date, existing);
      });

    return Array.from(txByDate.entries())
      .map(([date, data]) => ({
        date: new Date(date).toLocaleDateString("vi-VN", {
          day: "2-digit",
          month: "2-digit",
        }),
        "Nhß║¡p kho": data.in,
        "Xuß║Ñt kho": data.out,
      }))
      .slice(-14); // Last 14 days
  }, [inventoryTransactions]);

  // === ADVANCED INVENTORY ANALYSIS ===

  // Slow-moving items (not sold in 60+ days)
  const slowMovingItems = useMemo(() => {
    const now = new Date();
    const sixtyDaysAgo = new Date(now.getTime() - 60 * 24 * 60 * 60 * 1000);

    // Build map of last sale date per partId
    const lastSaleMap = new Map<string, Date>();

    // Check sales
    sales.forEach((sale: any) => {
      (sale.items || []).forEach((item: any) => {
        const saleDate = new Date(sale.date);
        const existing = lastSaleMap.get(item.partId);
        if (!existing || saleDate > existing) {
          lastSaleMap.set(item.partId, saleDate);
        }
      });
    });

    // Check work orders
    workOrders.forEach((wo: any) => {
      if (wo.status === "─É├ú hß╗ºy") return;
      (wo.partsUsed || []).forEach((part: any) => {
        const woDate = new Date(wo.creationDate);
        const existing = lastSaleMap.get(part.partId);
        if (!existing || woDate > existing) {
          lastSaleMap.set(part.partId, woDate);
        }
      });
    });

    return parts
      .filter((p) => {
        const stock = p.stock[currentBranchId] || 0;
        if (stock <= 0) return false;

        const lastSale = lastSaleMap.get(p.id);
        // Never sold or sold before 60 days
        return !lastSale || lastSale < sixtyDaysAgo;
      })
      .map((p) => {
        const stock = p.stock[currentBranchId] || 0;
        const costPrice = p.costPrice?.[currentBranchId] || p.wholesalePrice?.[currentBranchId] || 0;
        const lastSale = lastSaleMap.get(p.id);
        const daysSinceLastSale = lastSale
          ? Math.floor((now.getTime() - lastSale.getTime()) / (1000 * 60 * 60 * 24))
          : 999;

        return {
          id: p.id,
          name: p.name,
          category: p.category || "Kh├┤ng ph├ón loß║íi",
          stock,
          value: stock * costPrice,
          daysSinceLastSale,
          lastSaleDate: lastSale,
        };
      })
      .sort((a, b) => b.value - a.value)
      .slice(0, 15);
  }, [parts, sales, workOrders, currentBranchId]);

  // Cost of goods sold (last 365 days for turnover calculation)
  const annualCOGS = useMemo(() => {
    const oneYearAgo = new Date();
    oneYearAgo.setFullYear(oneYearAgo.getFullYear() - 1);

    // Build cost map
    const costMap = new Map<string, number>();
    parts.forEach((p) => {
      costMap.set(p.id, p.costPrice?.[currentBranchId] || p.wholesalePrice?.[currentBranchId] || 0);
    });

    // Sales COGS
    const salesCOGS = sales
      .filter((s) => new Date(s.date) >= oneYearAgo)
      .reduce((sum, s: any) => {
        return sum + (s.items || []).reduce((itemSum: number, item: any) => {
          if (item.isService) return itemSum;
          const cost = costMap.get(item.partId) || 0;
          return itemSum + (cost * (item.quantity || 0));
        }, 0);
      }, 0);

    // Work order COGS
    const woCOGS = workOrders
      .filter((wo) => {
        const d = new Date(wo.creationDate);
        return d >= oneYearAgo && wo.status !== "─É├ú hß╗ºy" && !wo.refunded;
      })
      .reduce((sum, wo: any) => {
        return sum + (wo.partsUsed || []).reduce((partSum: number, p: any) => {
          const cost = p.costPrice || costMap.get(p.partId) || 0;
          return partSum + (cost * (p.quantity || 0));
        }, 0);
      }, 0);

    return salesCOGS + woCOGS;
  }, [sales, workOrders, parts, currentBranchId]);

  // Inventory turnover and days to sell
  const inventoryMetrics = useMemo(() => {
    // Average inventory value (at cost)
    const avgInventoryAtCost = parts.reduce((sum, p) => {
      const stock = p.stock[currentBranchId] || 0;
      const cost = p.costPrice?.[currentBranchId] || p.wholesalePrice?.[currentBranchId] || 0;
      return sum + (stock * cost);
    }, 0);

    const turnover = avgInventoryAtCost > 0 ? annualCOGS / avgInventoryAtCost : 0;
    const daysToSell = turnover > 0 ? Math.round(365 / turnover) : 999;

    return { turnover, daysToSell, avgInventoryAtCost };
  }, [parts, annualCOGS, currentBranchId]);

  // Capital analysis
  const capitalAnalysis = useMemo(() => {
    const slowMovingValue = slowMovingItems.reduce((sum, item) => sum + item.value, 0);
    const totalCapital = inventoryMetrics.avgInventoryAtCost;
    const fastMovingValue = totalCapital - slowMovingValue;

    return {
      totalCapital,
      slowMovingValue,
      slowMovingPercent: totalCapital > 0 ? (slowMovingValue / totalCapital * 100) : 0,
      fastMovingValue,
      fastMovingPercent: totalCapital > 0 ? (fastMovingValue / totalCapital * 100) : 0,
    };
  }, [slowMovingItems, inventoryMetrics]);

  const COLORS = [
    "#3b82f6",
    "#10b981",
    "#f59e0b",
    "#ef4444",
    "#8b5cf6",
    "#ec4899",
    "#06b6d4",
    "#f97316",
  ];

  if (isLoading) {
    return (
      <div className="flex items-center justify-center h-96">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {/* Summary Stats */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
        <div className="bg-white dark:bg-slate-800/80 p-4 rounded-lg border border-slate-200 dark:border-slate-700 border-t-2 border-t-blue-500 shadow-sm">
          <div className="text-xs font-medium text-slate-500 dark:text-slate-400 mb-1">
            Tß╗òng gi├í trß╗ï tß╗ôn kho
          </div>
          <div className="text-2xl font-bold text-slate-800 dark:text-white">
            {formatCurrency(totalInventoryValue)}
          </div>
        </div>

        <div className="bg-white dark:bg-slate-800/80 p-4 rounded-lg border border-slate-200 dark:border-slate-700 border-t-2 border-t-emerald-500 shadow-sm">
          <div className="text-xs font-medium text-slate-500 dark:text-slate-400 mb-1">
            Tß╗òng SL tß╗ôn kho
          </div>
          <div className="text-2xl font-bold text-slate-800 dark:text-white">
            {totalInventoryQty}
          </div>
          <div className="text-[10px] text-slate-500 mt-0.5">
            {parts.length} m├ú sß║ún phß║⌐m
          </div>
        </div>

        <div className="bg-white dark:bg-slate-800/80 p-4 rounded-lg border border-slate-200 dark:border-slate-700 border-t-2 border-t-amber-500 shadow-sm">
          <div className="text-xs font-medium text-slate-500 dark:text-slate-400 mb-1">
            Sß║»p hß║┐t h├áng
          </div>
          <div className="text-2xl font-bold text-slate-800 dark:text-white">
            {lowStockItems.length}
          </div>
        </div>

        <div className="bg-white dark:bg-slate-800/80 p-4 rounded-lg border border-slate-200 dark:border-slate-700 border-t-2 border-t-red-500 shadow-sm">
          <div className="text-xs font-medium text-slate-500 dark:text-slate-400 mb-1">
            Hß║┐t h├áng
          </div>
          <div className="text-2xl font-bold text-slate-800 dark:text-white">
            {outOfStockCount}
          </div>
        </div>
      </div>

      {/* === ADVANCED INVENTORY ANALYSIS === */}
      <div className="bg-white dark:bg-[#1e293b] p-4 rounded-lg shadow-sm border border-slate-200 dark:border-slate-700">
        <h3 className="text-base font-semibold text-slate-900 dark:text-slate-100 mb-4">
          Ph├ón t├¡ch tß╗ôn kho n├óng cao
        </h3>

        {/* Metrics Cards */}
        <div className="grid grid-cols-2 md:grid-cols-4 gap-3 mb-4">
          {/* Turnover */}
          <div className="bg-slate-50 dark:bg-slate-800 p-3 rounded-lg border border-slate-200 dark:border-slate-700 border-l-4 border-l-violet-500">
            <div className="text-xs font-medium text-slate-500 dark:text-slate-400 mb-1">
              V├▓ng quay tß╗ôn kho
            </div>
            <div className="text-xl font-bold text-slate-800 dark:text-white">
              {inventoryMetrics.turnover.toFixed(1)}x/n─âm
            </div>
            <div className="text-[10px] text-slate-500 dark:text-slate-500 mt-0.5">
              {inventoryMetrics.daysToSell < 999 ? `TB ${inventoryMetrics.daysToSell} ng├áy b├ín hß║┐t` : 'Ch╞░a ─æß╗º dß╗» liß╗çu'}
            </div>
          </div>

          {/* Capital at Cost */}
          <div className="bg-slate-50 dark:bg-slate-800 p-3 rounded-lg border border-slate-200 dark:border-slate-700 border-l-4 border-l-indigo-500">
            <div className="text-xs font-medium text-slate-500 dark:text-slate-400 mb-1">
              Vß╗æn kß║╣t tß╗ôn kho
            </div>
            <div className="text-xl font-bold text-slate-800 dark:text-white">
              {formatCurrency(capitalAnalysis.totalCapital)}
            </div>
            <div className="text-[10px] text-slate-500 dark:text-slate-500 mt-0.5">
              Theo gi├í vß╗æn
            </div>
          </div>

          {/* Slow Moving Value */}
          <div className="bg-slate-50 dark:bg-slate-800 p-3 rounded-lg border border-slate-200 dark:border-slate-700 border-l-4 border-l-orange-500">
            <div className="text-xs font-medium text-slate-500 dark:text-slate-400 mb-1">
              H├áng b├ín chß║¡m (60+ ng├áy)
            </div>
            <div className="text-xl font-bold text-slate-800 dark:text-white">
              {formatCurrency(capitalAnalysis.slowMovingValue)}
            </div>
            <div className="text-[10px] text-slate-500 dark:text-slate-500 mt-0.5">
              {capitalAnalysis.slowMovingPercent.toFixed(1)}% tß╗òng vß╗æn
            </div>
          </div>

          {/* Fast Moving Value */}
          <div className="bg-slate-50 dark:bg-slate-800 p-3 rounded-lg border border-slate-200 dark:border-slate-700 border-l-4 border-l-teal-500">
            <div className="text-xs font-medium text-slate-500 dark:text-slate-400 mb-1">
              H├áng b├ín nhanh
            </div>
            <div className="text-xl font-bold text-slate-800 dark:text-white">
              {formatCurrency(capitalAnalysis.fastMovingValue)}
            </div>
            <div className="text-[10px] text-slate-500 dark:text-slate-500 mt-0.5">
              {capitalAnalysis.fastMovingPercent.toFixed(1)}% tß╗òng vß╗æn
            </div>
          </div>
        </div>

        {/* Capital Distribution Bar */}
        <div className="mb-4">
          <div className="text-xs text-slate-600 dark:text-slate-400 mb-1">Ph├ón bß╗ò vß╗æn tß╗ôn kho</div>
          <div className="h-4 rounded-full overflow-hidden flex bg-slate-200 dark:bg-slate-700">
            <div
              className="bg-teal-500 transition-all"
              style={{ width: `${capitalAnalysis.fastMovingPercent}%` }}
              title={`B├ín nhanh: ${formatCurrency(capitalAnalysis.fastMovingValue)}`}
            />
            <div
              className="bg-orange-500 transition-all"
              style={{ width: `${capitalAnalysis.slowMovingPercent}%` }}
              title={`B├ín chß║¡m: ${formatCurrency(capitalAnalysis.slowMovingValue)}`}
            />
          </div>
          <div className="flex justify-between mt-1 text-[10px] text-slate-500">
            <span className="flex items-center gap-1">
              <span className="w-2 h-2 bg-teal-500 rounded-full"></span>
              B├ín nhanh ({capitalAnalysis.fastMovingPercent.toFixed(0)}%)
            </span>
            <span className="flex items-center gap-1">
              <span className="w-2 h-2 bg-orange-500 rounded-full"></span>
              B├ín chß║¡m ({capitalAnalysis.slowMovingPercent.toFixed(0)}%)
            </span>
          </div>
        </div>

        {/* Slow Moving Items Table */}
        {slowMovingItems.length > 0 && (
          <div>
            <div className="flex items-center justify-between mb-2">
              <div className="text-sm font-semibold text-slate-700 dark:text-slate-300">
                Top h├áng b├ín chß║¡m (ch╞░a b├ín 60+ ng├áy)
              </div>
              <span className="text-xs text-orange-600 dark:text-orange-400 bg-orange-100 dark:bg-orange-900/30 px-2 py-0.5 rounded-full">
                {slowMovingItems.length} sß║ún phß║⌐m
              </span>
            </div>
            <div className="overflow-auto max-h-[250px]">
              <table className="w-full text-sm">
                <thead className="bg-slate-50 dark:bg-slate-800 text-slate-600 dark:text-slate-400 sticky top-0">
                  <tr>
                    <th className="px-3 py-2 text-left font-medium">Sß║ún phß║⌐m</th>
                    <th className="px-3 py-2 text-center font-medium">Tß╗ôn</th>
                    <th className="px-3 py-2 text-right font-medium">Gi├í trß╗ï</th>
                    <th className="px-3 py-2 text-right font-medium">Ng├áy ch╞░a b├ín</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                  {slowMovingItems.map((item) => (
                    <tr key={item.id} className="hover:bg-slate-50 dark:hover:bg-slate-800/50">
                      <td className="px-3 py-2">
                        <div className="font-medium text-slate-900 dark:text-slate-100">{item.name}</div>
                        <div className="text-[10px] text-slate-500">{item.category}</div>
                      </td>
                      <td className="px-3 py-2 text-center text-slate-600 dark:text-slate-400">{item.stock}</td>
                      <td className="px-3 py-2 text-right font-semibold text-orange-600 dark:text-orange-400">{formatCurrency(item.value)}</td>
                      <td className="px-3 py-2 text-right">
                        <span className={`text-xs font-medium px-1.5 py-0.5 rounded ${item.daysSinceLastSale > 90
                          ? 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400'
                          : 'bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-400'
                          }`}>
                          {item.daysSinceLastSale >= 999 ? 'Ch╞░a b├ín' : `${item.daysSinceLastSale} ng├áy`}
                        </span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </div>

      {/* Charts Row 1 */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        {/* Category Distribution */}
        <div className="bg-white dark:bg-[#1e293b] p-4 rounded-lg shadow-sm border border-slate-200 dark:border-slate-700">
          <h3 className="text-base font-semibold text-slate-900 dark:text-slate-100 mb-3">
            Gi├í trß╗ï theo danh mß╗Ñc
          </h3>
          {(() => {
            // Group categories: top 5 + "Kh├íc"
            const topCategories = categoryData.slice(0, 5);
            const otherCategories = categoryData.slice(5);
            const otherValue = otherCategories.reduce((sum, c) => sum + c.value, 0);
            const chartData = otherValue > 0
              ? [...topCategories, { name: "Kh├íc", value: otherValue, count: otherCategories.length, stock: 0 }]
              : topCategories;

            const totalValue = chartData.reduce((sum, c) => sum + c.value, 0);

            return (
              <div className="flex flex-col lg:flex-row gap-4">
                {/* Pie Chart */}
                <div className="flex-1">
                  <ResponsiveContainer width="100%" height={200}>
                    <PieChart>
                      <Pie
                        data={chartData}
                        cx="50%"
                        cy="50%"
                        innerRadius={50}
                        outerRadius={80}
                        fill="#8884d8"
                        dataKey="value"
                        paddingAngle={2}
                      >
                        {chartData.map((entry, index) => (
                          <Cell
                            key={`cell-${index}`}
                            fill={COLORS[index % COLORS.length]}
                          />
                        ))}
                      </Pie>
                      <Tooltip
                        formatter={(value: number) => formatCurrency(value)}
                        contentStyle={{
                          backgroundColor: "rgba(15, 23, 42, 0.95)",
                          border: "none",
                          borderRadius: "8px",
                          color: "#fff",
                        }}
                      />
                    </PieChart>
                  </ResponsiveContainer>
                </div>
                {/* Legend */}
                <div className="flex-1 space-y-2">
                  {chartData.map((item, index) => {
                    const percent = totalValue > 0 ? ((item.value / totalValue) * 100).toFixed(1) : 0;
                    return (
                      <div key={item.name} className="flex items-center justify-between gap-2 text-sm">
                        <div className="flex items-center gap-2 min-w-0">
                          <div
                            className="w-3 h-3 rounded-full flex-shrink-0"
                            style={{ backgroundColor: COLORS[index % COLORS.length] }}
                          />
                          <span className="text-slate-700 dark:text-slate-300 truncate">{item.name}</span>
                        </div>
                        <div className="flex items-center gap-2 flex-shrink-0">
                          <span className="text-slate-500 dark:text-slate-400 text-xs">{percent}%</span>
                          <span className="text-slate-900 dark:text-slate-100 font-medium text-xs">
                            {formatCurrency(item.value)}
                          </span>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            );
          })()}
        </div>

        {/* Inventory Transactions */}
        <div className="bg-white dark:bg-[#1e293b] p-4 rounded-lg shadow-sm border border-slate-200 dark:border-slate-700">
          <h3 className="text-base font-semibold text-slate-900 dark:text-slate-100 mb-3">
            Nhß║¡p/Xuß║Ñt kho (14 ng├áy gß║ºn nhß║Ñt)
          </h3>
          <ResponsiveContainer width="100%" height={250}>
            <LineChart data={recentTransactions}>
              <CartesianGrid strokeDasharray="3 3" stroke="#334155" />
              <XAxis dataKey="date" stroke="#94a3b8" />
              <YAxis stroke="#94a3b8" />
              <Tooltip
                contentStyle={{
                  backgroundColor: "rgba(15, 23, 42, 0.95)",
                  border: "none",
                  borderRadius: "8px",
                  color: "#fff",
                }}
              />
              <Legend />
              <Line
                type="monotone"
                dataKey="Nhß║¡p kho"
                stroke="#10b981"
                strokeWidth={2}
              />
              <Line
                type="monotone"
                dataKey="Xuß║Ñt kho"
                stroke="#ef4444"
                strokeWidth={2}
              />
            </LineChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Top Items */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        {/* Top Value Items */}
        <div className="bg-white dark:bg-[#1e293b] p-4 rounded-lg shadow-sm border border-slate-200 dark:border-slate-700">
          <h3 className="text-base font-semibold text-slate-900 dark:text-slate-100 mb-3">
            Top 10 sß║ún phß║⌐m gi├í trß╗ï cao
          </h3>
          <div className="space-y-2">
            {topValueItems.map((item, index) => (
              <div
                key={item.id}
                className="flex items-center justify-between p-2 bg-slate-50 dark:bg-slate-800 rounded-lg"
              >
                <div className="flex items-center gap-2">
                  <div className="w-6 h-6 rounded-full bg-blue-100 dark:bg-blue-900/30 flex items-center justify-center text-xs font-bold text-blue-600 dark:text-blue-400">
                    {index + 1}
                  </div>
                  <div>
                    <div className="text-sm font-medium text-slate-900 dark:text-slate-100">
                      {item.name}
                    </div>
                    <div className="text-[10px] text-slate-600 dark:text-slate-400">
                      Tß╗ôn: {item.stock[currentBranchId] || 0}
                    </div>
                  </div>
                </div>
                <div className="text-right">
                  <div className="text-sm font-semibold text-slate-900 dark:text-slate-100">
                    {formatCurrency(item.totalValue)}
                  </div>
                  <div className="text-[10px] text-slate-600 dark:text-slate-400">
                    {formatCurrency(item.retailPrice[currentBranchId] || 0)}/sp
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Low Stock Alerts */}
        <div className="bg-white dark:bg-[#1e293b] p-4 rounded-lg shadow-sm border border-slate-200 dark:border-slate-700">
          <h3 className="text-base font-semibold text-slate-900 dark:text-slate-100 mb-3 flex items-center gap-2">
            <span className="inline-flex">
              <svg
                xmlns="http://www.w3.org/2000/svg"
                className="w-4 h-4 text-amber-600"
                fill="none"
                viewBox="0 0 24 24"
                stroke="currentColor"
                strokeWidth="2"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  d="M12 9v4m0 4h.01M10.29 3.86 1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0Z"
                />
              </svg>
            </span>
            Cß║únh b├ío tß╗ôn kho thß║Ñp
          </h3>
          <div className="space-y-2">
            {lowStockItems.map((item) => {
              const stock = item.stock[currentBranchId] || 0;
              const level =
                stock <= 3 ? "critical" : stock <= 5 ? "warning" : "low";

              return (
                <div
                  key={item.id}
                  className={`flex items-center justify-between p-2 rounded-lg ${level === "critical"
                    ? "bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800"
                    : level === "warning"
