                                </div>
                            </div>
                        )}

                        {showGoals && (
                            <div className="mt-3 flex items-center justify-between z-10 relative text-xs text-slate-500 dark:text-slate-400">
                                <div>
                                    {daysLeft > 0 ? (
                                        <span>Cß║ºn {formatCurrency(dailyProfitNeeded)}/ng├áy</span>
                                    ) : (
                                        <span>─É├ú hß║┐t th├íng</span>
