// Time ago helper
function timeAgo(dateString: string): string {
  const now = new Date();
  const date = new Date(dateString);
  const seconds = Math.floor((now.getTime() - date.getTime()) / 1000);

  if (seconds < 60) return "Vß╗½a xong";
  if (seconds < 3600) return `${Math.floor(seconds / 60)} ph├║t tr╞░ß╗¢c`;
  if (seconds < 86400) return `${Math.floor(seconds / 3600)} giß╗¥ tr╞░ß╗¢c`;
  if (seconds < 604800) return `${Math.floor(seconds / 86400)} ng├áy tr╞░ß╗¢c`;

  return date.toLocaleDateString("vi-VN", { day: "2-digit", month: "2-digit" });
}

