          />
        </div>
        <div className="text-slate-600 dark:text-slate-400 text-sm font-medium whitespace-nowrap">
          Tß╗òng: <span className="font-bold">{filteredSuppliers.length}</span>{" "}
          nh├á cung cß║Ñp
