    if (paymentAmountNum > remainingAmount) {
      showToast.error(
        `Sß╗æ tiß╗ün thanh to├ín kh├┤ng ─æ╞░ß╗úc v╞░ß╗út qu├í sß╗æ nß╗ú c├▓n lß║íi (${formatCurrency(
          remainingAmount
        )})`
      );
      return;
    }

    const supplier = suppliers.find((s) => s.id === selectedSupplierId);
    if (supplier && onPay) {
      setIsSubmitting(true);
      try {
        await onPay({
          supplierName: supplier.name,
          supplierId: supplier.id,
          amount: paymentAmountNum,
          paymentMethod,
          timestamp: createTime,
          shouldPrint: isPrintChecked,
        });
      } catch (error) {
        console.error(error);
        setIsSubmitting(false);
      }
    } else {
      onClose();
    }
  };

  return (
    <div className="fixed inset-0 bg-black/50 backdrop-blur-sm flex items-end md:items-center justify-center p-0 md:p-4 z-[100]">
