            <div className="flex items-center justify-between mb-3">
              <span className="text-sm font-medium text-secondary-text">-</span>
              <span className="text-sm font-medium text-secondary-text">
                Chi tiß║┐t
              </span>
              <span className="text-sm font-medium text-secondary-text">
                Sß╗æ tiß╗ün
              </span>
