            {/* Payment Modal */}
            {showPaymentModal && selectedInstallment && (
                <InstallmentPaymentModal
                    installment={selectedInstallment}
                    onClose={() => {
                        setShowPaymentModal(false);
                        setSelectedInstallment(null);
