                        {formatCurrency(employeeRemaining)}
                      </p>
                    </div>
                    <div className="bg-white/80 dark:bg-slate-800/80 rounded-lg p-4">
                      <p className="text-xs text-slate-600 dark:text-slate-400 mb-1">
