                                <div className="bg-slate-800/50 rounded-lg p-2">
                                    <div className="text-[10px] text-slate-500 uppercase">L╞░╞íng c╞í bß║ún</div>
                                    <div className="text-sm font-bold text-white">
                                        {formatCurrency(emp.baseSalary).replace("Γé½", "")}
