                    </div>
                </div>
            )}

            {/* Tabs */}
            <div className="px-4 mb-4">
                <div className="flex bg-[#1e1e2d] p-1 rounded-xl overflow-x-auto no-scrollbar">
                    {[
                        { key: "list", label: "Danh s├ích", icon: ClipboardList },
                        { key: "attendance", label: "Chß║Ñm c├┤ng", icon: Clock },
                        { key: "payroll", label: "L╞░╞íng", icon: DollarSign },
                        { key: "advance", label: "ß╗¿ng l╞░╞íng", icon: Wallet },
                        { key: "history", label: "Lß╗ïch sß╗¡", icon: History },
                    ].map((tab) => (
                        <button
                            key={tab.key}
                            onClick={() => setActiveTab(tab.key)}
