        // Nß║┐u amount > 0: thu, amount < 0: chi (hoß║╖c ng╞░ß╗úc lß║íi t├╣y type)
        // RULE: income ΓåÆ +amount, expense ΓåÆ -amount
        let delta = 0;
        if (isIncomeTx(tx)) {
          delta = Math.abs(tx.amount); // Income lu├┤n cß╗Öng (d╞░╞íng)
        } else {
          delta = -Math.abs(tx.amount); // Expense lu├┤n trß╗½ (├óm)
