          return sum + Math.abs(tx.amount);
        } else {
          return sum - Math.abs(tx.amount);
        }
      }, 0);

    console.log('[DEBUG CashBook] cashTransactionsDelta:', cashTransactionsDelta);
    console.log('[DEBUG CashBook] bankTransactionsDelta:', bankTransactionsDelta);

