import React, { useState, useMemo, useEffect } from "react";
import { useAppContext } from "../../contexts/AppContext";
import { useAuth } from "../../contexts/AuthContext";
import { showToast } from "../../utils/toast";
import { formatCurrency, formatDate } from "../../utils/format";
import type { CashTransaction } from "../../types";
import {
    useCashTxRepo,
    useCreateCashTxRepo,
    useUpdateCashTxRepo,
    useDeleteCashTxRepo,
} from "../../hooks/useCashTransactionsRepository";
import { useUpdatePaymentSourceBalanceRepo } from "../../hooks/usePaymentSourcesRepository";
import { supabase } from "../../supabaseClient";
import { Plus, Search, Filter, Wallet, ArrowUpCircle, ArrowDownCircle, MoreVertical, Edit2, Trash2 } from "lucide-react";
import { AddTransactionModal, EditTransactionModal, DeleteConfirmModal, getCategoryLabel } from "./CashBookModals";


export const CashBookMobile: React.FC = () => {
    const {
        paymentSources,
        currentBranchId,
        setCashTransactions,
        setPaymentSources,
    } = useAppContext();

    // Fetch cash transactions
    const { data: cashTransactions = [], isLoading: isCashTxLoading } =
        useCashTxRepo({ branchId: currentBranchId });
    const createCashTxRepo = useCreateCashTxRepo();
    const updateCashTxRepo = useUpdateCashTxRepo();
    const deleteCashTxRepo = useDeleteCashTxRepo();
    const updatePaymentSourceBalanceRepo = useUpdatePaymentSourceBalanceRepo();

    // Fetch profiles for user names
    const [profilesMap, setProfilesMap] = useState<Record<string, string>>({});

    useEffect(() => {
        const fetchProfiles = async () => {
            const { data, error } = await supabase
                .from("profiles")
                .select("id, name");
            if (!error && data) {
                const map: Record<string, string> = {};
                data.forEach((profile: any) => {
                    map[profile.id] = profile.name;
                });
                setProfilesMap(map);
            }
        };
        fetchProfiles();
    }, []);

    const [filterType, setFilterType] = useState<"all" | "income" | "expense">("all");
    const [filterPaymentSource, setFilterPaymentSource] = useState<string>("all");
    const [filterDateRange, setFilterDateRange] = useState<"today" | "week" | "month" | "all">("month");
    const [searchQuery, setSearchQuery] = useState("");
    const [showFilters, setShowFilters] = useState(false);
    const [showAddModal, setShowAddModal] = useState(false);
    const [editingTransaction, setEditingTransaction] = useState<CashTransaction | null>(null);
    const [deletingTransaction, setDeletingTransaction] = useState<CashTransaction | null>(null);

    // Filter transactions
    const filteredTransactions = useMemo(() => {
        let filtered = cashTransactions.filter(
            (tx) => tx.branchId === currentBranchId
        );

        // Filter by type
        if (filterType !== "all") {
            filtered = filtered.filter((tx) => tx.type === filterType);
        }

        // Filter by payment source
        if (filterPaymentSource !== "all") {
            filtered = filtered.filter(
                (tx) => tx.paymentSourceId === filterPaymentSource
            );
        }

        // Filter by date range
        const now = new Date();
        const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());

        switch (filterDateRange) {
            case "today":
                filtered = filtered.filter((tx) => new Date(tx.date) >= today);
                break;
            case "week":
                const weekAgo = new Date(today);
                weekAgo.setDate(weekAgo.getDate() - 7);
                filtered = filtered.filter((tx) => new Date(tx.date) >= weekAgo);
                break;
            case "month":
                const monthAgo = new Date(today);
                monthAgo.setMonth(monthAgo.getMonth() - 1);
                filtered = filtered.filter((tx) => new Date(tx.date) >= monthAgo);
                break;
        }

        // Filter by search query
        if (searchQuery.trim()) {
            const query = searchQuery.toLowerCase();
            filtered = filtered.filter(
                (tx) =>
                    ((tx as any).description || "").toLowerCase().includes(query) ||
                    (tx.notes || "").toLowerCase().includes(query) ||
                    ((tx as any).reference || "").toLowerCase().includes(query) ||
                    ((tx as any).recipient || "").toLowerCase().includes(query) ||
                    getCategoryLabel(tx.category).toLowerCase().includes(query)
            );
        }

        return filtered.sort(
            (a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()
        );
    }, [
        cashTransactions,
        currentBranchId,
        filterType,
        filterPaymentSource,
        filterDateRange,
        searchQuery,
    ]);

    const INCOME_CATEGORIES = new Set([
        "sale_income",
        "service_income",
        "other_income",
        "debt_collection",
        "service_deposit",
        "employee_advance_repayment",
        "general_income",
        "deposit",
    ]);
    const EXPENSE_CATEGORIES = new Set([
        "inventory_purchase",
        "supplier_payment",
        "debt_payment",
        "salary",
        "employee_advance",
        "loan_payment",
        "rent",
        "utilities",
        "outsourcing",
        "service_cost",
        "sale_refund",
        "other_expense",
        "general_expense",
    ]);

    // Γ£à FIX: Refactored transaction type detection with clear priority (consistent with CashBook.tsx)
    const isIncomeTx = (tx: CashTransaction) => {
        const normalizedCategory = String(tx.category || "").trim().toLowerCase();

        // Priority 1: Check expense categories first (more specific)
        if (EXPENSE_CATEGORIES.has(normalizedCategory)) return false;

        // Priority 2: Check income categories
        if (INCOME_CATEGORIES.has(normalizedCategory)) return true;

        // Priority 3: Fallback to type field only if category not recognized
        return tx.type === "income" || tx.type === "deposit";
    };

    // Get initial balances
    const savedInitialCash =
        paymentSources.find((ps) => ps.id === "cash")?.balance[currentBranchId] || 0;
    const savedInitialBank =
        paymentSources.find((ps) => ps.id === "bank")?.balance[currentBranchId] || 0;

    // Calculate ACTUAL BALANCE (from ALL transactions, not filtered)
    const actualBalance = useMemo(() => {
        const allBranchTransactions = cashTransactions.filter(
            (tx) => tx.branchId === currentBranchId
        );

        // T├¡nh biß║┐n ─æß╗Öng tiß╗ün mß║╖t tß╗½ Tß║ñT Cß║ó giao dß╗ïch
        const cashTransactionsDelta = allBranchTransactions
            .filter((tx) => tx.paymentSourceId === "cash")
            .reduce((sum, tx) => {
                if (isIncomeTx(tx)) {
                    return sum + Math.abs(tx.amount);
                } else {
                    return sum - Math.abs(tx.amount);
                }
            }, 0);

        // T├¡nh biß║┐n ─æß╗Öng ng├ón h├áng tß╗½ Tß║ñT Cß║ó giao dß╗ïch
        const bankTransactionsDelta = allBranchTransactions
            .filter((tx) => tx.paymentSourceId === "bank")
            .reduce((sum, tx) => {
                if (isIncomeTx(tx)) {
                    return sum + Math.abs(tx.amount);
                } else {
                    return sum - Math.abs(tx.amount);
                }
            }, 0);

        // Sß╗æ d╞░ thß╗▒c tß║┐ = Sß╗æ d╞░ ban ─æß║ºu + Biß║┐n ─æß╗Öng tß╗½ giao dß╗ïch
        const cashBalance = savedInitialCash + cashTransactionsDelta;
        const bankBalance = savedInitialBank + bankTransactionsDelta;

        return {
            cashBalance,
            bankBalance,
            totalBalance: cashBalance + bankBalance,
        };
    }, [
        cashTransactions,
        currentBranchId,
        savedInitialCash,
        savedInitialBank,
    ]);

    // Calculate FILTERED SUMMARY (from filtered transactions only)
    const filteredSummary = useMemo(() => {
        const income = filteredTransactions
            .filter((tx) => isIncomeTx(tx))
            .reduce((sum, tx) => sum + Math.abs(tx.amount), 0);

        const expense = filteredTransactions
            .filter((tx) => tx.type === "expense")
            .reduce((sum, tx) => sum + Math.abs(tx.amount), 0);

        const balance = income - expense;

        // T├¡nh ri├¬ng cho tiß╗ün mß║╖t v├á ng├ón h├áng trong kß╗│ lß╗ìc
        const cashIncome = filteredTransactions
            .filter((tx) => tx.paymentSourceId === "cash" && isIncomeTx(tx))
            .reduce((sum, tx) => sum + Math.abs(tx.amount), 0);

        const cashExpense = filteredTransactions
            .filter((tx) => tx.paymentSourceId === "cash" && tx.type === "expense")
            .reduce((sum, tx) => sum + Math.abs(tx.amount), 0);

        const bankIncome = filteredTransactions
            .filter((tx) => tx.paymentSourceId === "bank" && isIncomeTx(tx))
            .reduce((sum, tx) => sum + Math.abs(tx.amount), 0);

        const bankExpense = filteredTransactions
            .filter((tx) => tx.paymentSourceId === "bank" && tx.type === "expense")
            .reduce((sum, tx) => sum + Math.abs(tx.amount), 0);

        return {
            income,
            expense,
            balance,
            cashIncome,
            cashExpense,
            cashBalance: cashIncome - cashExpense,
            bankIncome,
            bankExpense,
            bankBalance: bankIncome - bankExpense,
        };
    }, [filteredTransactions]);

    // Determine if we're showing filtered view (not "all")
    const isFilteredView = filterDateRange !== "all" || filterType !== "all" || filterPaymentSource !== "all" || searchQuery.trim() !== "";

    return (
        <div className="bg-[#151521] min-h-screen text-white pb-20">
            {/* Stats Cards - Horizontal Scroll */}
            <div className="px-4 py-4 overflow-x-auto no-scrollbar flex gap-3 snap-x">
                {/* Balance Card */}
                <div className="snap-center shrink-0 w-[85vw] bg-slate-800/80 border border-slate-700/50 rounded-2xl p-4 shadow-sm relative overflow-hidden">
                    <div className="absolute top-0 right-0 p-3 opacity-5">
                        <Wallet className="w-24 h-24 text-white" />
                    </div>
                    <div className="relative z-10">
                        <p className="text-slate-400 text-sm font-medium mb-1">Tß╗òng sß╗æ d╞░ thß╗▒c tß║┐</p>
                        <h3 className="text-3xl font-bold text-white mb-4">
                            {formatCurrency(actualBalance.totalBalance)}
                        </h3>
                        <div className="grid grid-cols-2 gap-4">
                            <div className="bg-slate-900/50 rounded-xl p-2.5 border border-slate-700/50">
                                <p className="text-slate-400 text-xs mb-1">Tiß╗ün mß║╖t</p>
                                <p className="font-semibold text-white">{formatCurrency(actualBalance.cashBalance)}</p>
                            </div>
                            <div className="bg-slate-900/50 rounded-xl p-2.5 border border-slate-700/50">
                                <p className="text-slate-400 text-xs mb-1">Ng├ón h├áng</p>
                                <p className="font-semibold text-white">{formatCurrency(actualBalance.bankBalance)}</p>
                            </div>
                        </div>
                    </div>
                </div>

                {/* Income/Expense Summary - Show filtered summary */}
                <div className="snap-center shrink-0 w-[85vw] bg-[#1e1e2d] rounded-2xl p-4 border border-slate-800 shadow-lg">
                    <div className="flex items-center justify-between mb-3">
                        <h4 className="text-slate-400 text-sm font-medium">Thu chi trong kß╗│</h4>
                        {isFilteredView && (
                            <span className="text-xs text-blue-400">
                                ({filteredTransactions.length} GD)
                            </span>
                        )}
                    </div>
                    <div className="space-y-3">
                        <div className="flex items-center justify-between">
                            <div className="flex items-center gap-3">
                                <div className="w-10 h-10 rounded-full bg-green-500/20 flex items-center justify-center">
                                    <ArrowUpCircle className="w-6 h-6 text-green-500" />
                                </div>
                                <div>
                                    <p className="text-slate-400 text-xs">Tß╗òng thu</p>
                                    <p className="text-green-500 font-bold">{formatCurrency(filteredSummary.income)}</p>
                                </div>
                            </div>
                        </div>
                        <div className="w-full h-[1px] bg-slate-800"></div>
                        <div className="flex items-center justify-between">
                            <div className="flex items-center gap-3">
                                <div className="w-10 h-10 rounded-full bg-red-500/20 flex items-center justify-center">
                                    <ArrowDownCircle className="w-6 h-6 text-red-500" />
                                </div>
                                <div>
                                    <p className="text-slate-400 text-xs">Tß╗òng chi</p>
                                    <p className="text-red-500 font-bold">{formatCurrency(filteredSummary.expense)}</p>
                                </div>
                            </div>
                        </div>
                        <div className="w-full h-[1px] bg-slate-800"></div>
                        <div className="flex items-center justify-between">
                            <div className="flex items-center gap-3">
                                <div className="w-10 h-10 rounded-full bg-blue-500/20 flex items-center justify-center">
                                    <Wallet className="w-6 h-6 text-blue-500" />
                                </div>
                                <div>
                                    <p className="text-slate-400 text-xs">Ch├¬nh lß╗çch</p>
                                    <p className={`font-bold ${filteredSummary.balance >= 0 ? "text-blue-500" : "text-red-500"
                                        }`}>
                                        {formatCurrency(filteredSummary.balance)}
                                    </p>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            {/* Filters & Search */}
            <div className="px-4 mb-4">
                <div className="flex gap-2 mb-3">
                    <div className="relative flex-1">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                        <input
                            type="text"
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            placeholder="T├¼m kiß║┐m giao dß╗ïch..."
                            className="w-full bg-[#1e1e2d] border border-slate-800 rounded-xl pl-9 pr-4 py-2.5 text-sm text-white placeholder-slate-500 focus:outline-none focus:border-blue-500"
                        />
                    </div>
                    <button
                        onClick={() => setShowFilters(!showFilters)}
                        className={`p-2.5 rounded-xl border ${showFilters ? 'bg-blue-600 border-blue-600 text-white' : 'bg-[#1e1e2d] border-slate-800 text-slate-400'}`}
                    >
                        <Filter className="w-5 h-5" />
                    </button>
                </div>

                {showFilters && (
                    <div className="bg-[#1e1e2d] rounded-xl p-4 border border-slate-800 space-y-4 animate-in slide-in-from-top-2">
                        <div>
                            <label className="text-xs text-slate-400 mb-2 block">Thß╗¥i gian</label>
                            <div className="flex bg-[#151521] p-1 rounded-lg">
                                {['today', 'week', 'month', 'all'].map((range) => (
                                    <button
                                        key={range}
                                        onClick={() => setFilterDateRange(range as any)}
                                        className={`flex-1 py-1.5 rounded-md text-xs font-medium transition-all ${filterDateRange === range ? 'bg-blue-600 text-white' : 'text-slate-400'}`}
                                    >
                                        {range === 'today' ? 'H├┤m nay' : range === 'week' ? '7 ng├áy' : range === 'month' ? '30 ng├áy' : 'Tß║Ñt cß║ú'}
                                    </button>
                                ))}
                            </div>
                        </div>
                        <div className="grid grid-cols-2 gap-3">
                            <div>
                                <label className="text-xs text-slate-400 mb-2 block">Loß║íi</label>
                                <select
                                    value={filterType}
                                    onChange={(e) => setFilterType(e.target.value as any)}
                                    className="w-full bg-[#151521] border border-slate-800 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:border-blue-500"
                                >
                                    <option value="all">Tß║Ñt cß║ú</option>
                                    <option value="income">Thu</option>
                                    <option value="expense">Chi</option>
                                </select>
                            </div>
                            <div>
                                <label className="text-xs text-slate-400 mb-2 block">Nguß╗ôn tiß╗ün</label>
                                <select
                                    value={filterPaymentSource}
                                    onChange={(e) => setFilterPaymentSource(e.target.value)}
                                    className="w-full bg-[#151521] border border-slate-800 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:border-blue-500"
                                >
                                    <option value="all">Tß║Ñt cß║ú</option>
                                    <option value="cash">Tiß╗ün mß║╖t</option>
                                    <option value="bank">Ng├ón h├áng</option>
                                </select>
                            </div>
                        </div>
                    </div>
                )}
            </div>

            {/* Transactions List */}
            <div className="px-4 space-y-3">
                <h3 className="text-slate-400 text-sm font-medium">Giao dß╗ïch gß║ºn ─æ├óy</h3>
                {isCashTxLoading ? (
                    <div className="text-center py-8 text-slate-500">
                        <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-blue-600 mx-auto mb-2"></div>
                        ─Éang tß║úi dß╗» liß╗çu...
                    </div>
                ) : filteredTransactions.length === 0 ? (
                    <div className="text-center py-12 bg-[#1e1e2d] rounded-2xl border border-slate-800">
                        <div className="w-16 h-16 bg-slate-800 rounded-full flex items-center justify-center mx-auto mb-3">
                            <Wallet className="w-8 h-8 text-slate-600" />
                        </div>
                        <p className="text-slate-400">Kh├┤ng c├│ giao dß╗ïch n├áo</p>
                    </div>
                ) : (
                    filteredTransactions.map((tx) => (
                        <div
                            key={tx.id}
                            className="bg-[#1e1e2d] p-4 rounded-xl border border-slate-800 active:scale-[0.98] transition-transform"
                        >
                            <div className="flex justify-between items-start mb-3">
                                <div className="flex items-start gap-3">
                                    <div className={`w-10 h-10 rounded-full flex items-center justify-center shrink-0 border ${isIncomeTx(tx) ? 'bg-green-500/10 border-green-500/20' : 'bg-red-500/10 border-red-500/20'}`}>
                                        {isIncomeTx(tx) ? (
                                            <ArrowUpCircle className="w-5 h-5 text-green-500" />
                                        ) : (
                                            <ArrowDownCircle className="w-5 h-5 text-red-500" />
                                        )}
                                    </div>
                                    <div>
                                        <h4 className="font-medium text-white">{getCategoryLabel(tx.category)}</h4>
                                        <p className="text-xs text-slate-400 mt-0.5">{formatDate(new Date(tx.date))}</p>
                                    </div>
                                </div>
                                <div className="text-right">
                                    <p className={`font-bold ${isIncomeTx(tx) ? 'text-green-500' : 'text-red-500'}`}>
                                        {isIncomeTx(tx) ? '+' : '-'}{formatCurrency(Math.abs(tx.amount))}
                                    </p>
                                    <span className="text-[10px] px-2 py-0.5 rounded-full bg-slate-800 text-slate-400 inline-block mt-1">
                                        {tx.paymentSourceId === 'bank' ? 'Ng├ón h├áng' : 'Tiß╗ün mß║╖t'}
                                    </span>
                                </div>
                            </div>
                            <div className="mt-3 pt-3 border-t border-slate-800 flex justify-between items-center">
                                <p className="text-sm text-slate-300 line-clamp-1 flex-1 mr-2">
                                    {(tx as any).recipient && <span className="font-medium text-blue-400 mr-1">{(tx as any).recipient}:</span>}
                                    {tx.notes || (tx as any).description || <span className="italic text-slate-500">Kh├┤ng c├│ ghi ch├║</span>}
                                </p>
                                <div className="flex gap-2 shrink-0">
                                    <button
                                        onClick={() => setEditingTransaction(tx)}
                                        className="p-2 bg-slate-800/80 rounded-lg text-slate-400 hover:text-blue-400 hover:bg-slate-700 active:scale-95 transition-all"
                                    >
                                        <Edit2 className="w-4 h-4" />
                                    </button>
                                    <button
                                        onClick={() => setDeletingTransaction(tx)}
                                        className="p-2 bg-slate-800/80 rounded-lg text-slate-400 hover:text-red-400 hover:bg-slate-700 active:scale-95 transition-all"
                                    >
                                        <Trash2 className="w-4 h-4" />
                                    </button>
                                </div>
                            </div>
                        </div>
                    ))
                )}
            </div>
            {/* Floating Action Button */}
            <button
                onClick={() => setShowAddModal(true)}
                className="fixed bottom-24 right-4 w-14 h-14 bg-slate-800 rounded-full shadow-lg border border-slate-700/50 flex items-center justify-center text-white z-10 hover:bg-slate-700 active:scale-90 transition-all"
            >
                <Plus className="w-8 h-8" />
            </button>

            {/* Modals */}
            {showAddModal && (
                <AddTransactionModal
                    onClose={() => setShowAddModal(false)}
                    onSave={async (transaction) => {
                        if (!transaction.amount || transaction.amount <= 0) {
                            showToast.warning("Sß╗æ tiß╗ün phß║úi > 0");
                            return;
                        }
                        try {
                            const res = await createCashTxRepo.mutateAsync({
                                type: transaction.type,
                                amount: transaction.amount,
                                branchId: currentBranchId,
                                paymentSourceId: transaction.paymentSourceId,
                                date: transaction.date,
                                notes: transaction.notes,
                                category: transaction.category,
                                recipient: transaction.recipient,
                            });
                            if (res?.ok) {
                                setCashTransactions((prev) => [res.data as CashTransaction, ...prev]);
                                const delta = transaction.type === "income" ? transaction.amount : -transaction.amount;
                                await updatePaymentSourceBalanceRepo.mutateAsync({
                                    id: transaction.paymentSourceId,
                                    branchId: currentBranchId,
                                    delta,
                                });
                                setPaymentSources((prev) =>
                                    prev.map((ps) =>
                                        ps.id === transaction.paymentSourceId
                                            ? { ...ps, balance: { ...ps.balance, [currentBranchId]: (ps.balance[currentBranchId] || 0) + delta } }
                                            : ps
                                    )
                                );
                                showToast.success("─É├ú th├¬m giao dß╗ïch sß╗ò quß╗╣");
                                setShowAddModal(false);
                            } else if (res?.error) {
                                showToast.error(res.error.message || "Ghi giao dß╗ïch thß║Ñt bß║íi");
                            }
                        } catch (e: any) {
                            showToast.error(e?.message || "Lß╗ùi kh├┤ng x├íc ─æß╗ïnh");
                        }
                    }}
                />
            )}

            {editingTransaction && (
                <EditTransactionModal
                    transaction={editingTransaction}
                    onClose={() => setEditingTransaction(null)}
                    onSave={async (updatedData) => {
                        try {
                            const res = await updateCashTxRepo.mutateAsync({
                                id: editingTransaction.id,
                                ...updatedData,
                            });
                            if (res?.ok) {
                                showToast.success("─É├ú cß║¡p nhß║¡t giao dß╗ïch");
                                setEditingTransaction(null);
                            } else if (res?.error) {
                                showToast.error(res.error.message || "Cß║¡p nhß║¡t thß║Ñt bß║íi");
                            }
                        } catch (e: any) {
                            showToast.error(e?.message || "Lß╗ùi kh├┤ng x├íc ─æß╗ïnh");
                        }
                    }}
                />
            )}

            {deletingTransaction && (
                <DeleteConfirmModal
                    transaction={deletingTransaction}
                    onClose={() => setDeletingTransaction(null)}
                    onConfirm={async () => {
                        try {
                            const res = await deleteCashTxRepo.mutateAsync(deletingTransaction.id);
                            if (res?.ok) {
                                showToast.success("─É├ú x├│a giao dß╗ïch");
                                setDeletingTransaction(null);
                            } else if (res?.error) {
                                showToast.error(res.error.message || "X├│a thß║Ñt bß║íi");
                            }
                        } catch (e: any) {
                            showToast.error(e?.message || "Lß╗ùi kh├┤ng x├íc ─æß╗ïnh");
                        }
                    }}
                />
            )}
        </div>
    );
};

