const LoanPaymentModal: React.FC<{
  loan: Loan;
  onClose: () => void;
  onSave: (payment: LoanPayment) => void;
}> = ({ loan, onClose, onSave }) => {
  // Kiß╗âm tra xem c├│ phß║úi khoß║ún vay ─æ├ío hß║ín kh├┤ng
  const isDaoHan = loan.purpose?.toLowerCase().includes("─æ├ío hß║ín");

  // T├¡nh l├úi cho kß╗│ hß║ín (th├íng)
  const calculateInterest = () => {
    // L├úi = Sß╗æ tiß╗ün c├▓n nß╗ú * l├úi suß║Ñt/n─âm / 12 th├íng
    return (loan.remainingAmount * loan.interestRate / 100 / 12);
  };

  const [principalAmount, setPrincipalAmount] = useState(
    isDaoHan ? "0" : loan.monthlyPayment.toString()
  );
