    // Calculate dimensions based on rotation
    const pageWidth = rotateLabel ? currentSize.height : currentSize.width;
    const pageHeight = rotateLabel ? currentSize.width : currentSize.height;

    printWindow.document.write(`
      <!DOCTYPE html>
      <html>
        <head>
          <title>In m├ú vß║ích h├áng loß║ít - ${selectedParts.size} sß║ún phß║⌐m</title>
          <style>
            @page {
              size: ${pageWidth}mm ${pageHeight}mm;
              margin: 0;
            }
            * { 
              margin: 0; 
              padding: 0; 
              box-sizing: border-box; 
            }
            html, body {
              width: ${pageWidth}mm;
              height: ${pageHeight}mm;
              margin: 0;
              padding: 0;
            }
            body {
              font-family: Arial, sans-serif;
            }
            .label {
              width: ${pageWidth}mm;
              height: ${pageHeight}mm;
              padding: 0;
              display: flex;
              align-items: center;
              justify-content: center;
              box-sizing: border-box;
              overflow: hidden;
              page-break-after: always;
              page-break-inside: avoid;
            }
            .label:last-child {
              page-break-after: avoid;
            }
            .label-content {
              width: ${currentSize.width}mm;
              height: ${currentSize.height}mm;
              padding: 1mm;
              display: flex;
              flex-direction: column;
              align-items: center;
              justify-content: center;
              ${rotateLabel ? 'transform: rotate(-90deg); transform-origin: center center;' : ''}
            }
            .label-category {
              font-size: ${Math.max(7, currentSize.fontSize - 1)}px;
              font-weight: bold;
              text-align: center;
              line-height: 1.1;
              max-width: 100%;
              overflow: hidden;
              white-space: nowrap;
              text-overflow: ellipsis;
              margin-bottom: 1px;
              text-transform: uppercase;
              letter-spacing: 0.5px;
            }
            .label-name {
              font-size: ${Math.max(7, currentSize.fontSize - 1)}px;
              font-weight: bold;
              text-align: center;
              line-height: 1.2;
              max-width: 100%;
              overflow: hidden;
              display: -webkit-box;
              -webkit-line-clamp: 2;
              -webkit-box-orient: vertical;
              word-break: break-word;
              margin-bottom: 1px;
            }
            .label-price {
              font-size: ${currentSize.fontSize}px;
              font-weight: bold;
              line-height: 1;
              margin-top: 1px;
            }
            svg { 
              max-width: ${currentSize.width - 4}mm !important; 
              height: auto !important; 
            }
            @media print {
              html, body {
                width: ${pageWidth}mm !important;
                height: ${pageHeight}mm !important;
              }
