                              {part.barcode || part.sku}
                            </p>
                          </div>
                          <div className="text-right shrink-0">
                            <p className="text-xs text-slate-500 dark:text-slate-400">
                              Tß╗ôn kho
                            </p>
                            <p
                              className={`text-sm font-bold ${stock > 0 ? "text-green-600" : "text-red-500"
                                }`}
                            >
