import React, { useState, useMemo } from "react";
import { useAppContext } from "../../contexts/AppContext";
import { formatCurrency, formatDate } from "../../utils/format";
import { useSupplierDebtsRepo } from "../../hooks/useDebtsRepository";
import { usePartsRepo } from "../../hooks/usePartsRepository";
import { useSuppliers } from "../../hooks/useSuppliers";
import type { InventoryTransaction } from "../../types";

interface InventoryHistorySectionMobileProps {
  transactions: InventoryTransaction[];
  onEdit?: (receipt: any) => void;
  onDelete?: (receipt: any) => void;
}

const InventoryHistorySectionMobile: React.FC<
  InventoryHistorySectionMobileProps
> = ({ transactions, onEdit, onDelete }) => {
  const { currentBranchId } = useAppContext();
  const { data: supplierDebts = [] } = useSupplierDebtsRepo();
  const { data: parts = [] } = usePartsRepo();
  const { data: suppliers = [] } = useSuppliers();

  const [activeTimeFilter, setActiveTimeFilter] = useState("7days");
  const [customStartDate, setCustomStartDate] = useState(
    formatDate(new Date(), true)
  );
  const [customEndDate, setCustomEndDate] = useState(
    formatDate(new Date(), true)
  );
  const [searchTerm, setSearchTerm] = useState("");
  const [historyView, setHistoryView] = useState<"import" | "export" | "all">(
    "import"
  );
  const [expandedExportReceipts, setExpandedExportReceipts] = useState<Set<string>>(
    new Set()
  );
  const [showFilters, setShowFilters] = useState(false);
  const [selectedReceipt, setSelectedReceipt] = useState<{
    receiptCode: string;
    date: Date;
    supplier: string;
    items: InventoryTransaction[];
    total: number;
  } | null>(null);

  const filteredAllTransactions = useMemo(() => {
    let filtered = transactions.slice();
    const now = new Date();

    switch (activeTimeFilter) {
      case "7days":
        const sevenDaysAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
        filtered = filtered.filter((t) => new Date(t.date) >= sevenDaysAgo);
        break;
      case "30days":
        const thirtyDaysAgo = new Date(
          now.getTime() - 30 * 24 * 60 * 60 * 1000
        );
        filtered = filtered.filter((t) => new Date(t.date) >= thirtyDaysAgo);
        break;
      case "thisMonth":
        const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);
        filtered = filtered.filter((t) => new Date(t.date) >= startOfMonth);
        break;
      case "custom":
        filtered = filtered.filter((t) => {
          const date = new Date(t.date);
          return (
            date >= new Date(customStartDate) && date <= new Date(customEndDate)
          );
        });
        break;
    }

    if (searchTerm) {
      const q = searchTerm.toLowerCase();
      filtered = filtered.filter(
        (t) =>
          t.partName.toLowerCase().includes(q) ||
          (t.notes && t.notes.toLowerCase().includes(q))
      );
    }

    return filtered.sort(
      (a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()
    );
  }, [
    transactions,
    activeTimeFilter,
    customStartDate,
    customEndDate,
    searchTerm,
  ]);

  const filteredImportTransactions = useMemo(
    () => filteredAllTransactions.filter((t) => t.type === "Nhß║¡p kho"),
    [filteredAllTransactions]
  );

  const filteredExportTransactions = useMemo(
    () => filteredAllTransactions.filter((t) => t.type === "Xuß║Ñt kho"),
    [filteredAllTransactions]
  );

  const groupedExportReceipts = useMemo(() => {
    const groups = new Map<
      string,
      {
        groupKey: string;
        refLabel: string;
        date: string;
        items: InventoryTransaction[];
      }
    >();

    filteredExportTransactions.forEach((transaction) => {
      const d = new Date(transaction.date);
      const dateKey = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(
        2,
        "0"
      )}-${String(d.getDate()).padStart(2, "0")}`;

      const refLabel = transaction.saleId
        ? `Sale: ${transaction.saleId}`
        : transaction.workOrderId
          ? `WO: ${transaction.workOrderId}`
          : transaction.notes
            ? `Ghi ch├║: ${transaction.notes}`
            : "Kh├┤ng r├╡ tham chiß║┐u";

      const refKey = transaction.saleId
        ? `sale:${transaction.saleId}`
        : transaction.workOrderId
          ? `wo:${transaction.workOrderId}`
          : transaction.notes
            ? `note:${transaction.notes}`
            : "unknown";

      const groupKey = `${dateKey}_${refKey}`;

      if (!groups.has(groupKey)) {
        groups.set(groupKey, {
          groupKey,
          refLabel,
          date: transaction.date,
          items: [],
        });
      }
      groups.get(groupKey)!.items.push(transaction);
    });

    return Array.from(groups.values()).sort(
      (a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()
    );
  }, [filteredExportTransactions]);

  const showImports = historyView === "import" || historyView === "all";
  const showExports = historyView === "export" || historyView === "all";

  const toggleExportExpand = (groupKey: string) => {
    setExpandedExportReceipts((prev) => {
      const newSet = new Set(prev);
      if (newSet.has(groupKey)) {
        newSet.delete(groupKey);
      } else {
        newSet.add(groupKey);
      }
      return newSet;
    });
  };

  const totalAmount = useMemo(() => {
    return filteredImportTransactions.reduce((sum, t) => sum + t.totalPrice, 0);
  }, [filteredImportTransactions]);

  const groupedReceipts = useMemo(() => {
    const groups = new Map<string, InventoryTransaction[]>();

    filteredImportTransactions.forEach((transaction) => {
      const date = new Date(transaction.date);
      const dateKey = `${date.getFullYear()}-${String(
        date.getMonth() + 1
      ).padStart(2, "0")}-${String(date.getDate()).padStart(2, "0")}`;
      // Get supplier from supplierId or fallback to notes
      const supplier = transaction.supplierId 
        ? (suppliers.find((s: any) => s.id === transaction.supplierId)?.name || "Kh├┤ng x├íc ─æß╗ïnh")
        : (transaction.notes?.includes("NCC:")
          ? transaction.notes.split("NCC:")[1]?.trim()
          : "Kh├┤ng x├íc ─æß╗ïnh");
      const groupKey = `${dateKey}_${supplier}_${date.getHours()}_${date.getMinutes()}`;

      if (!groups.has(groupKey)) {
        groups.set(groupKey, []);
      }
      groups.get(groupKey)!.push(transaction);
    });

    return Array.from(groups.entries())
      .map(([key, items], index) => {
        const firstItem = items[0];
        const date = new Date(firstItem.date);

        let receiptCode = "";
        if (firstItem.notes) {
          const match = firstItem.notes.match(/NH-\d{8}-\d{3}/);
          if (match) {
            receiptCode = match[0];
          }
        }

        if (!receiptCode) {
          const dateStr = `${date.getFullYear()}${String(
            date.getMonth() + 1
          ).padStart(2, "0")}${String(date.getDate()).padStart(2, "0")}`;
          receiptCode = `NH-${dateStr}-${String(groups.size - index).padStart(
            3,
            "0"
          )}`;
        }

        return {
          receiptCode,
          date: firstItem.date,
          supplier: firstItem.supplierId
            ? (suppliers.find((s: any) => s.id === firstItem.supplierId)?.name || "Kh├┤ng x├íc ─æß╗ïnh")
            : (firstItem.notes?.includes("NCC:")
              ? firstItem.notes.split("NCC:")[1]?.split("|")[0]?.trim()
              : "Kh├┤ng x├íc ─æß╗ïnh"),
          items,
          total: items.reduce((sum, item) => sum + item.totalPrice, 0),
        };
      })
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [filteredImportTransactions, suppliers]);

  const displayCount = useMemo(() => {
    if (historyView === "export") {
      return groupedExportReceipts.length;
    }
    if (historyView === "all") {
      return groupedReceipts.length + groupedExportReceipts.length;
    }
    return groupedReceipts.length;
  }, [historyView, groupedReceipts.length, groupedExportReceipts.length]);

  return (
    <>
      <div className="flex flex-col h-full bg-slate-50 dark:bg-[#0f172a]">
        <div className="sticky top-0 z-10 bg-white dark:bg-[#1e293b] border-b border-slate-200 dark:border-slate-700 p-3 space-y-2">
          <input
            type="text"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            placeholder="T├¼m NCC, phß╗Ñ t├╣ng..."
            className="w-full px-4 py-2.5 border border-slate-300 dark:border-slate-600 rounded-lg dark:bg-slate-700 dark:text-slate-100 placeholder-slate-400 text-sm"
          />
          <div className="grid grid-cols-3 gap-2">
            {[
              { key: "import", label: "Phiß║┐u nhß║¡p" },
              { key: "export", label: "Xuß║Ñt kho" },
              { key: "all", label: "Tß║Ñt cß║ú" },
            ].map((view) => (
              <button
                key={view.key}
                onClick={() => setHistoryView(view.key as "import" | "export" | "all")}
                className={`px-3 py-2 rounded-lg text-xs font-semibold transition-colors ${historyView === view.key
                  ? "bg-slate-900 text-white dark:bg-slate-100 dark:text-slate-900"
                  : "bg-slate-100 dark:bg-slate-700 text-slate-700 dark:text-slate-300"
                  }`}
              >
                {view.label}
              </button>
            ))}
          </div>
          <div className="flex items-center gap-2">
            <button
              onClick={() => setShowFilters(true)}
              className="flex-1 flex items-center justify-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg text-sm font-medium"
            >
              <svg
                className="w-4 h-4"
                fill="none"
                stroke="currentColor"
                viewBox="0 0 24 24"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M3 4a1 1 0 011-1h16a1 1 0 011 1v2.586a1 1 0 01-.293.707l-6.414 6.414a1 1 0 00-.293.707V17l-4 4v-6.586a1 1 0 00-.293-.707L3.293 7.293A1 1 0 013 6.586V4z"
                />
              </svg>
              Bß╗Ö lß╗ìc
            </button>
            <div className="px-4 py-2 bg-slate-100 dark:bg-slate-700 rounded-lg text-sm font-medium text-slate-700 dark:text-slate-300">
              {displayCount}
            </div>
          </div>
        </div>

        {showImports && (
          <div className="px-3 py-3 bg-blue-50 dark:bg-blue-900/20 border-b border-blue-100 dark:border-blue-800">
            <div className="flex justify-between items-center">
              <div className="text-xs text-blue-600 dark:text-blue-400">
                Tß╗òng gi├í trß╗ï nhß║¡p
              </div>
              <div className="text-xl font-bold text-blue-600 dark:text-blue-400">
                {formatCurrency(totalAmount)}
              </div>
            </div>
          </div>
        )}

        <div className="flex-1 overflow-auto">
          {showImports && (
            <>
              {groupedReceipts.length === 0 ? (
                <div className="flex flex-col items-center justify-center h-full p-8 text-center">
                  <div className="text-6xl mb-4">≡ƒôª</div>
                  <h3 className="text-lg font-semibold text-slate-900 dark:text-slate-100 mb-2">
                    Kh├┤ng c├│ dß╗» liß╗çu
                  </h3>
                  <p className="text-sm text-slate-600 dark:text-slate-400">
                    Thß╗¡ thay ─æß╗òi bß╗Ö lß╗ìc hoß║╖c thß╗¥i gian
                  </p>
                </div>
              ) : (
                <div className="divide-y divide-slate-200 dark:divide-slate-700">
                  {groupedReceipts.map((receipt) => {
                    const receiptDate = new Date(receipt.date);
                    const formattedDate = receiptDate.toLocaleDateString("vi-VN", {
                      day: "2-digit",
                      month: "2-digit",
                      year: "numeric",
                    });
                    const formattedTime = receiptDate.toLocaleTimeString("vi-VN", {
                      hour: "2-digit",
                      minute: "2-digit",
                    });

                    const receiptDebt = supplierDebts.find((debt: any) =>
                      debt.description?.includes(receipt.receiptCode)
                    );
                    const remainingDebt = receiptDebt?.remainingAmount || 0;
                    const hasDebt = remainingDebt > 0;

                    return (
                      <button
                        key={receipt.receiptCode}
                        onClick={() =>
                          setSelectedReceipt({
                            ...receipt,
                            date: new Date(receipt.date),
                          })
                        }
                        className="w-full p-4 bg-white dark:bg-[#1e293b] hover:bg-slate-50 dark:hover:bg-slate-700/50 transition-colors text-left"
                      >
                        <div className="flex items-start justify-between gap-3 mb-3">
                          <div>
                            <div className="text-sm font-bold text-cyan-600 dark:text-cyan-400">
                              {receipt.receiptCode}
                            </div>
                            <div className="text-xs text-slate-500 dark:text-slate-400 mt-0.5">
                              {formattedDate} ┬╖ {formattedTime}
                            </div>
                          </div>
                          <div className="text-right">
                            <div className="text-xs text-slate-500 dark:text-slate-400">
                              Tß╗òng tiß╗ün
                            </div>
                            <div className="text-base font-bold text-slate-900 dark:text-white">
                              {formatCurrency(receipt.total)}
                            </div>
                          </div>
                        </div>

                        <div className="flex items-center gap-2 mb-2">
                          <div className="w-8 h-8 rounded-full bg-orange-100 dark:bg-orange-900/30 flex items-center justify-center text-lg">
                            ≡ƒÅó
                          </div>
                          <div className="text-sm font-medium text-slate-900 dark:text-white">
                            {receipt.supplier}
                          </div>
                        </div>

                        <div className="text-xs text-slate-600 dark:text-slate-400">
                          {receipt.items.length} sß║ún phß║⌐m
                        </div>

                        {hasDebt && (
                          <div className="mt-2">
                            <span className="inline-flex items-center gap-1 px-2 py-1 rounded-full text-xs font-medium bg-orange-100 text-orange-700 dark:bg-orange-900/30 dark:text-orange-200">
                              ΓÜá∩╕Å C├▓n nß╗ú {formatCurrency(remainingDebt)}
                            </span>
                          </div>
                        )}
                      </button>
                    );
                  })}
                </div>
              )}
            </>
          )}

          {showExports && (
            <div className={showImports ? "mt-4" : ""}>
              <div className="px-3 py-3 bg-white dark:bg-[#1e293b] border-y border-slate-200 dark:border-slate-700">
                <div className="flex items-center justify-between">
                  <div>
                    <div className="text-sm font-semibold text-slate-900 dark:text-slate-100">
                      Lß╗ïch sß╗¡ xuß║Ñt kho
                    </div>
                    <div className="text-xs text-slate-500 dark:text-slate-400">
                      {groupedExportReceipts.length} phiß║┐u
                    </div>
                  </div>
                </div>
              </div>

              {groupedExportReceipts.length === 0 ? (
                <div className="px-3 py-6 text-center text-slate-500">
                  <div className="text-4xl mb-2">≡ƒÜÜ</div>
                  <div className="text-sm">Ch╞░a c├│ dß╗» liß╗çu xuß║Ñt kho</div>
                </div>
              ) : (
                <div className="divide-y divide-slate-200 dark:divide-slate-700">
                  {groupedExportReceipts.map((group) => {
                    const d = new Date(group.date);
                    const dateStr = d.toLocaleDateString("vi-VN", {
                      day: "2-digit",
                      month: "2-digit",
                      year: "numeric",
                    });
                    const timeStr = d.toLocaleTimeString("vi-VN", {
                      hour: "2-digit",
                      minute: "2-digit",
                    });
                    const totalQty = group.items.reduce(
                      (sum, item) => sum + item.quantity,
                      0
                    );
                    const isExpanded = expandedExportReceipts.has(group.groupKey);
                    const visibleItems = isExpanded
                      ? group.items
                      : group.items.slice(0, 3);

                    return (
                      <div key={group.groupKey} className="p-3 bg-white dark:bg-[#0f172a]">
                        <div className="flex items-start justify-between gap-3">
                          <div>
                            <div className="text-sm font-semibold text-slate-900 dark:text-slate-100">
                              {group.refLabel}
                            </div>
                            <div className="text-xs text-slate-500 dark:text-slate-400">
                              {dateStr} ┬╖ {timeStr}
                            </div>
                          </div>
                          <div className="text-right">
                            <div className="text-xs text-slate-500 dark:text-slate-400">Xuß║Ñt</div>
                            <div className="text-lg font-bold text-red-600 dark:text-red-400">-{totalQty}</div>
                          </div>
                        </div>
                        <div className="mt-2 text-xs text-slate-600 dark:text-slate-400">
                          {group.items.length} d├▓ng phß╗Ñ t├╣ng
                        </div>
                        <div className="mt-2 space-y-2">
                          {visibleItems.map((item) => (
                            <div key={item.id} className="flex items-center justify-between text-sm">
                              <div className="text-slate-700 dark:text-slate-200">
                                {item.partName}
                              </div>
                              <div className="font-semibold text-red-600 dark:text-red-400">-{item.quantity}</div>
                            </div>
                          ))}
                        </div>
                        {group.items.length > 3 && (
                          <button
                            onClick={() => toggleExportExpand(group.groupKey)}
                            className="mt-2 inline-flex items-center gap-1 text-xs text-blue-600 hover:text-blue-700 dark:text-blue-400"
                          >
                            {isExpanded ? "Thu gß╗ìn" : "Xem th├¬m"}
                          </button>
                        )}
                      </div>
                    );
                  })}
                </div>
              )}
            </div>
          )}
        </div>
      </div>

      {showFilters && (
        <div className="fixed inset-0 z-50 flex items-end modal-bottom-safe">
          <div
            className="absolute inset-0 bg-black/50"
            onClick={() => setShowFilters(false)}
          />
          <div className="relative bg-white dark:bg-[#1e293b] rounded-t-2xl w-full max-h-[80vh] overflow-hidden flex flex-col">
            <div className="flex items-center justify-between p-4 border-b border-slate-200 dark:border-slate-700">
              <h3 className="text-lg font-semibold text-slate-900 dark:text-slate-100">
                Bß╗Ö lß╗ìc thß╗¥i gian
              </h3>
              <button
                onClick={() => setShowFilters(false)}
                className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg"
              >
                <svg
                  className="w-5 h-5"
                  fill="none"
                  stroke="currentColor"
                  viewBox="0 0 24 24"
                >
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth={2}
                    d="M6 18L18 6M6 6l12 12"
                  />
                </svg>
              </button>
            </div>
            <div className="flex-1 overflow-auto p-4 space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">
                  Thß╗¥i gian
                </label>
                <div className="grid grid-cols-2 gap-2">
                  {[
                    { key: "7days", label: "7 ng├áy qua" },
                    { key: "30days", label: "30 ng├áy qua" },
                    { key: "thisMonth", label: "Th├íng n├áy" },
                    { key: "custom", label: "T├╣y chß╗ìn" },
                  ].map((filter) => (
                    <button
                      key={filter.key}
                      onClick={() => setActiveTimeFilter(filter.key)}
                      className={`px-4 py-2.5 rounded-lg text-sm font-medium transition-colors ${activeTimeFilter === filter.key
                        ? "bg-blue-600 text-white"
                        : "bg-slate-100 dark:bg-slate-700 text-slate-700 dark:text-slate-300"
                        }`}
                    >
                      {filter.label}
                    </button>
                  ))}
                </div>
              </div>

              {activeTimeFilter === "custom" && (
                <div className="space-y-3">
                  <div>
                    <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">
                      Tß╗½ ng├áy
                    </label>
                    <input
                      type="date"
                      value={customStartDate}
                      onChange={(e) => setCustomStartDate(e.target.value)}
