  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (!formData.name.trim()) {
      showToast.warning("Vui l├▓ng nhß║¡p t├¬n sß║ún phß║⌐m");
      return;
    }

    onSave({
      id: part.id,
      name: formData.name.trim(),
      category: formData.category.trim() || undefined,
      stock: {
        ...(part.stock || {}),
