export default LookupManagerMobile;

import React, { useState, useMemo } from "react";
import { useAppContext } from "../../contexts/AppContext";
import { formatCurrency, formatDate } from "../../utils/format";
import { NumberInput } from "../common/NumberInput";
import type { Employee, PayrollRecord } from "../../types";
import { PlusIcon } from "../Icons";
import { useCreateCashTxRepo } from "../../hooks/useCashTransactionsRepository";
import { useUpdatePaymentSourceBalanceRepo } from "../../hooks/usePaymentSourcesRepository";

const PayrollManager: React.FC = () => {
  const {
    employees,
    payrollRecords,
    upsertEmployee,
    upsertPayrollRecord,
    currentBranchId,
  } = useAppContext();
  const { mutateAsync: createCashTxAsync } = useCreateCashTxRepo();
  const { mutateAsync: updatePaymentSourceBalanceAsync } =
    useUpdatePaymentSourceBalanceRepo();
  const [selectedMonth, setSelectedMonth] = useState(
    new Date().toISOString().slice(0, 7) // YYYY-MM
  );
  const [activeTab, setActiveTab] = useState<"employees" | "payroll">(
    "employees"
  );
  const [showAddEmployeeModal, setShowAddEmployeeModal] = useState(false);
  const [showPayrollModal, setShowPayrollModal] = useState(false);

  // Filter payroll by selected month
  const monthlyPayroll = useMemo(() => {
    return payrollRecords.filter((p) => p.month === selectedMonth);
  }, [payrollRecords, selectedMonth]);

  // Calculate summary
  const summary = useMemo(() => {
    const totalEmployees = employees.filter(
      (e) => e.status === "active"
    ).length;
    const totalBaseSalary = monthlyPayroll.reduce(
      (sum, p) => sum + p.baseSalary,
      0
    );
    const totalNetSalary = monthlyPayroll.reduce(
      (sum, p) => sum + p.netSalary,
      0
    );
    const paidCount = monthlyPayroll.filter(
      (p) => p.paymentStatus === "paid"
    ).length;
    const pendingCount = monthlyPayroll.filter(
      (p) => p.paymentStatus === "pending"
    ).length;

    return {
      totalEmployees,
      totalBaseSalary,
      totalNetSalary,
      paidCount,
      pendingCount,
    };
  }, [employees, monthlyPayroll]);

  return (
    <div className="h-full flex flex-col bg-slate-50 dark:bg-slate-900">
      {/* Header */}
      <div className="bg-white dark:bg-slate-800 border-b border-slate-200 dark:border-slate-700">
        <div className="px-4 py-3">
          <div className="flex items-center justify-between mb-3">
            <div>
              <h1 className="text-xl font-bold text-slate-900 dark:text-white">
                Quß║ún l├╜ l╞░╞íng
              </h1>
              <p className="text-sm text-slate-500 dark:text-slate-400 mt-1">
                Quß║ún l├╜ nh├ón vi├¬n v├á t├¡nh l╞░╞íng
              </p>
            </div>
            <button
              onClick={() =>
                activeTab === "employees"
                  ? setShowAddEmployeeModal(true)
                  : setShowPayrollModal(true)
              }
              className="flex items-center gap-2 px-4 py-2.5 bg-blue-600 hover:bg-blue-700 text-white rounded-lg font-medium transition-colors"
            >
              <PlusIcon className="w-5 h-5" />
              <span>
                {activeTab === "employees"
                  ? "Th├¬m nh├ón vi├¬n"
                  : "T├¡nh l╞░╞íng th├íng"}
              </span>
            </button>
          </div>

          {/* Tabs */}
          <div className="flex gap-2">
            <button
              onClick={() => setActiveTab("employees")}
              className={`px-4 py-2 rounded-t-lg font-medium text-sm transition-colors ${activeTab === "employees"
                ? "bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 border-b-2 border-blue-600"
                : "text-slate-600 dark:text-slate-400 hover:text-slate-900 dark:hover:text-slate-200"
                }`}
            >
              Danh s├ích nh├ón vi├¬n (
              {employees.filter((e) => e.status === "active").length})
            </button>
            <button
              onClick={() => setActiveTab("payroll")}
              className={`px-4 py-2 rounded-t-lg font-medium text-sm transition-colors ${activeTab === "payroll"
                ? "bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 border-b-2 border-blue-600"
                : "text-slate-600 dark:text-slate-400 hover:text-slate-900 dark:hover:text-slate-200"
                }`}
            >
              Bß║úng l╞░╞íng
            </button>
          </div>
        </div>
      </div>

      {/* Content */}
      <div className="flex-1 overflow-auto p-4">
        {activeTab === "employees" ? (
          <EmployeeList
            employees={employees}
            onEdit={(emp) => console.log("Edit", emp)}
          />
        ) : (
          <>
            {/* Month Selector & Summary */}
            <div className="mb-6">
              <div className="flex items-center justify-between mb-4">
                <div>
                  <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">
                    Chß╗ìn th├íng
                  </label>
                  <input
                    type="month"
                    value={selectedMonth}
                    onChange={(e) => setSelectedMonth(e.target.value)}
                    className="px-4 py-2 bg-white dark:bg-slate-800 border border-slate-300 dark:border-slate-600 rounded-lg text-slate-900 dark:text-white"
                  />
                </div>
              </div>

              {/* Summary Cards */}
              <div className="grid grid-cols-4 gap-4">
                <div className="bg-blue-50 dark:bg-blue-900/20 rounded-lg p-4 border border-blue-200 dark:border-blue-800">
                  <div className="text-blue-600 dark:text-blue-400 text-sm font-medium mb-2">
                    Tß╗òng l╞░╞íng c╞í bß║ún
                  </div>
                  <div className="text-blue-900 dark:text-blue-100 text-2xl font-bold">
                    {formatCurrency(summary.totalBaseSalary)}
                  </div>
                </div>

                <div className="bg-green-50 dark:bg-green-900/20 rounded-lg p-4 border border-green-200 dark:border-green-800">
                  <div className="text-green-600 dark:text-green-400 text-sm font-medium mb-2">
                    Tß╗òng l╞░╞íng thß╗▒c nhß║¡n
                  </div>
                  <div className="text-green-900 dark:text-green-100 text-2xl font-bold">
                    {formatCurrency(summary.totalNetSalary)}
                  </div>
                </div>

                <div className="bg-amber-50 dark:bg-amber-900/20 rounded-lg p-4 border border-amber-200 dark:border-amber-800">
                  <div className="text-amber-600 dark:text-amber-400 text-sm font-medium mb-2">
                    ─É├ú trß║ú l╞░╞íng
                  </div>
                  <div className="text-amber-900 dark:text-amber-100 text-2xl font-bold">
                    {summary.paidCount}
                  </div>
                  <div className="text-amber-600 dark:text-amber-400 text-xs mt-1">
                    nh├ón vi├¬n
                  </div>
                </div>

                <div className="bg-orange-50 dark:bg-orange-900/20 rounded-lg p-4 border border-orange-200 dark:border-orange-800">
                  <div className="text-orange-600 dark:text-orange-400 text-sm font-medium mb-2">
                    Ch╞░a trß║ú
                  </div>
                  <div className="text-orange-900 dark:text-orange-100 text-2xl font-bold">
                    {summary.pendingCount}
                  </div>
                  <div className="text-orange-600 dark:text-orange-400 text-xs mt-1">
                    nh├ón vi├¬n
                  </div>
                </div>
              </div>
            </div>

            {/* Payroll Table */}
            <PayrollTable
              payroll={monthlyPayroll}
              onMarkAsPaid={async (recordId, paymentMethod) => {
                const record = payrollRecords.find((p) => p.id === recordId);
                if (!record) return;

                // 1) Cß║¡p nhß║¡t trß║íng th├íi bß║úng l╞░╞íng (local for now)
                upsertPayrollRecord({
                  ...record,
                  paymentStatus: "paid",
                  paymentDate: new Date().toISOString(),
                  paymentMethod,
                });

                // 2) Ghi giao dß╗ïch chi trong sß╗ò quß╗╣ (Supabase)
                await createCashTxAsync({
                  type: "expense",
                  amount: record.netSalary,
                  branchId: currentBranchId,
                  paymentSourceId: paymentMethod,
                  category: "salary",
                  payrollRecordId: record.id,
                  recipient: record.employeeName,
                  notes: `Trß║ú l╞░╞íng th├íng ${selectedMonth} - ${record.employeeName}`,
                  date: new Date().toISOString(),
                });

                // 3) Cß║¡p nhß║¡t sß╗æ d╞░ nguß╗ôn tiß╗ün (Supabase)
                await updatePaymentSourceBalanceAsync({
                  id: paymentMethod,
                  branchId: currentBranchId,
                  delta: -record.netSalary,
                });
              }}
            />
          </>
        )}
      </div>

      {/* Modals */}
      {showAddEmployeeModal && (
        <AddEmployeeModal
          onClose={() => setShowAddEmployeeModal(false)}
          onSave={(emp) => {
            upsertEmployee(emp);
            setShowAddEmployeeModal(false);
          }}
        />
      )}

      {showPayrollModal && (
        <GeneratePayrollModal
          employees={employees.filter((e) => e.status === "active")}
          month={selectedMonth}
          onClose={() => setShowPayrollModal(false)}
          onSave={(records) => {
            records.forEach((record) => upsertPayrollRecord(record));
            setShowPayrollModal(false);
          }}
        />
      )}
    </div>
  );
};

