// Generate Payroll Modal
export const GeneratePayrollModal: React.FC<{
  employees: Employee[];
  month: string;
  onClose: () => void;
  onSave: (records: PayrollRecord[]) => void;
}> = ({ employees, month, onClose, onSave }) => {
  const [payrollData, setPayrollData] = useState<
    Array<{
      employeeId: string;
      employeeName: string;
      baseSalary: number;
      allowances: number;
      bonus: number;
      deduction: number;
    }>
  >(
    employees.map((emp) => ({
      employeeId: emp.id,
      employeeName: emp.name,
      baseSalary: emp.baseSalary,
      allowances: emp.allowances || 0,
      bonus: 0,
      deduction: 0,
    }))
  );

  const handleAllowanceChange = (employeeId: string, value: string) => {
    setPayrollData((prev) =>
      prev.map((item) =>
        item.employeeId === employeeId
          ? { ...item, allowances: parseFloat(value) || 0 }
          : item
      )
    );
  };

  const handleBonusChange = (employeeId: string, value: string) => {
    setPayrollData((prev) =>
      prev.map((item) =>
        item.employeeId === employeeId
          ? { ...item, bonus: parseFloat(value) || 0 }
          : item
      )
    );
  };

  const handleDeductionChange = (employeeId: string, value: string) => {
    setPayrollData((prev) =>
      prev.map((item) =>
        item.employeeId === employeeId
          ? { ...item, deduction: parseFloat(value) || 0 }
          : item
      )
    );
  };

  const calculateNetSalary = (
    baseSalary: number,
    allowances: number,
    bonus: number,
    deduction: number
  ) => {
    // BUG fix: clamp to 0 ΓÇö net salary cannot be negative
    return Math.max(0, baseSalary + allowances + bonus - deduction);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    const records: PayrollRecord[] = payrollData.map((data) => ({
      id: `PAY-${month}-${data.employeeId}`,
      employeeId: data.employeeId,
      employeeName: data.employeeName,
      month,
      baseSalary: data.baseSalary,
      allowances: data.allowances,
      bonus: data.bonus,
      deduction: data.deduction,
      workDays: 26,
      standardWorkDays: 26,
      socialInsurance: 0,
      healthInsurance: 0,
      unemploymentInsurance: 0,
      personalIncomeTax: 0,
      netSalary: calculateNetSalary(
        data.baseSalary,
        data.allowances,
        data.bonus,
        data.deduction
      ),
      paymentStatus: "pending" as const,
      paymentDate: undefined,
      notes: "",
      branchId: "main",
      created_at: new Date().toISOString(),
    }));

    onSave(records);
  };

  const totalBaseSalary = payrollData.reduce(
    (sum, item) => sum + item.baseSalary,
    0
  );
  const totalAllowances = payrollData.reduce(
    (sum, item) => sum + item.allowances,
    0
  );
  const totalBonus = payrollData.reduce((sum, item) => sum + item.bonus, 0);
  const totalDeduction = payrollData.reduce(
    (sum, item) => sum + item.deduction,
    0
  );
  const totalNetSalary = payrollData.reduce(
    (sum, item) =>
      sum +
      calculateNetSalary(
        item.baseSalary,
        item.allowances,
        item.bonus,
        item.deduction
      ),
    0
  );

  return (
    <div className="fixed inset-0 bg-black/50 backdrop-blur-sm flex items-center justify-center p-4 z-50">
      <div className="bg-white dark:bg-slate-800 rounded-xl shadow-2xl max-w-5xl w-full border border-slate-200 dark:border-slate-700 max-h-[90vh] flex flex-col">
        <div className="px-6 py-4 border-b border-slate-200 dark:border-slate-700">
          <h2 className="text-xl font-semibold text-slate-900 dark:text-white">
            T├¡nh l╞░╞íng th├íng {month}
          </h2>
          <p className="text-sm text-slate-500 dark:text-slate-400 mt-1">
            {employees.length} nh├ón vi├¬n
          </p>
        </div>

        <form onSubmit={handleSubmit} className="flex-1 flex flex-col">
          <div className="flex-1 overflow-y-auto p-6">
            <div className="bg-white dark:bg-slate-800 rounded-lg border border-slate-200 dark:border-slate-700 overflow-hidden">
              <table className="w-full text-sm">
                <thead className="bg-slate-50 dark:bg-slate-700 sticky top-0">
                  <tr>
                    <th className="px-4 py-3 text-left text-xs font-medium text-slate-500 dark:text-slate-400 uppercase">
                      Nh├ón vi├¬n
                    </th>
                    <th className="px-4 py-3 text-right text-xs font-medium text-slate-500 dark:text-slate-400 uppercase">
                      L╞░╞íng CB
                    </th>
                    <th className="px-4 py-3 text-right text-xs font-medium text-slate-500 dark:text-slate-400 uppercase">
                      Phß╗Ñ cß║Ñp
                    </th>
                    <th className="px-4 py-3 text-right text-xs font-medium text-slate-500 dark:text-slate-400 uppercase">
                      Th╞░ß╗ƒng
                    </th>
                    <th className="px-4 py-3 text-right text-xs font-medium text-slate-500 dark:text-slate-400 uppercase">
                      Phß║ít
                    </th>
                    <th className="px-4 py-3 text-right text-xs font-medium text-slate-500 dark:text-slate-400 uppercase">
                      Thß╗▒c nhß║¡n
                    </th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-200 dark:divide-slate-700">
                  {payrollData.map((item) => (
                    <tr
                      key={item.employeeId}
                      className="hover:bg-slate-50 dark:hover:bg-slate-700/50"
                    >
                      <td className="px-4 py-3 text-slate-900 dark:text-white font-medium">
                        {item.employeeName}
                      </td>
                      <td className="px-4 py-3 text-right text-slate-900 dark:text-white">
                        {formatCurrency(item.baseSalary)}
                      </td>
                      <td className="px-4 py-3">
                        <NumberInput
                          value={item.allowances}
                          onChange={(val) =>
                            handleAllowanceChange(item.employeeId, String(val))
                          }
                          className="w-full px-2 py-1.5 bg-white dark:bg-slate-700 border border-slate-300 dark:border-slate-600 rounded text-right text-slate-900 dark:text-white"
                        />
                      </td>
                      <td className="px-4 py-3">
                        <NumberInput
                          value={item.bonus}
                          onChange={(val) =>
                            handleBonusChange(item.employeeId, String(val))
                          }
                          className="w-full px-2 py-1.5 bg-white dark:bg-slate-700 border border-slate-300 dark:border-slate-600 rounded text-right text-slate-900 dark:text-white"
                        />
                      </td>
                      <td className="px-4 py-3">
                        <NumberInput
                          value={item.deduction}
                          onChange={(val) =>
                            handleDeductionChange(
                              item.employeeId,
                              String(val)
                            )
                          }
                          className="w-full px-2 py-1.5 bg-white dark:bg-slate-700 border border-slate-300 dark:border-slate-600 rounded text-right text-slate-900 dark:text-white"
                        />
                      </td>
                      <td className="px-4 py-3 text-right text-blue-600 dark:text-blue-400 font-bold">
                        {formatCurrency(
                          calculateNetSalary(
                            item.baseSalary,
                            item.allowances,
                            item.bonus,
                            item.deduction
                          )
                        )}
                      </td>
                    </tr>
                  ))}
                </tbody>
                <tfoot className="bg-slate-50 dark:bg-slate-700 border-t-2 border-slate-300 dark:border-slate-600">
                  <tr>
                    <td className="px-4 py-3 text-slate-900 dark:text-white font-bold">
                      Tß╗öNG Cß╗ÿNG
                    </td>
                    <td className="px-4 py-3 text-right text-slate-900 dark:text-white font-bold">
                      {formatCurrency(totalBaseSalary)}
                    </td>
                    <td className="px-4 py-3 text-right text-green-600 dark:text-green-400 font-bold">
                      {formatCurrency(totalAllowances)}
                    </td>
                    <td className="px-4 py-3 text-right text-green-600 dark:text-green-400 font-bold">
                      {formatCurrency(totalBonus)}
                    </td>
                    <td className="px-4 py-3 text-right text-red-600 dark:text-red-400 font-bold">
                      {formatCurrency(totalDeduction)}
                    </td>
                    <td className="px-4 py-3 text-right text-blue-600 dark:text-blue-400 font-bold text-lg">
