                      <th className="py-2 px-3 text-right w-32 text-sm font-semibold">Th├ánh tiß╗ün</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-200">
                    {items.map((item, index) => {
                      const part = partsMap.get(item.part_id);
