                    <div className="flex items-center gap-3">
                      <span className="text-sm">{formatCurrency(totalAmount)}</span>
                      {items.length > 0 && (
                        <span className="px-2 py-0.5 bg-white/20 rounded-full text-xs font-bold">
                          {items.length}
                        </span>
                      )}
                    </div>
                  </button>
                </div>
              </div>

              {/* Right: Shopping Cart - Width 50% on desktop */}
