                    {/* Supplier */}
                    <div>
                      <label className="flex items-center gap-1.5 text-xs font-medium text-slate-600 dark:text-slate-400 mb-1">
                        <Package className="w-3.5 h-3.5" />
                        Nh├á cung cß║Ñp
                      </label>
                      <div className="flex gap-2">
                        <select
                          value={supplierId}
                          onChange={(e) => setSupplierId(e.target.value)}
