  // Lu├┤n t├¡nh lß║íi tß╗½ c├íc th├ánh phß║ºn ─æß╗â phß║ún ├ính ─æ├║ng sau khi chß╗ënh sß╗¡a chiß║┐t khß║Ñu/ph├¡ vß║¡n chuyß╗ân.
  // Kh├┤ng d├╣ng po.final_amount v├¼ gi├í trß╗ï DB c├│ thß╗â lß╗ùi thß╗¥i nß║┐u discount/shipping ─æ╞░ß╗úc cß║¡p nhß║¡t m├á kh├┤ng cß║¡p nhß║¡t final_amount.
  const finalAmount = Math.max(0, totalAmount - discountAmount + shippingFee);

  const handleUpdateCosts = async () => {
    try {
      await updatePOMutation.mutateAsync({
        id: po.id,
        discount_amount: editDiscount,
