  // Handle delete work order - using hook for proper query invalidation
  const handleDelete = async (workOrder: WorkOrder) => {
    if (!confirm(`X├íc nhß║¡n x├│a phiß║┐u ${formatWorkOrderId(workOrder.id)}?`)) {
      return;
