          const newOrder: WorkOrder = {
            id: `WO-${Date.now()}`,
            customerName: "",
            customerPhone: "",
            vehicleModel: "",
            licensePlate: "",
            issueDescription: template.description,
            status: "Tiß║┐p nhß║¡n",
            paymentStatus: "unpaid",
            discount: 0,
            creationDate: new Date().toISOString(),
            estimatedCompletion: new Date(
