        return "7 ng├áy qua";
      case "month":
        return "th├íng n├áy";
      case "all":
        return "tß║Ñt cß║ú";
      default:
        return "";
    }
  };

  // Filter work orders
  const filteredWorkOrders = useMemo(() => {
    let filtered = dateFilteredWorkOrders;

    // Status filter
    if (statusFilter !== "all") {
      filtered = filtered.filter((w) => w.status === statusFilter);
    }

    // Search filter
    if (searchQuery.trim()) {
      const query = searchQuery.trim().toLowerCase();
      filtered = filtered.filter((w) => {
        const partsText = (w.partsUsed || [])
          .map((p) => [p.partName, p.sku, p.category].filter(Boolean).join(" "))
          .join(" ");
        const servicesText = (w.additionalServices || [])
          .map((s) => [s.description].filter(Boolean).join(" "))
          .join(" ");

        const text = [
          w.id, // Original ID (e.g., SC-1767330309661)
          formatWorkOrderId(w.id), // Formatted ID (e.g., SC-20260127-309661)
          w.customerName,
          w.customerPhone,
          w.vehicleModel,
          w.licensePlate,
          w.issueDescription,
          w.technicianName,
          w.assignedTechnician,
          w.status,
          w.paymentStatus,
          w.paymentMethod,
          w.notes,
          w.currentKm != null ? String(w.currentKm) : "",
          w.total != null ? String(w.total) : "",
          partsText,
          servicesText,
        ]
          .filter(Boolean)
          .join(" ")
          .toLowerCase();

        return text.includes(query);
      });
    }

    return filtered.sort((a, b) => {
      const dateA = new Date(a.creationDate || 0).getTime();
      const dateB = new Date(b.creationDate || 0).getTime();
      return dateB - dateA;
    });
  }, [dateFilteredWorkOrders, statusFilter, searchQuery]);

