              );

              let updatedVehicles;
              if (vehicleExists) {
                // Update km for existing vehicle
                updatedVehicles = existingVehicles.map((v: any) =>
                  v.id === formData.vehicleId
                    ? { ...v, currentKm: formData.currentKm }
