          partialPayment > maxAdditionalPayment
        ) {
          showToast.error(
            `Sß╗æ tiß╗ün thanh to├ín th├¬m kh├┤ng ─æ╞░ß╗úc v╞░ß╗út qu├í ${formatCurrency(maxAdditionalPayment)}!`
          );
          resetSubmitting();
          return;
        }

        // 3. Validate total > 0 ONLY if status is "Trß║ú m├íy"
        if (total <= 0 && formData.status === "Trß║ú m├íy") {
