        // 4. Validate payment method when there's a payment (deposit or additional payment)
        if ((depositAmount > 0 || (formData.status === "Trß║ú m├íy" && showPartialPayment && partialPayment > 0)) && !formData.paymentMethod) {
          showToast.error("Vui l├▓ng chß╗ìn ph╞░╞íng thß╗⌐c thanh to├ín");
