          // ≡ƒö╣ VALIDATE DUPLICATE PHONE
          if (!existingCustomer) {
            // Chß╗ë tß║ío kh├ích h├áng mß╗¢i nß║┐u S─ÉT ch╞░a tß╗ôn tß║íi
