                      ]);

                      // Update payment sources balance
                      setPaymentSources((prev: any[]) =>
                        prev.map((ps) => {
                          if (ps.id === "cash") {
                            return {
                              ...ps,
                              balance: {
                                ...ps.balance,
                                [currentBranchId]:
                                  (ps.balance[currentBranchId] || 0) -
