              } catch (error: any) {
                console.error("[handleSave] Error deducting inventory:", error);
                showToast.warning(
                  "─É├ú l╞░u phiß║┐u nh╞░ng c├│ lß╗ùi khi trß╗½ kho: " + error.message
                );
