/**
 * Custom hook for managing service filters state
 * Extracted from ServiceManager.tsx for reusability
 */

import { useState, useMemo, useCallback } from "react";
import { useDebouncedValue } from "../../../hooks/useDebouncedValue";
import { formatWorkOrderId } from "../../../utils/format";
import type {
    ServiceTabKey,
    QuickStatusFilter,
    ServiceStats
} from "../types/service.types";
import type { WorkOrder } from "../../../types";

interface UseServiceFiltersOptions {
    workOrders: WorkOrder[];
    stats: ServiceStats;
    dateFilteredOrders: WorkOrder[];
}

interface ServiceFiltersState {
    searchQuery: string;
    activeTab: ServiceTabKey;
    dateFilter: "all" | "today" | "week" | "month";
    technicianFilter: string;
    paymentFilter: "all" | "paid" | "unpaid" | "partial";
}

interface UseServiceFiltersReturn {
    // State values
    filters: ServiceFiltersState;
    debouncedSearchQuery: string;

    // Filtered results
    filteredOrders: WorkOrder[];
    paginatedOrders: WorkOrder[];
    hasMoreOrders: boolean;

    // Quick status filters for UI
    quickStatusFilters: QuickStatusFilter[];

    // Actions
    setSearchQuery: (value: string) => void;
    setActiveTab: (tab: ServiceTabKey) => void;
    setDateFilter: (value: "all" | "today" | "week" | "month") => void;
    setTechnicianFilter: (value: string) => void;
    setPaymentFilter: (value: "all" | "paid" | "unpaid" | "partial") => void;
    clearFilters: () => void;
    loadMore: () => void;
}

const PAGE_SIZE = 20;

/**
 * Hook to manage service filters and return filtered work orders
 */
export function useServiceFilters({
    workOrders,
    stats,
    dateFilteredOrders,
}: UseServiceFiltersOptions): UseServiceFiltersReturn {

    const buildSearchText = useCallback((order: WorkOrder) => {
        const partsText = (order.partsUsed || [])
            .map((p) => [p.partName, p.sku, p.category].filter(Boolean).join(" "))
            .join(" ");

        const servicesText = (order.additionalServices || [])
            .map((s) => [s.description].filter(Boolean).join(" "))
            .join(" ");

        const text = [
            order.id, // Original ID (e.g., SC-1767330309661)
            formatWorkOrderId(order.id), // Formatted ID (e.g., SC-20260127-309661)
            order.customerName,
            order.customerPhone,
            order.vehicleModel,
            order.licensePlate,
            order.issueDescription,
            order.technicianName,
            order.assignedTechnician,
            order.status,
            order.paymentStatus,
            order.paymentMethod,
            order.notes,
            order.currentKm != null ? String(order.currentKm) : "",
            order.total != null ? String(order.total) : "",
            partsText,
            servicesText,
        ]
            .filter(Boolean)
            .join(" ")
            .toLowerCase();

        return text;
    }, []);

    // Filter state
    const [searchQuery, setSearchQuery] = useState("");
    const [activeTab, setActiveTab] = useState<ServiceTabKey>("all");
    const [dateFilter, setDateFilter] = useState<"all" | "today" | "week" | "month">("week");
    const [technicianFilter, setTechnicianFilter] = useState("all");
    const [paymentFilter, setPaymentFilter] = useState<"all" | "paid" | "unpaid" | "partial">("all");
    const [visibleCount, setVisibleCount] = useState(PAGE_SIZE);

    // Debounce search for performance
    const debouncedSearchQuery = useDebouncedValue(searchQuery, 300);

    // Reset visible count when filters change
    const handleFilterChange = useCallback(() => {
        setVisibleCount(PAGE_SIZE);
    }, []);

    // Filter work orders based on all criteria
    const filteredOrders = useMemo(() => {
        let filtered = workOrders.filter((o) => !o.refunded);

        // Tab filter
        if (activeTab === "delivered") {
            filtered = filtered.filter((o) => o.status === "Trß║ú m├íy");
        } else {
            filtered = filtered.filter((o) => o.status !== "Trß║ú m├íy");

            if (activeTab === "pending")
                filtered = filtered.filter((o) => o.status === "Tiß║┐p nhß║¡n");
            else if (activeTab === "inProgress")
                filtered = filtered.filter((o) => o.status === "─Éang sß╗¡a");
            else if (activeTab === "done")
                filtered = filtered.filter((o) => o.status === "─É├ú sß╗¡a xong");
        }

        // Search filter (using debounced value)
        if (debouncedSearchQuery) {
            const query = debouncedSearchQuery.trim().toLowerCase();
            if (query) {
                filtered = filtered.filter((o) => buildSearchText(o).includes(query));
            }
        }

        // Date filter
        if (dateFilter !== "all") {
            const now = new Date();
            const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());

            filtered = filtered.filter((o) => {
                const orderDate = new Date(o.creationDate || (o as any).creationdate);

                if (dateFilter === "today") {
                    return orderDate >= today;
                } else if (dateFilter === "week") {
                    const weekAgo = new Date(today);
                    weekAgo.setDate(weekAgo.getDate() - 7);
                    return orderDate >= weekAgo;
                } else if (dateFilter === "month") {
                    const monthAgo = new Date(today);
                    monthAgo.setMonth(monthAgo.getMonth() - 1);
                    return orderDate >= monthAgo;
                }
                return true;
            });
        }

        // Technician filter
        if (technicianFilter !== "all") {
            filtered = filtered.filter((o) => o.technicianName === technicianFilter);
        }

        // Payment filter
        if (paymentFilter !== "all") {
            filtered = filtered.filter((o) => {
                const status = o.paymentStatus || (o as any).paymentstatus;
                if (paymentFilter === "paid") return status === "paid";
                if (paymentFilter === "unpaid") return status === "unpaid";
                if (paymentFilter === "partial") return status === "partial";
                return true;
            });
        }

        // Sort by date descending
        return filtered.sort((a, b) => {
            const dateA = a.creationDate || (a as any).creationdate;
            const dateB = b.creationDate || (b as any).creationdate;
            if (!dateA || !dateB) return 0;
            return new Date(dateB).getTime() - new Date(dateA).getTime();
        });
    }, [
        workOrders,
        activeTab,
        debouncedSearchQuery,
        dateFilter,
        technicianFilter,
        paymentFilter,
    ]);

    // Paginated results
    const paginatedOrders = useMemo(
        () => filteredOrders.slice(0, visibleCount),
        [filteredOrders, visibleCount]
    );

    const hasMoreOrders = filteredOrders.length > visibleCount;

    // Quick status filter items
    const quickStatusFilters = useMemo(
        (): QuickStatusFilter[] => [
            {
                key: "all",
                label: "Tß║Ñt cß║ú",
                color: "slate",
                count: dateFilteredOrders.filter(
                    (o) => o.status !== "Trß║ú m├íy" && !o.refunded
                ).length,
            },
            {
                key: "pending",
                label: "Tiß║┐p nhß║¡n",
                color: "blue",
                count: stats.pending,
            },
            {
                key: "inProgress",
                label: "─Éang sß╗¡a",
                color: "orange",
                count: stats.inProgress,
            },
            {
                key: "done",
                label: "─É├ú sß╗¡a xong",
                color: "green",
                count: stats.done,
            },
            {
                key: "delivered",
                label: "─É├ú trß║ú m├íy",
                color: "purple",
                count: stats.delivered,
            },
        ],
        [dateFilteredOrders, stats]
    );

    // Clear all filters
    const clearFilters = useCallback(() => {
        setSearchQuery("");
        setActiveTab("all");
        setDateFilter("week");
        setTechnicianFilter("all");
        setPaymentFilter("all");
        setVisibleCount(PAGE_SIZE);
    }, []);

    // Load more items
    const loadMore = useCallback(() => {
        setVisibleCount((prev) => prev + PAGE_SIZE);
    }, []);

    // Wrapper functions to reset pagination on filter change
    const handleSetActiveTab = useCallback((tab: ServiceTabKey) => {
        setActiveTab(tab);
        handleFilterChange();
    }, [handleFilterChange]);

    const handleSetDateFilter = useCallback((value: "all" | "today" | "week" | "month") => {
        setDateFilter(value);
        handleFilterChange();
    }, [handleFilterChange]);

    const handleSetTechnicianFilter = useCallback((value: string) => {
        setTechnicianFilter(value);
        handleFilterChange();
    }, [handleFilterChange]);

    const handleSetPaymentFilter = useCallback((value: "all" | "paid" | "unpaid" | "partial") => {
        setPaymentFilter(value);
        handleFilterChange();
    }, [handleFilterChange]);

    return {
        filters: {
            searchQuery,
            activeTab,
            dateFilter,
            technicianFilter,
            paymentFilter,
        },
        debouncedSearchQuery,
        filteredOrders,
        paginatedOrders,
        hasMoreOrders,
        quickStatusFilters,
        setSearchQuery,
        setActiveTab: handleSetActiveTab,
        setDateFilter: handleSetDateFilter,
        setTechnicianFilter: handleSetTechnicianFilter,
        setPaymentFilter: handleSetPaymentFilter,
        clearFilters,
        loadMore,
    };
}

import { useMemo } from "react";
import type { WorkOrder, WorkOrderPart, Part } from "../../../types";
import type { ServiceStats } from "../types/service.types";

interface UseServiceStatsOptions {
    workOrders: WorkOrder[];
    dateFilter: "all" | "today" | "week" | "month";
    parts?: Part[]; // Optional parts list for cost lookup fallback
    currentBranchId?: string;
}

interface UseServiceStatsReturn {
    stats: ServiceStats;
    dateFilteredOrders: WorkOrder[];
    totalOpenTickets: number;
    urgentTickets: number;
    urgentRatio: number;
    completionRate: number;
    profitMargin: number;
}

/**
 * Hook to calculate service statistics from work orders
 * 
 * @param options - Work orders, date filter settings, optional parts list, and branch ID
 * @returns Calculated statistics and derived metrics
 */
export function useServiceStats({
    workOrders,
    dateFilter,
    parts = [],
    currentBranchId = ""
}: UseServiceStatsOptions): UseServiceStatsReturn {

    // Create a map for fast part cost lookup
    const partCostMap = useMemo(() => {
        const map = new Map<string, number>();
        parts.forEach((part) => {
            // Priority: costPrice[branch] > costPrice (number) > importPrice > 0
            let cost = 0;
            const p = part as any;

            if (p.costPrice && typeof p.costPrice === 'object' && currentBranchId) {
                cost = p.costPrice[currentBranchId] || 0;
            } else if (typeof p.costPrice === 'number') {
                cost = p.costPrice;
            } else if (p.importPrice && typeof p.importPrice === 'number') {
                cost = p.importPrice; // Handle legacy importPrice field
            }

            if (part.id) map.set(part.id, cost);
            if (part.sku) map.set(part.sku, cost);
        });
        return map;
    }, [parts, currentBranchId]);

    // Helper to get part cost with fallback
    // Uses snapshot costPrice if explicitly set (even 0), otherwise looks up from catalog
    const getPartCost = (partId: string, sku: string, snapshotCost?: number | null) => {
        if (snapshotCost != null) return snapshotCost; // use snapshot cost even if 0 (free/gifted part)
        return partCostMap.get(partId) || partCostMap.get(sku) || 0;
    };

    // Filter orders by date
    const dateFilteredOrders = useMemo(() => {
        let filtered = [...workOrders];

        if (dateFilter !== "all") {
            const now = new Date();
            const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());

            filtered = filtered.filter((o) => {
                const orderDate = new Date(o.creationDate || (o as any).creationdate);

                if (dateFilter === "today") {
                    return orderDate >= today;
                } else if (dateFilter === "week") {
                    const weekAgo = new Date(today);
                    weekAgo.setDate(weekAgo.getDate() - 7);
                    return orderDate >= weekAgo;
                } else if (dateFilter === "month") {
                    const monthAgo = new Date(today);
                    monthAgo.setMonth(monthAgo.getMonth() - 1);
                    return orderDate >= monthAgo;
                }
                return true;
            });
        }

        return filtered;
    }, [workOrders, dateFilter]);

    // Calculate stats
    const stats = useMemo((): ServiceStats => {
        const pending = dateFilteredOrders.filter(
            (o) => o.status === "Tiß║┐p nhß║¡n"
        ).length;

        const inProgress = dateFilteredOrders.filter(
            (o) => o.status === "─Éang sß╗¡a"
        ).length;

        const done = dateFilteredOrders.filter(
            (o) => o.status === "─É├ú sß╗¡a xong"
        ).length;

        const delivered = dateFilteredOrders.filter(
            (o) => o.status === "Trß║ú m├íy"
        ).length;

        // Calculate revenue: fully paid orders use `total`, partial orders use `totalPaid` (actual collected)
        const filteredRevenue = dateFilteredOrders
            .filter((o) => o.paymentStatus === "paid" || o.paymentStatus === "partial")
            .reduce((sum, o) => {
                if (o.paymentStatus === "paid") return sum + o.total;
                return sum + (o.totalPaid || 0); // partial: only count money actually received
            }, 0);

        // Calculate profit = Revenue collected - Cost of parts & services delivered
        const filteredProfit = dateFilteredOrders
            .filter((o) => o.paymentStatus === "paid" || o.paymentStatus === "partial")
            .reduce((sum, o) => {
                // Revenue collected for this order
                const revenueCollected = o.paymentStatus === "paid" ? o.total : (o.totalPaid || 0);

                // Parts cost with fallback lookup
                const partsCost = o.partsUsed?.reduce(
                    (s: number, p: WorkOrderPart) => {
                        const cost = getPartCost(
                            p.partId, // always camelCase after normalizeWorkOrder fix (BUG 14)
                            p.sku || "",
                            p.costPrice // pass raw (undefined if not set, 0 if free)
                        );
                        return s + cost * (p.quantity || 0);
                    },
                    0
                ) || 0;

                // Services cost
                const servicesCost = o.additionalServices?.reduce(
                    (s: number, svc: { costPrice?: number; quantity?: number }) =>
                        s + (svc.costPrice || 0) * (svc.quantity || 0),
                    0
                ) || 0;

                return sum + (revenueCollected - partsCost - servicesCost);
            }, 0);

        return {
            pending,
            inProgress,
            done,
            delivered,
            filteredRevenue,
            filteredProfit,
        };
    }, [dateFilteredOrders, partCostMap]);

    // Calculate derived metrics
    const totalOpenTickets = stats.pending + stats.inProgress + stats.done;
    const urgentTickets = stats.pending + stats.inProgress;
    const urgentRatio = totalOpenTickets
        ? Math.round((urgentTickets / totalOpenTickets) * 100)
        : 0;
    const completionRate = totalOpenTickets
        ? Math.round((stats.done / totalOpenTickets) * 100)
        : 0;
    const profitMargin = stats.filteredRevenue
        ? Math.round((stats.filteredProfit / stats.filteredRevenue) * 100)
        : 0;

    return {
        stats,
        dateFilteredOrders,
        totalOpenTickets,
        urgentTickets,
        urgentRatio,
        completionRate,
        profitMargin,
    };
}

