import React, {
  createContext,
  useContext,
  useState,
  useCallback,
  useEffect,
} from "react";
import type {
  Part,
  Customer,
  Supplier,
  Sale,
  CartItem,
  WorkOrder,
  PaymentSource,
  CashTransaction,
  InventoryTransaction,
  Employee,
  PayrollRecord,
  Loan,
  LoanPayment,
  CustomerDebt,
  SupplierDebt,
} from "../types";
import { createCashTransaction } from "../lib/repository/cashTransactionsRepository";
import { updatePaymentSourceBalance } from "../lib/repository/paymentSourcesRepository";
import { showToast } from "../utils/toast";
import { mapRepoErrorForUser } from "../utils/errorMapping";
import { safeAudit } from "../lib/repository/auditLogsRepository";
import { supabase } from "../supabaseClient";

interface AppContextType {
  parts: Part[];
  customers: Customer[];
  suppliers: Supplier[];
  sales: Sale[];
  workOrders: WorkOrder[];
  cartItems: CartItem[];
  paymentSources: PaymentSource[];
  cashTransactions: CashTransaction[];
  inventoryTransactions: InventoryTransaction[];
  employees: Employee[];
  payrollRecords: PayrollRecord[];
  loans: Loan[];
  loanPayments: LoanPayment[];
  customerDebts: CustomerDebt[];
  supplierDebts: SupplierDebt[];
  currentBranchId: string;
  // setters / mutators
  setParts: React.Dispatch<React.SetStateAction<Part[]>>;
  upsertPart: (part: Partial<Part> & { id?: string }) => void;
  deletePart: (partId: string) => void;
  setCustomers: React.Dispatch<React.SetStateAction<Customer[]>>;
  upsertCustomer: (customer: Partial<Customer> & { id?: string }) => Promise<string>;
  setSuppliers: React.Dispatch<React.SetStateAction<Supplier[]>>;
  upsertSupplier: (supplier: Partial<Supplier> & { id?: string }) => void;
  setWorkOrders: React.Dispatch<React.SetStateAction<WorkOrder[]>>;
  upsertWorkOrder: (order: WorkOrder) => void;
  setCartItems: React.Dispatch<React.SetStateAction<CartItem[]>>;
  clearCart: () => void;
  deleteSale: (saleId: string) => void;
  finalizeSale: (data: {
    items: CartItem[];
    discount: number;
    paymentMethod: "cash" | "bank";
    customer: { id?: string; name: string; phone?: string };
    note?: string;
  }) => void;
  setPaymentSources: React.Dispatch<React.SetStateAction<PaymentSource[]>>;
  setCashTransactions: React.Dispatch<React.SetStateAction<CashTransaction[]>>;
  recordInventoryTransaction: (tx: Omit<InventoryTransaction, "id">) => void;
  setEmployees: React.Dispatch<React.SetStateAction<Employee[]>>;
  upsertEmployee: (employee: Partial<Employee> & { id?: string }) => void;
  setPayrollRecords: React.Dispatch<React.SetStateAction<PayrollRecord[]>>;
  upsertPayrollRecord: (record: PayrollRecord) => void;
  setLoans: React.Dispatch<React.SetStateAction<Loan[]>>;
  upsertLoan: (loan: Partial<Loan> & { id?: string }) => void;
  setLoanPayments: React.Dispatch<React.SetStateAction<LoanPayment[]>>;
  upsertLoanPayment: (payment: LoanPayment) => void;
  setCustomerDebts: React.Dispatch<React.SetStateAction<CustomerDebt[]>>;
  setSupplierDebts: React.Dispatch<React.SetStateAction<SupplierDebt[]>>;
  payCustomerDebts: (
    customerIds: string[],
    paymentMethod: "cash" | "bank",
    timestamp: string
  ) => void;
  paySupplierDebts: (
    supplierIds: string[],
    paymentMethod: "cash" | "bank",
    timestamp: string
  ) => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({
  children,
}) => {
  // --- State ---
  const [currentBranchId] = useState("CN1");

  // Load from localStorage on init (once)
  const getInitialData = () => {
    try {
      const stored = localStorage.getItem("motocare-data");
      if (stored) {
        return JSON.parse(stored);
      }
    } catch (error) {
      console.error("Error loading from localStorage:", error);
    }
    return {};
  };

  const initialData = getInitialData();

  const [parts, setParts] = useState<Part[]>(() => initialData?.parts || []);
  const [customers, setCustomers] = useState<Customer[]>(
    () => initialData?.customers || []
  );
  const [suppliers, setSuppliers] = useState<Supplier[]>(
    () => initialData?.suppliers || []
  );
  const [sales, setSales] = useState<Sale[]>(() => initialData?.sales || []);
  const [workOrders, setWorkOrders] = useState<WorkOrder[]>(
    () => initialData?.workOrders || []
  );
  const [cartItems, setCartItems] = useState<CartItem[]>(
    () => initialData?.cartItems || []
  );
  const [paymentSources, setPaymentSources] = useState<PaymentSource[]>(
    () =>
      initialData?.paymentSources || [
        { id: "cash", name: "Tiß╗ün mß║╖t", balance: { CN1: 0 }, isDefault: true },
        { id: "bank", name: "T├ái khoß║ún ng├ón h├áng", balance: { CN1: 0 } },
      ]
  );
  const [cashTransactions, setCashTransactions] = useState<CashTransaction[]>(
    () => initialData?.cashTransactions || []
  );
  const [inventoryTransactions, setInventoryTransactions] = useState<
    InventoryTransaction[]
  >(() => initialData?.inventoryTransactions || []);
  const [employees, setEmployees] = useState<Employee[]>(
    () => initialData?.employees || []
  );
  const [payrollRecords, setPayrollRecords] = useState<PayrollRecord[]>(
    () => initialData?.payrollRecords || []
  );
  const [loans, setLoans] = useState<Loan[]>(() => initialData?.loans || []);
  const [loanPayments, setLoanPayments] = useState<LoanPayment[]>(
    () => initialData?.loanPayments || []
  );
  const [customerDebts, setCustomerDebts] = useState<CustomerDebt[]>(
    () => initialData?.customerDebts || []
  );
  const [supplierDebts, setSupplierDebts] = useState<SupplierDebt[]>(
    () => initialData?.supplierDebts || []
  );

  // --- Fetch paymentSources from DB on mount to sync with Supabase ---
  useEffect(() => {
    const fetchPaymentSources = async () => {
      try {
        console.log('[AppContext] ≡ƒöä Fetching payment_sources from DB...');
        const [paymentSourcesRes, payrollRes] = await Promise.all([
          supabase.from("payment_sources").select("*"),
          supabase.from("payroll_records").select("*"),
        ]);

        if (!paymentSourcesRes.error && Array.isArray(paymentSourcesRes.data)) {
          if (paymentSourcesRes.data.length > 0) {
            console.log('[AppContext] Γ£à Loaded payment_sources:', paymentSourcesRes.data);
            setPaymentSources(paymentSourcesRes.data);
          } else {
            console.warn('[AppContext] ΓÜá∩╕Å payment_sources empty on first fetch, retrying once...');
            const retryRes = await supabase.from("payment_sources").select("*");
            if (!retryRes.error && Array.isArray(retryRes.data) && retryRes.data.length > 0) {
              console.log('[AppContext] Γ£à Loaded payment_sources after retry:', retryRes.data);
              setPaymentSources(retryRes.data);
            } else {
              console.warn('[AppContext] ΓÜá∩╕Å Keep existing paymentSources, skip overwrite with empty data');
            }
          }
        } else if (paymentSourcesRes.error) {
          console.error('[AppContext] Γ¥î Failed to load payment_sources:', paymentSourcesRes.error);
        }

        if (!payrollRes.error && payrollRes.data) {
          // Map DB columns back to camelCase for application use
          const mappedPayroll = payrollRes.data.map((r) => ({
            id: r.id,
            employeeId: r.employee_id,
            employeeName: r.employee_name,
            month: r.month,
            baseSalary: r.base_salary,
            allowances: r.allowances,
            bonus: r.bonus,
            deduction: r.deduction,
            workDays: r.work_days,
            standardWorkDays: r.standard_work_days,
            socialInsurance: r.social_insurance,
            healthInsurance: r.health_insurance,
            unemploymentInsurance: r.unemployment_insurance,
            personalIncomeTax: r.personal_income_tax,
            netSalary: r.net_salary,
            paymentStatus: r.payment_status,
            paymentDate: r.payment_date,
            paymentMethod: r.payment_method,
            notes: r.notes,
            branchId: r.branch_id,
            created_at: r.created_at,
          }));
          setPayrollRecords(mappedPayroll);
        }
      } catch (err) {
        console.error("Failed to fetch initial data from Supabase:", err);
      }
    };
    fetchPaymentSources();
  }, []);

  // --- Persist to localStorage ---
  useEffect(() => {
    const data = {
      parts,
      customers,
      suppliers,
      sales,
      workOrders,
      cartItems,
      paymentSources,
      cashTransactions,
      inventoryTransactions,
      employees,
      payrollRecords,
      loans,
      loanPayments,
      customerDebts,
      supplierDebts,
    };
    localStorage.setItem("motocare-data", JSON.stringify(data));
  }, [
    parts,
    customers,
    suppliers,
    sales,
    workOrders,
    cartItems,
    paymentSources,
    cashTransactions,
    inventoryTransactions,
    employees,
    payrollRecords,
    loans,
    loanPayments,
    customerDebts,
    supplierDebts,
  ]);

  // --- Helpers ---
  const upsertPart = useCallback(
    (part: Partial<Part> & { id?: string }) => {
      setParts((prev) => {
        if (part.id) {
          return prev.map((p) =>
            p.id === part.id ? ({ ...p, ...part } as Part) : p
          );
        }
        const id = `PART-${Date.now()}-${Math.random().toString(16).slice(2)}`;
        const newPart: Part = {
          id,
          name: part.name || "T├¬n phß╗Ñ t├╣ng",
          sku: part.sku || id,
          stock: part.stock || { [currentBranchId]: 0 },
          retailPrice: part.retailPrice || { [currentBranchId]: 0 },
          wholesalePrice: part.wholesalePrice || { [currentBranchId]: 0 },
          category: part.category,
          description: part.description,
          warrantyPeriod: part.warrantyPeriod,
          created_at: new Date().toISOString(),
        };
        return [newPart, ...prev];
      });
    },
    [currentBranchId]
  );

  const deletePart = useCallback((partId: string) => {
    setParts((prev) => prev.filter((p) => p.id !== partId));
  }, []);

  const upsertCustomer = useCallback(
    async (customer: Partial<Customer> & { id?: string }): Promise<string> => {
      // Prepare customer data for database
      const customerId =
        customer.id ||
        `CUS-${Date.now()}-${Math.random().toString(16).slice(2)}`;

      // Check if customer exists in local state
      let existingCustomer = customers.find((c) => c.id === customer.id);

      // Nß║┐u kh├┤ng c├│ trong local state nh╞░ng c├│ ID, kiß╗âm tra trong database
      if (!existingCustomer && customer.id) {
        try {
          const { data: dbCustomer } = await supabase
            .from("customers")
            .select("id")
            .eq("id", customer.id)
            .maybeSingle(); // Use maybeSingle to avoid 406 error when not found
          if (dbCustomer) {
            existingCustomer = { id: dbCustomer.id } as Customer;
          }
        } catch {
          // Kh├┤ng t├¼m thß║Ñy trong DB, sß║╜ insert mß╗¢i
        }
      }

      try {
        if (existingCustomer) {
          // Update existing customer in Supabase
          const { error } = await supabase
            .from("customers")
            .update({
              name: customer.name || existingCustomer.name,
              phone: customer.phone || existingCustomer.phone || null,
              vehiclemodel:
                customer.vehicleModel || existingCustomer.vehicleModel || null,
              licenseplate:
                customer.licensePlate || existingCustomer.licensePlate || null,
              vehicles: customer.vehicles || existingCustomer.vehicles || [],
              status: customer.status || existingCustomer.status || "active",
              segment: customer.segment || existingCustomer.segment || "New",
              loyaltypoints:
                customer.loyaltyPoints ?? existingCustomer.loyaltyPoints ?? 0,
              totalspent:
                customer.totalSpent ?? existingCustomer.totalSpent ?? 0,
              visitcount:
                customer.visitCount ?? existingCustomer.visitCount ?? 0,
              lastvisit:
                customer.lastVisit || existingCustomer.lastVisit || null,
            })
            .eq("id", customer.id);

          if (error) {
            console.error("Error updating customer in Supabase:", error);
            showToast.error("Lß╗ùi cß║¡p nhß║¡t kh├ích h├áng");
          }
        } else {
          // Kiß╗âm tra sß╗æ ─æiß╗çn thoß║íi tr├╣ng lß║╖p tr╞░ß╗¢c khi th├¬m mß╗¢i
          // CHß╗ê kiß╗âm tra nß║┐u c├│ S─ÉT V├Ç kh├┤ng phß║úi update kh├ích h├áng hiß╗çn tß║íi
          if (customer.phone) {
            const { data: duplicates } = await supabase
              .from("customers")
              .select("id, name, vehiclemodel, licenseplate, vehicles")
              .eq("phone", customer.phone)
              .limit(1);

            // Nß║┐u t├¼m thß║Ñy kh├ích h├áng vß╗¢i c├╣ng S─ÉT - Cß║¼P NHß║¼T thay v├¼ b├ío lß╗ùi
            if (duplicates && duplicates.length > 0) {
              const existingId = duplicates[0].id;
              console.log(
                "Kh├ích h├áng ─æ├ú tß╗ôn tß║íi vß╗¢i S─ÉT n├áy, chuyß╗ân sang UPDATE:",
                customer.phone,
                "ID:",
                existingId
              );

              // Cß║¡p nhß║¡t th├┤ng tin kh├ích h├áng hiß╗çn c├│ (merge vehicles nß║┐u cß║ºn)
              const existingVehicles = duplicates[0].vehicles || [];
              let updatedVehicles = existingVehicles;

              // Nß║┐u c├│ xe mß╗¢i, th├¬m v├áo danh s├ích
              if (customer.vehicles && customer.vehicles.length > 0) {
                const newVehicle = customer.vehicles[0];
                const vehicleExists = existingVehicles.some(
                  (v: any) =>
                    v.licensePlate === newVehicle.licensePlate ||
                    v.id === newVehicle.id
                );
                if (!vehicleExists && newVehicle.licensePlate) {
                  updatedVehicles = [...existingVehicles, newVehicle];
                }
              }

              const { error: updateError } = await supabase
                .from("customers")
                .update({
                  name: customer.name || duplicates[0].name || "Kh├ích h├áng",
                  vehiclemodel:
                    customer.vehicleModel || duplicates[0].vehiclemodel || null,
                  licenseplate:
                    customer.licensePlate || duplicates[0].licenseplate || null,
                  vehicles: updatedVehicles,
                  lastvisit: new Date().toISOString(),
                })
                .eq("id", existingId);

              if (updateError) {
                console.error("Lß╗ùi cß║¡p nhß║¡t kh├ích h├áng:", updateError);
              } else {
                console.log("─É├ú cß║¡p nhß║¡t kh├ích h├áng:", existingId);
              }

              // Cß║¡p nhß║¡t local state vß╗¢i ID thß╗▒c cß╗ºa kh├ích h├áng
              setCustomers((prev) => {
                const existingIndex = prev.findIndex(
                  (c) => c.id === existingId
                );
                if (existingIndex >= 0) {
                  // Kh├ích h├áng ─æ├ú c├│ trong local state, cß║¡p nhß║¡t
                  return prev.map((c) =>
                    c.id === existingId
                      ? ({
                        ...c,
                        name: customer.name || c.name,
                        vehicleModel: customer.vehicleModel || c.vehicleModel,
                        licensePlate: customer.licensePlate || c.licensePlate,
                        vehicles: updatedVehicles,
                      } as Customer)
                      : c
                  );
                }
                // Kh├ích h├áng ch╞░a c├│ trong local state (c├│ thß╗â do pagination), th├¬m v├áo
                const updatedCustomer: Customer = {
                  id: existingId,
                  name: customer.name || duplicates[0].name || "Kh├ích h├áng",
                  phone: customer.phone,
                  vehicleModel: customer.vehicleModel || duplicates[0].vehiclemodel || undefined,
                  licensePlate: customer.licensePlate || duplicates[0].licenseplate || undefined,
                  vehicles: updatedVehicles,
                  created_at: new Date().toISOString(),
                } as Customer;
                return [updatedCustomer, ...prev];
              });
              return existingId; // Trß║ú vß╗ü ID thß╗▒c cß╗ºa kh├ích h├áng ─æ├ú tß╗ôn tß║íi
            }
          }

          // Th├¬m kh├ích h├áng mß╗¢i v├áo Supabase
          const { error } = await supabase.from("customers").insert([
            {
              id: customerId,
              name: customer.name || "Kh├ích h├áng",
              phone: customer.phone || null,
              vehiclemodel: customer.vehicleModel || null,
              licenseplate: customer.licensePlate || null,
              vehicles: customer.vehicles || [],
              status: customer.status || "active",
              segment: customer.segment || "New",
              loyaltypoints: customer.loyaltyPoints ?? 0,
              totalspent: customer.totalSpent ?? 0,
              visitcount: customer.visitCount ?? 0, // Mß║╖c ─æß╗ïnh 0, sß║╜ t─âng khi c├│ phiß║┐u sß╗¡a/b├ín h├áng
              lastvisit: customer.lastVisit || null, // Null nß║┐u ch╞░a c├│ giao dß╗ïch
            },
          ]);

          if (error) {
            console.error("Lß╗ùi th├¬m kh├ích h├áng v├áo Supabase:", error);
            showToast.error("Lß╗ùi l╞░u kh├ích h├áng mß╗¢i");
            return customerId; // Vß║½n trß║ú vß╗ü ID mß╗¢i d├╣ lß╗ùi
          } else {
            showToast.success("─É├ú l╞░u kh├ích h├áng mß╗¢i");
            return customerId; // Trß║ú vß╗ü ID mß╗¢i
          }
        }
      } catch (err) {
        console.error("Error saving customer to database:", err);
      }

      // Update local state (keep all fields for UI)
      setCustomers((prev) => {
        if (customer.id) {
          // Update existing customer
          const existingIndex = prev.findIndex((c) => c.id === customer.id);
          if (existingIndex >= 0) {
            return prev.map((c) =>
              c.id === customer.id ? ({ ...c, ...customer } as Customer) : c
            );
          }
          // ID provided but not found, create new with that ID
          const newCustomer: Customer = {
            id: customer.id,
            name: customer.name || "Kh├ích h├áng",
            phone: customer.phone,
            created_at: new Date().toISOString(),
            ...customer, // Spread all other fields
          } as Customer;
          return [newCustomer, ...prev];
        }
        // No ID provided, generate new
        const newCustomer: Customer = {
          id: customerId,
          name: customer.name || "Kh├ích h├áng",
          phone: customer.phone,
          created_at: new Date().toISOString(),
          ...customer, // Spread all other fields
        } as Customer;
        return [newCustomer, ...prev];
      });
      
      return customerId; // Trß║ú vß╗ü ID cuß╗æi c├╣ng
    },
    [customers]
  );

  const upsertSupplier = useCallback(
    (supplier: Partial<Supplier> & { id?: string }) => {
      setSuppliers((prev) => {
        if (supplier.id) {
          return prev.map((s) =>
            s.id === supplier.id ? ({ ...s, ...supplier } as Supplier) : s
          );
        }
        const id = `SUP-${Date.now()}-${Math.random().toString(16).slice(2)}`;
        const newSupplier: Supplier = {
          id,
          name: supplier.name || "Nh├á cung cß║Ñp",
          phone: supplier.phone,
          email: supplier.email,
          address: supplier.address,
          created_at: new Date().toISOString(),
        };
        return [newSupplier, ...prev];
      });
    },
    []
  );

  const upsertWorkOrder = useCallback((order: WorkOrder) => {
    setWorkOrders((prev) => {
      const existing = prev.find((w) => w.id === order.id);
      if (existing) {
        return prev.map((w) => (w.id === order.id ? order : w));
      }
      return [order, ...prev];
    });
  }, []);

  const clearCart = useCallback(() => setCartItems([]), []);

  const finalizeSale = useCallback(
    (data: {
      items: CartItem[];
      discount: number;
      paymentMethod: "cash" | "bank";
      customer: { id?: string; name: string; phone?: string };
      note?: string;
    }) => {
      if (!data.items.length) return;
      // Compute subtotal and per-line discounts if present
      const lineSubtotal = data.items.reduce(
        (sum, it) => sum + it.sellingPrice * it.quantity,
        0
      );
      const lineDiscounts = data.items.reduce(
        (sum, it) => sum + (it.discount || 0),
        0
      );
      const total = lineSubtotal - lineDiscounts - data.discount;
      const saleId = `SALE-${Date.now()}`;
      const newSale: Sale = {
        id: saleId,
        date: new Date().toISOString(),
        items: data.items,
        subtotal: lineSubtotal,
        discount: data.discount + lineDiscounts,
        total,
        customer: data.customer,
        paymentMethod: data.paymentMethod,
        userId: "local-user",
        userName: "Local User",
        branchId: currentBranchId,
        cashTransactionId: undefined,
      };
      setSales((prev) => [newSale, ...prev]);

      // Adjust part stock
      setParts((prev) =>
        prev.map((p) => {
          const soldQty = data.items
            .filter((i) => i.partId === p.id)
            .reduce((s, i) => s + i.quantity, 0);
          if (!soldQty) return p;
          return {
            ...p,
            stock: {
              ...p.stock,
              [currentBranchId]: (p.stock[currentBranchId] || 0) - soldQty,
            },
          };
        })
      );

      // Record cash transaction
      const ctId = `CT-${Date.now()}`;
      const cashTx: CashTransaction = {
        id: ctId,
        type: "income",
        date: new Date().toISOString(),
        amount: total,
        notes: data.note || "Thu tiß╗ün b├ín h├áng",
        paymentSourceId: data.paymentMethod,
        branchId: currentBranchId,
        category: "sale_income",
        saleId,
      };
      setCashTransactions((prev) => [cashTx, ...prev]);

      // Update payment source balance
      setPaymentSources((prev) =>
        prev.map((ps) =>
          ps.id === data.paymentMethod
            ? {
              ...ps,
              balance: {
                ...ps.balance,
                [currentBranchId]: (ps.balance[currentBranchId] || 0) + total,
              },
            }
            : ps
        )
      );

      clearCart();
    },
    [clearCart, currentBranchId]
  );

  const deleteSale = useCallback(
    (saleId: string) => {
      // Find the sale
      const sale = sales.find((s) => s.id === saleId);
      if (!sale) return;

      // Remove sale
      setSales((prev) => prev.filter((s) => s.id !== saleId));

      // Restore part stock
      setParts((prev) =>
        prev.map((p) => {
          const soldQty = sale.items
            .filter((i) => i.partId === p.id)
            .reduce((s, i) => s + i.quantity, 0);
          if (!soldQty) return p;
          return {
            ...p,
            stock: {
              ...p.stock,
              [currentBranchId]: (p.stock[currentBranchId] || 0) + soldQty,
            },
          };
        })
      );

      // Remove related cash transaction
      setCashTransactions((prev) => prev.filter((ct) => ct.saleId !== saleId));

      // Restore payment source balance
      setPaymentSources((prev) =>
        prev.map((ps) =>
          ps.id === sale.paymentMethod
            ? {
              ...ps,
              balance: {
                ...ps.balance,
                [currentBranchId]:
                  (ps.balance[currentBranchId] || 0) - sale.total,
              },
            }
            : ps
        )
      );
    },
    [sales, currentBranchId]
  );

  const recordInventoryTransaction = useCallback(
    (tx: Omit<InventoryTransaction, "id">) => {
      const id = `INV-${Date.now()}-${Math.random().toString(16).slice(2)}`;
      const full: InventoryTransaction = { id, ...tx };
      setInventoryTransactions((prev) => [full, ...prev]);
    },
    []
  );

  const upsertEmployee = useCallback(
    (employee: Partial<Employee> & { id?: string }) => {
      setEmployees((prev) => {
        if (employee.id) {
          return prev.map((e) =>
            e.id === employee.id ? ({ ...e, ...employee } as Employee) : e
          );
        }
        const id = `EMP-${Date.now()}-${Math.random().toString(16).slice(2)}`;
        const newEmployee: Employee = {
          id,
          name: employee.name || "Nh├ón vi├¬n",
          phone: employee.phone,
          position: employee.position || "",
          baseSalary: employee.baseSalary || 0,
          startDate: employee.startDate || new Date().toISOString(),
          status: employee.status || "active",
          created_at: new Date().toISOString(),
        };
        return [newEmployee, ...prev];
      });
    },
    []
  );

  const upsertPayrollRecord = useCallback(async (record: PayrollRecord) => {
    // 1. Prepare DB data
    const dbData = {
      id: record.id,
      employee_id: record.employeeId,
      employee_name: record.employeeName,
      month: record.month,
      base_salary: record.baseSalary,
      allowances: record.allowances,
      bonus: record.bonus,
      deduction: record.deduction,
      work_days: record.workDays,
      standard_work_days: record.standardWorkDays,
      social_insurance: record.socialInsurance,
      health_insurance: record.healthInsurance,
      unemployment_insurance: record.unemploymentInsurance,
      personal_income_tax: record.personalIncomeTax,
      net_salary: record.netSalary,
      payment_status: record.paymentStatus,
      payment_date: record.paymentDate,
      payment_method: record.paymentMethod,
      notes: record.notes,
      branch_id: record.branchId,
      created_at: record.created_at || new Date().toISOString(),
    };

    // 2. Call Supabase
    const { error } = await supabase.from("payroll_records").upsert(dbData);

    if (error) {
      console.error("Error upserting payroll record:", error);
      showToast.error("Lß╗ùi l╞░u bß║úng l╞░╞íng");
      return;
    }

    // 3. Update local state
    setPayrollRecords((prev) => {
      const existing = prev.find((p) => p.id === record.id);
      if (existing) {
        return prev.map((p) => (p.id === record.id ? record : p));
      }
      return [record, ...prev];
    });
  }, []);

  const upsertLoan = useCallback(
    (loan: Partial<Loan> & { id?: string }) => {
      setLoans((prev) => {
        if (loan.id) {
          return prev.map((l) =>
            l.id === loan.id ? ({ ...l, ...loan } as Loan) : l
          );
        }
        const id = `LOAN-${Date.now()}-${Math.random().toString(16).slice(2)}`;
        const newLoan: Loan = {
          id,
          lenderName: loan.lenderName || "",
          loanType: loan.loanType || "bank",
          principal: loan.principal || 0,
          interestRate: loan.interestRate || 0,
          term: loan.term || 0,
          startDate: loan.startDate || new Date().toISOString(),
          endDate: loan.endDate || new Date().toISOString(),
          monthlyPayment: loan.monthlyPayment || 0,
          remainingAmount: loan.remainingAmount || loan.principal || 0,
          status: loan.status || "active",
          purpose: loan.purpose,
          collateral: loan.collateral,
          branchId: currentBranchId,
          created_at: new Date().toISOString(),
        };
        return [newLoan, ...prev];
      });
    },
    [currentBranchId]
  );

  const upsertLoanPayment = useCallback((payment: LoanPayment) => {
    setLoanPayments((prev) => {
      const existing = prev.find((p) => p.id === payment.id);
      if (existing) {
        return prev.map((p) => (p.id === payment.id ? payment : p));
      }
      return [payment, ...prev];
    });
  }, []);

  // Pay customer debts (bulk)
  const payCustomerDebts = useCallback(
    (
      customerIds: string[],
      paymentMethod: "cash" | "bank",
      timestamp: string
    ) => {
      let totalPaid = 0;

      // Update customer debts
      setCustomerDebts(
        (prev) =>
          prev
            .map((debt) => {
              if (
                customerIds.includes(debt.customerId) &&
                debt.branchId === currentBranchId
              ) {
                const amountToPay = debt.remainingAmount;
                totalPaid += amountToPay;

                return {
                  ...debt,
                  paidAmount: debt.totalAmount,
                  remainingAmount: 0,
                  status: "paid" as const,
                };
              }
              return debt;
            })
            .filter((debt) => debt.remainingAmount > 0) // Remove fully paid debts
      );

      // Ghi sß╗ò quß╗╣ v├á cß║¡p nhß║¡t sß╗æ d╞░ nguß╗ôn tiß╗ün tr├¬n Supabase
      if (totalPaid > 0) {
        void (async () => {
          const { data: userData } = await supabase.auth.getUser();
          const userId = userData?.user?.id || null;
          const cashRes = await createCashTransaction({
            type: "income",
            amount: totalPaid,
            branchId: currentBranchId,
            paymentSourceId: paymentMethod,
            date: timestamp,
            category: "debt_collection",
            notes: `Thu hß║┐t nß╗ú cho ${customerIds.length} kh├ích h├áng`,
            recipient: `Thu nß╗ú ${customerIds.length} kh├ích h├áng`,
          });
          if (!cashRes.ok) {
            showToast.error(mapRepoErrorForUser(cashRes.error));
            return;
          }
          const balRes = await updatePaymentSourceBalance(
            paymentMethod,
            currentBranchId,
            totalPaid
          );
          if (!balRes.ok) {
            showToast.error(mapRepoErrorForUser(balRes.error));
          }
          // Audit: thu nß╗ú kh├ích h├áng
          void safeAudit(userId, {
            action: "debt.customer_pay",
            tableName: "customer_debts",
            oldData: null,
            newData: { customerIds, totalPaid, paymentMethod, timestamp },
          });
        })();
      }
    },
    [currentBranchId]
  );

  // Pay supplier debts (bulk)
  const paySupplierDebts = useCallback(
    (
      supplierIds: string[],
      paymentMethod: "cash" | "bank",
      timestamp: string
    ) => {
      let totalPaid = 0;

      // Update supplier debts
      setSupplierDebts(
        (prev) =>
          prev
            .map((debt) => {
              if (
                supplierIds.includes(debt.supplierId) &&
                debt.branchId === currentBranchId
              ) {
                const amountToPay = debt.remainingAmount;
                totalPaid += amountToPay;

                return {
                  ...debt,
                  paidAmount: debt.totalAmount,
                  remainingAmount: 0,
                  status: "paid" as const,
                };
              }
              return debt;
            })
            .filter((debt) => debt.remainingAmount > 0) // Remove fully paid debts
      );

      // Ghi sß╗ò quß╗╣ v├á cß║¡p nhß║¡t sß╗æ d╞░ nguß╗ôn tiß╗ün tr├¬n Supabase
      if (totalPaid > 0) {
        void (async () => {
          const { data: userData } = await supabase.auth.getUser();
          const userId = userData?.user?.id || null;
          const cashRes = await createCashTransaction({
            type: "expense",
            amount: totalPaid,
            branchId: currentBranchId,
            paymentSourceId: paymentMethod,
            date: timestamp,
            category: "debt_payment",
            notes: `Trß║ú hß║┐t nß╗ú cho ${supplierIds.length} nh├á cung cß║Ñp`,
            recipient: `Trß║ú nß╗ú ${supplierIds.length} nh├á cung cß║Ñp`,
          });
          if (!cashRes.ok) {
            showToast.error(mapRepoErrorForUser(cashRes.error));
            return;
          }
          const balRes = await updatePaymentSourceBalance(
            paymentMethod,
            currentBranchId,
            -totalPaid
          );
          if (!balRes.ok) {
            showToast.error(mapRepoErrorForUser(balRes.error));
          }
          // Audit: trß║ú nß╗ú nh├á cung cß║Ñp
          void safeAudit(userId, {
            action: "debt.supplier_pay",
            tableName: "supplier_debts",
            oldData: null,
            newData: { supplierIds, totalPaid, paymentMethod, timestamp },
          });
        })();
      }
    },
    [currentBranchId]
  );

  return (
    <AppContext.Provider
      value={{
        parts,
        customers,
        suppliers,
        sales,
        workOrders,
        cartItems,
        paymentSources,
        cashTransactions,
        inventoryTransactions,
        employees,
        payrollRecords,
        loans,
        loanPayments,
        customerDebts,
        supplierDebts,
        currentBranchId,
        setParts,
        upsertPart,
        deletePart,
        setCustomers,
        upsertCustomer,
        setSuppliers,
        upsertSupplier,
        setWorkOrders,
        upsertWorkOrder,
        setCartItems,
        clearCart,
        deleteSale,
        finalizeSale,
        setPaymentSources,
        setCashTransactions,
        recordInventoryTransaction,
        setEmployees,
        upsertEmployee,
        setPayrollRecords,
        upsertPayrollRecord,
        setLoans,
        upsertLoan,
        setLoanPayments,
        upsertLoanPayment,
        setCustomerDebts,
        setSupplierDebts,
        payCustomerDebts,
        paySupplierDebts,
      }}
    >
      {children}
    </AppContext.Provider>
  );
};

export const useAppContext = () => {
  const ctx = useContext(AppContext);
  if (!ctx) throw new Error("useAppContext phß║úi d├╣ng b├¬n trong AppProvider");
  return ctx;
};

import { createContext, useContext, useEffect, useState } from "react";
// Use a single Supabase client app-wide to avoid multiple GoTrue instances
import { supabase } from "../supabaseClient";
import type {
  User,
  Session,
  AuthChangeEvent,
  AuthenticatorAssuranceLevels,
} from "@supabase/supabase-js";
import { safeAudit } from "../lib/repository/auditLogsRepository";
import { showToast } from "../utils/toast";

export type UserRole = "owner" | "manager" | "staff";

export interface UserProfile {
  id: string;
  email: string;
  role: UserRole;
  name?: string;
  full_name?: string; // legacy fallback
  avatar_url?: string;
  branch_id?: string | null;
  created_at: string;
}

interface AuthContextType {
  user: User | null;
  profile: UserProfile | null;
  session: Session | null;
  loading: boolean;
  error: string | null;
  // MFA state
  mfaRequired: boolean;
  currentAAL: AuthenticatorAssuranceLevels | null;
  // Methods
  signIn: (
    email: string,
    password: string
  ) => Promise<{ mfaRequired: boolean }>;
  signOut: () => Promise<void>;
  hasRole: (roles: UserRole[]) => boolean;
  completeMFAVerification: () => void;
  checkMFAStatus: () => Promise<{
    hasMFA: boolean;
    requiresVerification: boolean;
  }>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error("useAuth must be used within AuthProvider");
  }
  return context;
};

export const AuthProvider = ({ children }: { children: React.ReactNode }) => {
  const [user, setUser] = useState<User | null>(null);
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [session, setSession] = useState<Session | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  // MFA state
  const [mfaRequired, setMfaRequired] = useState(false);
  const [currentAAL, setCurrentAAL] =
    useState<AuthenticatorAssuranceLevels | null>(null);

  useEffect(() => {
    let timeoutId: NodeJS.Timeout | undefined;

    // Get initial session
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      setUser(session?.user ?? null);
      if (session?.user) {
        // Set timeout to prevent infinite loading
        timeoutId = setTimeout(() => {
          console.warn('Profile loading timeout - forcing loading to false');
          setLoading(false);
        }, 10000); // 10 second timeout

        loadUserProfile(session.user.id).finally(() => {
          if (timeoutId) clearTimeout(timeoutId);
        });
      } else {
        setLoading(false);
      }
    });

    // Listen for auth changes
    const handleAuthEvent = async (
      event: AuthChangeEvent,
      nextSession: Session | null
    ) => {
      setSession(nextSession);
      setUser(nextSession?.user ?? null);
      if (nextSession?.user) {
        loadUserProfile(nextSession.user.id);
      } else {
        setProfile(null);
        setLoading(false);
      }
    };

    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange(handleAuthEvent);

    return () => {
      subscription.unsubscribe();
      if (timeoutId) clearTimeout(timeoutId);
    };
  }, []);

  const loadUserProfile = async (userId: string) => {
    try {
      // ╞»u ti├¬n bß║úng profiles tr╞░ß╗¢c, sau ─æ├│ fallback sang user_profiles nß║┐u kh├┤ng c├│ hoß║╖c bß║úng kh├┤ng tß╗ôn tß║íi
      let { data, error } = await supabase
        .from("profiles")
        .select("*")
        .eq("id", userId)
        .maybeSingle();

      if (error && (error as any).code !== "PGRST116") {
        // Lß╗ùi kh├íc PGRST116 (table not found) => n├⌐m lß╗ùi ─æß╗â hiß╗ân thß╗ï
        throw error;
      }

      if (!data) {
        const alt = await supabase
          .from("user_profiles")
          .select("*")
          .eq("id", userId)
          .maybeSingle();
        data = alt.data as any;
        error = alt.error as any;
        if (error && (error as any).code !== "PGRST116") throw error;
      }

      if (error) throw error;
      if (!data) {
        // Nß║┐u kh├┤ng c├│ profile, tß║ío mß╗Öt profile mß║╖c ─æß╗ïnh ─æß╗â tr├ính stuck
        console.warn('No profile found for user, creating default profile');
        const defaultProfile: UserProfile = {
          id: userId,
          email: user?.email || 'unknown',
          role: 'staff', // default role
          created_at: new Date().toISOString(),
        };
        setProfile(defaultProfile);
      } else {
        setProfile(data as any);
      }
    } catch (error) {
      console.error("Error loading user profile:", error);
      // Tß║ío profile mß║╖c ─æß╗ïnh thay v├¼ set null ─æß╗â tr├ính stuck
      const defaultProfile: UserProfile = {
        id: userId,
        email: user?.email || 'unknown',
        role: 'staff',
        created_at: new Date().toISOString(),
      };
      setProfile(defaultProfile);
      setError("Kh├┤ng thß╗â tß║úi hß╗ô s╞í ng╞░ß╗¥i d├╣ng");
    } finally {
      setLoading(false);
    }
  };

  const signIn = async (
    email: string,
    password: string
  ): Promise<{ mfaRequired: boolean }> => {
    const { error, data } = await supabase.auth.signInWithPassword({
      email,
      password,
    });
    if (error) throw error;
    setError(null);

    // Check if MFA is required
    const { data: aalData } =
      await supabase.auth.mfa.getAuthenticatorAssuranceLevel();

    if (aalData) {
      setCurrentAAL(aalData.currentLevel);

      // If user has MFA enrolled and hasn't verified yet (AAL1 but needs AAL2)
      if (aalData.nextLevel === "aal2" && aalData.currentLevel === "aal1") {
        setMfaRequired(true);
        // Audit login attempt (best-effort)
        const userId = data?.user?.id || null;
        void safeAudit(userId, { action: "auth.login_mfa_pending" });
        return { mfaRequired: true };
      }
    }

    // No MFA required, complete login
    const userId = data?.user?.id || null;
    void safeAudit(userId, { action: "auth.login" });
    return { mfaRequired: false };
  };

  // Called after successful MFA verification
  const completeMFAVerification = () => {
    setMfaRequired(false);
    setCurrentAAL("aal2");
    // Audit successful MFA login
    if (user?.id) {
      void safeAudit(user.id, { action: "auth.login_mfa_success" });
    }
  };

  // Check MFA status for current user
  const checkMFAStatus = async (): Promise<{
    hasMFA: boolean;
    requiresVerification: boolean;
  }> => {
    try {
      const { data: factorsData } = await supabase.auth.mfa.listFactors();
      const { data: aalData } =
        await supabase.auth.mfa.getAuthenticatorAssuranceLevel();

      const verifiedFactors =
        factorsData?.totp?.filter((f) => f.status === "verified") || [];
      const hasMFA = verifiedFactors.length > 0;
      const requiresVerification =
        aalData?.nextLevel === "aal2" && aalData?.currentLevel === "aal1";

      return { hasMFA, requiresVerification };
    } catch (err) {
      console.error("Error checking MFA status:", err);
      return { hasMFA: false, requiresVerification: false };
    }
  };

  const signOut = async () => {
    const currentUserId = user?.id || null;
    const { error } = await supabase.auth.signOut();
    if (error) throw error;
    setError(null);
    // Audit logout (best-effort)
    void safeAudit(currentUserId, { action: "auth.logout" });
  };

  const hasRole = (roles: UserRole[]): boolean => {
    if (!profile) return false;
    return roles.includes(profile.role);
  };

  const value = {
    user,
    profile,
    session,
    loading,
    error,
    // MFA
    mfaRequired,
    currentAAL,
    // Methods
    signIn,
    signOut,
    hasRole,
    completeMFAVerification,
    checkMFAStatus,
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
};

import React, { createContext, useContext, useState, useCallback } from "react";
import type { CartItem } from "../types";

interface CartContextType {
  cartItems: CartItem[];
  setCartItems: React.Dispatch<React.SetStateAction<CartItem[]>>;
  clearCart: () => void;
  addToCart: (item: CartItem) => void;
  removeFromCart: (itemId: string) => void;
  updateCartItemQuantity: (itemId: string, quantity: number) => void;
  cartTotal: number;
  cartItemCount: number;
}

const CartContext = createContext<CartContextType | undefined>(undefined);

export const CartProvider: React.FC<{ children: React.ReactNode }> = ({
  children,
}) => {
  const [cartItems, setCartItems] = useState<CartItem[]>([]);

  const clearCart = useCallback(() => setCartItems([]), []);

  const addToCart = useCallback((item: CartItem) => {
    setCartItems((prev) => {
      const existing = prev.find((i) => i.partId === item.partId);
      if (existing) {
        return prev.map((i) =>
          i.partId === item.partId
            ? { ...i, quantity: i.quantity + item.quantity }
            : i
        );
      }
      return [...prev, item];
    });
  }, []);

  const removeFromCart = useCallback((itemId: string) => {
    setCartItems((prev) => prev.filter((i) => i.partId !== itemId));
  }, []);

  const updateCartItemQuantity = useCallback(
    (itemId: string, quantity: number) => {
      if (quantity <= 0) {
        removeFromCart(itemId);
        return;
      }
      setCartItems((prev) =>
        prev.map((i) => (i.partId === itemId ? { ...i, quantity } : i))
      );
    },
    [removeFromCart]
  );

  const cartTotal = cartItems.reduce(
    (sum, item) => sum + item.sellingPrice * item.quantity,
    0
  );

  const cartItemCount = cartItems.reduce((sum, item) => sum + item.quantity, 0);

  return (
    <CartContext.Provider
      value={{
        cartItems,
        setCartItems,
        clearCart,
        addToCart,
        removeFromCart,
        updateCartItemQuantity,
        cartTotal,
        cartItemCount,
      }}
    >
      {children}
    </CartContext.Provider>
  );
};

export const useCart = (): CartContextType => {
  const context = useContext(CartContext);
  if (!context) {
    throw new Error("useCart must be used within a CartProvider");
  }
  return context;
};

export default CartContext;

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { useStoreSettings } from "../hooks/useStoreSettings";

type Theme = 'light' | 'dark';

type BrandPreset = "logo" | "blue" | "emerald" | "amber" | "custom";

const BRAND_PRESETS: Record<Exclude<BrandPreset, "custom">, { primary: string; secondary: string }> = {
  logo: { primary: "16 185 129", secondary: "245 158 11" }, // emerald-500 / amber-500
  blue: { primary: "59 130 246", secondary: "37 99 235" }, // blue-500 / blue-600
  emerald: { primary: "16 185 129", secondary: "5 150 105" }, // emerald-500 / emerald-600
  amber: { primary: "245 158 11", secondary: "217 119 6" }, // amber-500 / amber-600
};

const hexToRgb = (hex?: string): string | null => {
  if (!hex) return null;
  const cleaned = hex.replace("#", "").trim();
  if (!/^[0-9a-fA-F]{6}$/.test(cleaned)) return null;
  const r = parseInt(cleaned.slice(0, 2), 16);
  const g = parseInt(cleaned.slice(2, 4), 16);
  const b = parseInt(cleaned.slice(4, 6), 16);
  return `${r} ${g} ${b}`;
};

const darkenRgb = (rgb: string, ratio = 0.15) => {
  const [r, g, b] = rgb.split(" ").map((v) => Number(v));
  const clamp = (v: number) => Math.max(0, Math.min(255, v));
  return `${clamp(Math.round(r * (1 - ratio)))} ${clamp(
    Math.round(g * (1 - ratio))
  )} ${clamp(Math.round(b * (1 - ratio)))}`;
};

interface ThemeContextType {
  theme: Theme;
  toggleTheme: () => void;
}

const ThemeContext = createContext<ThemeContextType | undefined>(undefined);

export const ThemeProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [theme, setTheme] = useState<Theme>(() => {
    const saved = localStorage.getItem('theme');
    return (saved === 'light' || saved === 'dark') ? saved : 'light';
  });

  const { data: storeSettings } = useStoreSettings();

  useEffect(() => {
    localStorage.setItem('theme', theme);
    const metaThemeColor = document.querySelector('meta[name="theme-color"]');

    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
      if (metaThemeColor) metaThemeColor.setAttribute('content', '#0f172a'); // slate-900
    } else {
      document.documentElement.classList.remove('dark');
      if (metaThemeColor) metaThemeColor.setAttribute('content', '#ffffff'); // white
    }
  }, [theme]);

  useEffect(() => {
    const preset = (storeSettings?.theme_preset as BrandPreset) || "blue";
    const customRgb = hexToRgb(storeSettings?.primary_color);

    let primary = BRAND_PRESETS.blue.primary;
    let secondary = BRAND_PRESETS.blue.secondary;

    if (preset === "custom" && customRgb) {
      primary = customRgb;
      secondary = darkenRgb(customRgb, 0.18);
    } else if (preset in BRAND_PRESETS) {
      const mapped = BRAND_PRESETS[preset as Exclude<BrandPreset, "custom">];
      primary = mapped.primary;
      secondary = mapped.secondary;
    }

    const root = document.documentElement;
    root.style.setProperty("--brand-primary", primary);
    root.style.setProperty("--brand-secondary", secondary);
  }, [storeSettings?.theme_preset, storeSettings?.primary_color]);

  const toggleTheme = () => {
    setTheme(prev => prev === 'light' ? 'dark' : 'light');
  };

  return (
    <ThemeContext.Provider value={{ theme, toggleTheme }}>
      {children}
    </ThemeContext.Provider>
  );
};

export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (!context) {
    throw new Error('useTheme must be used within ThemeProvider');
  }
  return context;
};

