    case "inventory":
      return "≡ƒôª";
    case "inventory_warning":
      return "ΓÜá∩╕Å";
    case "debt":
      return "≡ƒÆ░";
    case "cash":
      return "≡ƒÆ╡";
    default:
      return "≡ƒöö";
  }
}

