// Normalize Vietnamese diacritics to ASCII for client-side fuzzy matching
export const normalizeViStr = (s: string): string =>
  s
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/\u0111/g, "d")
    .replace(/\u0110/g, "D")
    .toLowerCase()
    .trim();

export async function fetchPartsPaged(params?: {
  page?: number; // 1-based
  pageSize?: number;
  search?: string; // match name or sku
  category?: string; // exact match
}): Promise<RepoResult<Part[]>> {
  try {
    const pageSize =
      params?.pageSize && params.pageSize > 0 ? params.pageSize : 50;
    const page = params?.page && params.page > 0 ? params.page : 1;
    const from = (page - 1) * pageSize;
    const to = from + pageSize - 1;
    let query = supabase
      .from(PARTS_TABLE)
      .select("*", { count: "exact" })
      .order("name")
      .range(from, to);
    if (params?.category && params.category !== "all") {
      query = query.eq("category", params.category);
    }
    if (params?.search && params.search.trim()) {
      const raw = params.search.trim().replace(/['"]/g, "");

      // ─Éiß╗üu kiß╗çn 1: khß╗¢p to├án cß╗Ñm tß╗½ (ch├¡nh x├íc nhß║Ñt)
      const orParts: string[] = [
        `name.ilike.%${raw}%`,
        `sku.ilike.%${raw}%`,
        `category.ilike.%${raw}%`,
        `description.ilike.%${raw}%`,
      ];

      // ─Éiß╗üu kiß╗çn 2: khß╗¢p tß╗½ng tß╗½ ri├¬ng lß║╗ (ΓëÑ 3 k├╜ tß╗▒) ─æß╗â bß║»t ─æ╞░ß╗úc
      // tr╞░ß╗¥ng hß╗úp tß╗½ xuß║Ñt hiß╗çn kh├┤ng liß╗ün nhau hoß║╖c sai dß║Ñu tiß║┐ng Viß╗çt.
      // VD: "ß╗ò kh├│a" ΓåÆ th├¬m name.ilike.%ß╗ò% v├á name.ilike.%kh├│a%
      // Client-side normalize filter sß║╜ lß╗ìc ch├¡nh x├íc sau.
      raw.split(/\s+/).forEach((word) => {
        if (word.length >= 3) {
          const cond = `name.ilike.%${word}%`;
          if (!orParts.includes(cond)) orParts.push(cond);
        }

        // ─Éiß╗üu kiß╗çn 3 (diacritic fallback): vß╗¢i tß╗½ ΓëÑ 4 k├╜ tß╗▒,
        // normalize vß╗ü ASCII rß╗ôi lß║Ñy 2 k├╜ tß╗▒ ─æß║ºu l├ám prefix cluster.
        // Mß╗Ñc ─æ├¡ch: "kh├│a" ΓåÆ ASCII "khoa" ΓåÆ prefix "kh" ΓåÆ name.ilike.%kh%
        // ─Éiß╗üu n├áy bß║»t ─æ╞░ß╗úc Cß║ó HAI "kho├í" lß║½n "kh├│a" trong DB (─æß╗üu chß╗⌐a "kh").
        // Client-side normalize filter sß║╜ loß║íi bß╗Å false positives.
        if (word.length >= 4) {
          const ascii = normalizeViStr(word);
          const prefix = ascii.slice(0, 2);
          if (prefix.length === 2 && /^[a-z]{2}$/.test(prefix)) {
            const prefixCond = `name.ilike.%${prefix}%`;
            if (!orParts.includes(prefixCond)) orParts.push(prefixCond);
          }
        }
      });

      query = query.or(orParts.join(","));
    }
    const { data, error, count } = await query;
    if (error)
      return failure({
        code: "supabase",
        message: "Kh├┤ng thß╗â tß║úi danh s├ích phß╗Ñ t├╣ng (ph├ón trang)",
        cause: error,
      });
    return success((data || []) as Part[], { total: count, page, pageSize });
  } catch (e: any) {
    return failure({
      code: "network",
      message: "Lß╗ùi kß║┐t nß╗æi tß╗¢i m├íy chß╗º khi tß║úi phß╗Ñ t├╣ng (ph├ón trang)",
      cause: e,
    });
  }
}

