// Atomic balance update (fetch current -> merge -> update). Expect balance JSON shape.
export async function updatePaymentSourceBalance(
  id: string,
  branchId: string,
  delta: number
): Promise<RepoResult<PaymentSource>> {
  try {
    // Fetch current row
    const { data: current, error: fetchErr } = await supabase
      .from(TABLE)
      .select("*")
      .eq("id", id)
      .single();
    if (fetchErr || !current)
      return failure({
        code: "supabase",
        message: "Kh├┤ng t├¼m thß║Ñy nguß╗ôn tiß╗ün",
        cause: fetchErr,
      });

    const balance = current.balance || {};
    const newBalance = {
      ...balance,
      [branchId]: (balance[branchId] || 0) + delta,
    };

    const { data, error } = await supabase
      .from(TABLE)
      .update({ balance: newBalance })
      .eq("id", id)
      .select()
      .single();
    if (error || !data)
      return failure({
        code: "supabase",
        message: "Cß║¡p nhß║¡t sß╗æ d╞░ thß║Ñt bß║íi",
        cause: error,
      });
    // Audit balance adjustment
    let userId: string | null = null;
    try {
      const { data: userData } = await supabase.auth.getUser();
      userId = userData?.user?.id || null;
    } catch {}
    await safeAudit(userId, {
      action: "payment_source.balance_adjust",
      tableName: TABLE,
      recordId: id,
      oldData: { balance },
      newData: { balance: newBalance, delta, branchId },
    });
    return success(data as PaymentSource);
  } catch (e: any) {
    return failure({
      code: "network",
      message: "Lß╗ùi kß║┐t nß╗æi khi cß║¡p nhß║¡t sß╗æ d╞░",
      cause: e,
    });
  }
}

