// Refund an entire sale (customer returned everything or full cancellation after payment)
export async function refundSale(
  id: string,
  reason?: string
): Promise<RepoResult<{ id: string; refunded: boolean }>> {
  try {
    // Fetch existing sale
    const { data: saleRow, error: fetchErr } = await supabase
      .from(SALES_TABLE)
      .select("*")
      .eq("id", id)
      .single();
    if (fetchErr || !saleRow) {
      return failure({
        code: "not_found",
        message: "Kh├┤ng t├¼m thß║Ñy h├│a ─æ╞ín ─æß╗â ho├án tiß╗ün",
        cause: fetchErr,
      });
    }
    // Mark as refunded using explicit columns (refunded, refundReason)
    const patch: any = { refunded: true, refundReason: reason || null };
    const { error: updErr } = await supabase
      .from(SALES_TABLE)
      .update(patch)
      .eq("id", id);
    if (updErr) {
      return failure({
        code: "supabase",
        message: "Kh├┤ng thß╗â cß║¡p nhß║¡t trß║íng th├íi ho├án tiß╗ün",
        cause: updErr,
      });
    }
    // Record cash refund (expense/negative income) to adjust payment source balance
    try {
      const refundAmount = 0 - Number((saleRow as any).total || 0);
      const branchId = (saleRow as Sale).branchId || "CN1";
      const paymentMethod = (saleRow as any).paymentMethod || null;
      await supabase.from("cash_transactions").insert([
        {
          category: "sale_refund",
          amount: refundAmount,
          date: new Date().toISOString(),
          description: `Ho├án tiß╗ün h├│a ─æ╞ín ${id}`,
          branchId,
          paymentSource: paymentMethod,
          reference: id,
        },
      ] as any);
    } catch { }
    // Restock all items (nhß║¡p trß║ú) - best effort
    try {
      const branchId = (saleRow as Sale).branchId || "CN1";
      const items: CartItem[] = (saleRow as Sale).items || [];
      for (const it of items) {
        // Skip quick_service items (dß╗ïch vß╗Ñ nhanh kh├┤ng c├│ stock)
        if (it.partId?.startsWith("quick_service_")) continue;
        // Lookup partId via SKU if needed
        let partId = it.partId;
        if (!partId) {
          const lookup = await fetchPartBySku(it.sku);
          if (lookup.ok && lookup.data) {
            partId = (lookup.data as any).id;
          }
        }
        if (partId) {
          // Cß║¡p nhß║¡t stock trß╗▒c tiß║┐p (trigger ─æ├ú bß╗ï x├│a, kh├┤ng tß╗▒ update)
          const { data: partData } = await supabase
            .from("parts")
            .select("stock")
            .eq("id", partId)
            .single();
          if (partData) {
            const currentStock = (partData.stock as any)?.[branchId] || 0;
            await supabase
              .from("parts")
              .update({
                stock: { ...partData.stock, [branchId]: currentStock + it.quantity },
              })
              .eq("id", partId);
          }
          // Ghi lß╗ïch sß╗¡ inventory transaction
          await createInventoryTransaction({
            type: "Nhß║¡p kho",
            partId,
            partName: it.partName,
            quantity: it.quantity, // nhß║¡p trß║ú sß╗æ l╞░ß╗úng gß╗æc
            branchId,
            notes: `Ho├án tiß╗ün h├│a ─æ╞ín ${id}`,
          });
        }
      }
    } catch { }
    // Audit
    let userId: string | null = null;
    try {
      const { data: userData } = await supabase.auth.getUser();
      userId = userData?.user?.id || null;
    } catch { }
    await safeAudit(userId, {
      action: "sale.refund",
      tableName: SALES_TABLE,
      recordId: id,
      oldData: saleRow,
      newData: { refunded: true, refundReason: reason || null },
    });
    return success({ id, refunded: true });
  } catch (e: any) {
    return failure({
      code: "network",
      message: "Lß╗ùi kß║┐t nß╗æi khi ho├án tiß╗ün h├│a ─æ╞ín",
      cause: e,
    });
  }
}

// Return a single item from sale (partial return)
export async function returnSaleItem(params: {
  saleId: string;
  itemSku: string; // identify item in sale
  quantity: number; // quantity being returned (<= original)
  reason?: string;
}): Promise<RepoResult<{ saleId: string; itemSku: string; returned: number }>> {
  try {
    if (params.quantity <= 0) {
      return failure({ code: "validation", message: "Sß╗æ l╞░ß╗úng trß║ú phß║úi > 0" });
    }
    // Fetch sale
    const { data: saleRow, error: fetchErr } = await supabase
      .from(SALES_TABLE)
      .select("*")
      .eq("id", params.saleId)
      .single();
    if (fetchErr || !saleRow) {
      return failure({
        code: "not_found",
        message: "Kh├┤ng t├¼m thß║Ñy h├│a ─æ╞ín ─æß╗â trß║ú h├áng",
        cause: fetchErr,
      });
    }
    const items: any[] = saleRow.items || [];
    const targetIndex = items.findIndex((it) => it.sku === params.itemSku);
    if (targetIndex === -1) {
      return failure({
        code: "not_found",
        message: "Kh├┤ng t├¼m thß║Ñy sß║ún phß║⌐m trong h├│a ─æ╞ín",
      });
    }
    const target = items[targetIndex];
    if (params.quantity > target.quantity) {
      return failure({
        code: "validation",
        message: "Sß╗æ l╞░ß╗úng trß║ú v╞░ß╗út qu├í sß╗æ l╞░ß╗úng ─æ├ú mua",
      });
    }
    // Adjust item quantity
    const newQty = target.quantity - params.quantity;
    if (newQty === 0) {
      items.splice(targetIndex, 1); // remove item completely
    } else {
      items[targetIndex] = { ...target, quantity: newQty };
    }
    // Recalculate totals
    const newSubtotal = items.reduce(
      (s, it) => s + it.sellingPrice * it.quantity,
      0
    );
    // Keep discount ratio; adjust total accordingly
    const discount = saleRow.discount || 0;
    const newTotal = Math.max(0, newSubtotal - discount);
    const patch = {
      items,
      subtotal: newSubtotal,
      total: newTotal,
      updated_at: new Date().toISOString(),
    } as any;
    const { error: updErr } = await supabase
      .from(SALES_TABLE)
      .update(patch)
      .eq("id", params.saleId);
    if (updErr) {
      return failure({
        code: "supabase",
        message: "Cß║¡p nhß║¡t h├│a ─æ╞ín sau trß║ú h├áng thß║Ñt bß║íi",
        cause: updErr,
      });
    }
    // Restock returned quantity (nhß║¡p trß║ú)
    try {
      let partId = target.partId;
      if (!partId) {
        const lookup = await fetchPartBySku(target.sku);
        if (lookup.ok && lookup.data) partId = (lookup.data as any).id;
      }
      // Skip quick_service items
      if (partId && !partId.startsWith("quick_service_")) {
        const restockBranchId = (saleRow as Sale).branchId || "CN1";
        // Cß║¡p nhß║¡t stock trß╗▒c tiß║┐p (trigger ─æ├ú bß╗ï x├│a, kh├┤ng tß╗▒ update)
        const { data: partData } = await supabase
          .from("parts")
          .select("stock")
          .eq("id", partId)
          .single();
        if (partData) {
          const currentStock = (partData.stock as any)?.[restockBranchId] || 0;
          await supabase
            .from("parts")
            .update({
              stock: { ...partData.stock, [restockBranchId]: currentStock + params.quantity },
            })
            .eq("id", partId);
        }
        // Ghi lß╗ïch sß╗¡ inventory transaction
        await createInventoryTransaction({
          type: "Nhß║¡p kho",
          partId,
          partName: target.partName,
          quantity: params.quantity,
          branchId: restockBranchId,
          notes: `Trß║ú h├áng SKU ${params.itemSku} tß╗½ h├│a ─æ╞ín ${params.saleId}`,
        });
      }
    } catch { }
    // Audit
    let userId: string | null = null;
    try {
      const { data: userData } = await supabase.auth.getUser();
      userId = userData?.user?.id || null;
    } catch { }
    await safeAudit(userId, {
      action: "sale.return_item",
      tableName: SALES_TABLE,
      recordId: params.saleId,
      oldData: saleRow,
      newData: {
        itemSku: params.itemSku,
        returned: params.quantity,
        remainingItems: items,
        subtotal: newSubtotal,
        total: newTotal,
        reason: params.reason || null,
      },
    });
    return success({
      saleId: params.saleId,
      itemSku: params.itemSku,
      returned: params.quantity,
    });
  } catch (e: any) {
    return failure({
      code: "network",
      message: "Lß╗ùi kß║┐t nß╗æi khi trß║ú h├áng cho h├│a ─æ╞ín",
      cause: e,
    });
  }
}

