        code: "supabase",
        message: "Kh├┤ng t├¼m thß║Ñy ─æ╞ín h├áng",
        cause: fetchError,
      });
    }

    // Update delivery status to delivered
    const { error: updateError } = await supabase
      .from(SALES_TABLE)
      .update({
