// ─Éß╗ông bß╗Ö giao dß╗ïch giß╗»a Motocare v├á Pin Factory
// Sß╗¡ dß╗Ñng ─æß╗â ─æß║⌐y giao dß╗ïch tß╗½ mß╗Öt hß╗ç thß╗æng sang hß╗ç thß╗æng kia

import { supabase } from "../supabaseClient";
import { pinSupabase, PinCashTransaction } from "./pinSupabase";
import type { CashTransaction } from "../types";
import { canonicalizeMotocareCashTxCategory } from "./finance/cashTxCategories";

// ========================================
// ─Éß╗ÆNG Bß╗ÿ Tß╗¬ MOTOCARE ΓåÆ PIN FACTORY
// ========================================

export async function syncMotocareToPin(
  transaction: CashTransaction
): Promise<{ success: boolean; error?: any }> {
  try {
    // Chuyß╗ân ─æß╗òi format tß╗½ Motocare sang Pin Factory
    // ΓÜá∩╕Å Chß╗ë d├╣ng c├íc cß╗Öt c╞í bß║ún: id, type, amount, date
    const pinTx: any = {
      id: `MOTO-${transaction.id}`, // Prefix ─æß╗â tr├ính tr├╣ng ID
      type: transaction.type === "income" ? "income" : "expense",
      amount: Math.abs(transaction.amount),
      date: transaction.date,
    };

    // Insert v├áo Pin Factory database
    const { data, error } = await pinSupabase
      .from("cashtransactions")
      .upsert(pinTx, { onConflict: "id" }); // Upsert ─æß╗â tr├ính duplicate

    if (error) {
      console.error("[Sync MotocareΓåÆPin] Error:", error);
      return { success: false, error };
    }

    console.log("[Sync MotocareΓåÆPin] Γ£à Synced:", pinTx.id);
    return { success: true };
  } catch (err) {
    console.error("[Sync MotocareΓåÆPin] Exception:", err);
    return { success: false, error: err };
  }
}

// ========================================
// ─Éß╗ÆNG Bß╗ÿ Tß╗¬ PIN FACTORY ΓåÆ MOTOCARE
// ========================================

export async function syncPinToMotocare(
  transaction: PinCashTransaction,
  branchId: string = "CN1"
): Promise<{ success: boolean; error?: any }> {
  try {
    const rawCategory = transaction.category || "other_income";
    const canonicalCategory =
      canonicalizeMotocareCashTxCategory(rawCategory) || rawCategory;

    // Chuyß╗ân ─æß╗òi format tß╗½ Pin Factory sang Motocare
    const motocareTx = {
      id: `PIN-${transaction.id}`, // Prefix ─æß╗â tr├ính tr├╣ng ID
      type: transaction.type,
      category: canonicalCategory,
      amount: Math.abs(transaction.amount),
      date: transaction.date,
      description: transaction.description || "─Éß╗ông bß╗Ö tß╗½ Pin Factory",
      branchid: branchId,
      paymentsource: "cash", // Default cash v├¼ Pin kh├┤ng c├│ payment_method
      notes: `[─Éß╗ông bß╗Ö tß╗½ Pin Factory]`,
    };

    // Insert v├áo Motocare database
    const { data, error } = await supabase
      .from("cash_transactions")
      .upsert(motocareTx, { onConflict: "id" }); // Upsert ─æß╗â tr├ính duplicate

    if (error) {
      console.error("[Sync PinΓåÆMotocare] Error:", error);
      return { success: false, error };
    }

    console.log("[Sync PinΓåÆMotocare] Γ£à Synced:", motocareTx.id);
    return { success: true };
  } catch (err) {
    console.error("[Sync PinΓåÆMotocare] Exception:", err);
    return { success: false, error: err };
  }
}

// ========================================
// ─Éß╗ÆNG Bß╗ÿ H├ÇNG LOß║áT
// ========================================

export async function syncAllMotocareToPin(
  transactions: CashTransaction[]
): Promise<{ success: number; failed: number; errors: any[] }> {
  let success = 0;
  let failed = 0;
  const errors: any[] = [];

  for (const tx of transactions) {
    const result = await syncMotocareToPin(tx);
    if (result.success) {
      success++;
    } else {
      failed++;
      errors.push({ id: tx.id, error: result.error });
    }
  }

  return { success, failed, errors };
}

export async function syncAllPinToMotocare(
  transactions: PinCashTransaction[],
  branchId: string = "CN1"
): Promise<{ success: number; failed: number; errors: any[] }> {
  let success = 0;
  let failed = 0;
  const errors: any[] = [];

  for (const tx of transactions) {
    const result = await syncPinToMotocare(tx, branchId);
    if (result.success) {
      success++;
    } else {
      failed++;
      errors.push({ id: tx.id, error: result.error });
    }
  }

  return { success, failed, errors };
}

// ========================================
// ─Éß╗ÆNG Bß╗ÿ 2 CHIß╗ÇU (TH├öNG MINH)
// ========================================

export async function syncBidirectional(
  branchId: string = "CN1"
): Promise<{
  motoToPin: { success: number; failed: number };
  pinToMoto: { success: number; failed: number };
}> {
  console.log("[Sync Bidirectional] Bß║»t ─æß║ºu ─æß╗ông bß╗Ö 2 chiß╗üu...");

  // 1. Lß║Ñy tß║Ñt cß║ú giao dß╗ïch tß╗½ cß║ú 2 hß╗ç thß╗æng
  const [motocareRes, pinRes] = await Promise.all([
    supabase.from("cash_transactions").select("*").eq("branchid", branchId),
    pinSupabase.from("cashtransactions").select("*"),
  ]);

  const motocareTxs = motocareRes.data || [];
  const pinTxs = pinRes.data || [];

  // 2. T├¼m c├íc giao dß╗ïch ch╞░a ─æ╞░ß╗úc ─æß╗ông bß╗Ö
  const existingPinIds = new Set(pinTxs.map((tx) => tx.id));
  const existingMotoIds = new Set(motocareTxs.map((tx: any) => tx.id));

  // Giao dß╗ïch Motocare ch╞░a c├│ ß╗ƒ Pin (kh├┤ng bß║»t ─æß║ºu bß║▒ng "PIN-")
  const motoToSync = motocareTxs.filter(
    (tx: any) => 
      !tx.id.startsWith("PIN-") && 
      !existingPinIds.has(`MOTO-${tx.id}`)
  );

  // Giao dß╗ïch Pin ch╞░a c├│ ß╗ƒ Motocare (kh├┤ng bß║»t ─æß║ºu bß║▒ng "MOTO-")
  const pinToSync = pinTxs.filter(
    (tx) => 
      !tx.id.startsWith("MOTO-") && 
      !existingMotoIds.has(`PIN-${tx.id}`)
  );

  console.log(`[Sync] Cß║ºn ─æß╗ông bß╗Ö: ${motoToSync.length} MotocareΓåÆPin, ${pinToSync.length} PinΓåÆMotocare`);

  // 3. Thß╗▒c hiß╗çn ─æß╗ông bß╗Ö
  const [motoResult, pinResult] = await Promise.all([
    syncAllMotocareToPin(motoToSync as CashTransaction[]),
    syncAllPinToMotocare(pinToSync, branchId),
  ]);

  console.log(`[Sync] Kß║┐t quß║ú:`, {
    motoToPin: `${motoResult.success}/${motoToSync.length}`,
    pinToMoto: `${pinResult.success}/${pinToSync.length}`,
  });

  return {
    motoToPin: { success: motoResult.success, failed: motoResult.failed },
    pinToMoto: { success: pinResult.success, failed: pinResult.failed },
  };
}

import React, { useState } from 'react';
import { DeliveryOrdersView } from '../components/sales/DeliveryOrdersView';
import { useAppContext } from '../contexts/AppContext';
import { useSalesRepo } from '../hooks/useSalesRepository';
import { updateDeliveryStatus, completeDelivery, cancelDeliveredOrder } from '../lib/repository/salesRepository';
import { showToast } from '../utils/toast';
import { useQueryClient } from '@tanstack/react-query';
import { useEmployeesRepo } from '../hooks/useEmployeesRepository';

export const DeliveryTest = () => {
    const { currentBranchId } = useAppContext();
    const { data: sales = [], isLoading, refetch } = useSalesRepo();
    const { data: employees = [] } = useEmployeesRepo();
    const queryClient = useQueryClient();

    const handleUpdateStatus = async (saleId: string, status: string, shipperId?: string) => {
        const result = await updateDeliveryStatus(saleId, status as any, shipperId);
        if (result.ok) {
            showToast.success('Cß║¡p nhß║¡t trß║íng th├íi th├ánh c├┤ng!');
            await refetch();
            await queryClient.invalidateQueries({ queryKey: ['sales'] });
        } else {
            showToast.error(result.error.message);
        }
    };

    const handleComplete = async (saleId: string) => {
        const result = await completeDelivery(saleId, currentBranchId);
        if (result.ok) {
            showToast.success('─É├ú giao h├áng th├ánh c├┤ng!');
            await refetch();
            await queryClient.invalidateQueries({ queryKey: ['sales'] });
            await queryClient.invalidateQueries({ queryKey: ['cashTransactions'] });
        } else {
            showToast.error(result.error.message);
        }
    };

    const handleRefund = async (saleId: string) => {
        const reason = prompt('Nhß║¡p l├╜ do ho├án trß║ú:');
        if (reason === null) return; // Cancelled

        const confirmMsg = `X├íc nhß║¡n ho├án trß║ú ─æ╞ín h├áng n├áy?\n\nL├╜ do: ${reason || 'Kh├┤ng c├│'}`;
        if (!confirm(confirmMsg)) return;

        const result = await cancelDeliveredOrder(saleId, currentBranchId, reason);
        if (result.ok) {
            showToast.success('Ho├án trß║ú th├ánh c├┤ng! ─É├ú tß║ío phiß║┐u chi.');
            await refetch();
            await queryClient.invalidateQueries({ queryKey: ['sales'] });
            await queryClient.invalidateQueries({ queryKey: ['cashTransactions'] });
        } else {
            showToast.error(result.error.message);
        }
    };

    return (
        <div className="h-screen bg-slate-50 dark:bg-slate-900">
            <DeliveryOrdersView
                sales={sales}
                employees={employees}
                onUpdateStatus={handleUpdateStatus}
                onCompleteDelivery={handleComplete}
                onRefund={handleRefund}
                isLoading={isLoading}
            />
        </div>
    );
};

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '../../supabaseClient';
import { Plus, Edit2, Trash2, Save, X, Image as ImageIcon, AlertCircle } from 'lucide-react';

interface Promotion {
  id: string;
  title: string;
  description: string;
  discount_percent?: number;
  discount_amount?: number;
  start_date: string;
  end_date: string;
  image_url?: string;
  detail_image_url?: string;
  products?: string[];
  min_purchase?: number;
  is_active: boolean;
  featured: boolean;
}

export default function PromotionManager() {
  const navigate = useNavigate();
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingPromotion, setEditingPromotion] = useState<Promotion | null>(null);
  const [imageFile, setImageFile] = useState<File | null>(null);
  const [imagePreview, setImagePreview] = useState<string>('');
  const [detailImageFile, setDetailImageFile] = useState<File | null>(null);
  const [detailImagePreview, setDetailImagePreview] = useState<string>('');
  const [uploadProgress, setUploadProgress] = useState(0);
  const queryClient = useQueryClient();

  // Fetch promotions
  const { data: promotions = [], isLoading } = useQuery({
    queryKey: ['promotions-admin'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('promotions')
        .select('*')
        .order('created_at', { ascending: false });

      if (error) throw error;
      return data as Promotion[];
    }
  });

  // Upload image to Supabase Storage
  const uploadImage = async (file: File): Promise<string> => {
    const fileExt = file.name.split('.').pop();
    const fileName = `${Date.now()}-${Math.random().toString(36).substring(7)}.${fileExt}`;
    const filePath = `promotions/${fileName}`;

    const { error: uploadError } = await supabase.storage
      .from('images')
      .upload(filePath, file, {
        cacheControl: '3600',
        upsert: false
      });

    if (uploadError) throw uploadError;

    const { data } = supabase.storage.from('images').getPublicUrl(filePath);
    return data.publicUrl;
  };

  // Create/Update mutation
  const saveMutation = useMutation({
    mutationFn: async (formData: Partial<Promotion>) => {
      console.log('≡ƒÆ╛ Saving promotion:', formData);

      let imageUrl = formData.image_url;
      let detailImageUrl = formData.detail_image_url;

      // Upload thumbnail image if new file selected
      if (imageFile) {
        console.log('≡ƒô╖ Uploading thumbnail image...');
        setUploadProgress(25);
        try {
          imageUrl = await uploadImage(imageFile);
          console.log('Γ£à Thumbnail uploaded:', imageUrl);
        } catch (uploadErr) {
          console.error('Γ¥î Thumbnail upload failed:', uploadErr);
          throw new Error('Kh├┤ng thß╗â tß║úi h├¼nh thumbnail l├¬n. Vui l├▓ng thß╗¡ lß║íi.');
        }
      }

      // Upload detail image if new file selected
      if (detailImageFile) {
        console.log('≡ƒô╖ Uploading detail image...');
        setUploadProgress(50);
        try {
          detailImageUrl = await uploadImage(detailImageFile);
          console.log('Γ£à Detail image uploaded:', detailImageUrl);
        } catch (uploadErr) {
          console.error('Γ¥î Detail image upload failed:', uploadErr);
          throw new Error('Kh├┤ng thß╗â tß║úi h├¼nh chi tiß║┐t l├¬n. Vui l├▓ng thß╗¡ lß║íi.');
        }
      }

      setUploadProgress(75);

      const promotionData = {
        ...formData,
        image_url: imageUrl,
        detail_image_url: detailImageUrl
      };

      console.log('≡ƒôñ Sending to database:', promotionData);

      if (editingPromotion) {
        // Update
        console.log('≡ƒöä Updating promotion ID:', editingPromotion.id);
        const { data, error } = await supabase
          .from('promotions')
          .update(promotionData)
          .eq('id', editingPromotion.id)
          .select();

        if (error) {
          console.error('Γ¥î Update error:', error);
          throw new Error(`Lß╗ùi cß║¡p nhß║¡t: ${error.message}`);
        }
        console.log('Γ£à Update success:', data);
        return data;
      } else {
        // Insert
        console.log('Γ₧ò Creating new promotion');
        const { data, error } = await supabase
          .from('promotions')
          .insert([promotionData])
          .select();

        if (error) {
          console.error('Γ¥î Insert error:', error);
          throw new Error(`Lß╗ùi th├¬m mß╗¢i: ${error.message}`);
        }
        console.log('Γ£à Insert success:', data);
        return data;
      }
    },
    onSuccess: (data) => {
      console.log('≡ƒÄë Mutation success, refreshing data...');
      queryClient.invalidateQueries({ queryKey: ['promotions-admin'] });
      queryClient.invalidateQueries({ queryKey: ['promotions'] });
      resetForm();
      alert('Γ£à L╞░u th├ánh c├┤ng!');
    },
    onError: (error: Error) => {
      console.error('Γ¥î Mutation error:', error);
      alert(`Γ¥î Lß╗ùi: ${error.message}`);
    }
  });

  // Delete mutation
  const deleteMutation = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase
        .from('promotions')
        .delete()
        .eq('id', id);

      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['promotions-admin'] });
      queryClient.invalidateQueries({ queryKey: ['promotions'] });
    }
  });

  const handleImageSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setImageFile(file);
      const reader = new FileReader();
      reader.onloadend = () => {
        setImagePreview(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleDetailImageSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setDetailImageFile(file);
      const reader = new FileReader();
      reader.onloadend = () => {
        setDetailImagePreview(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);

    const promotion: Partial<Promotion> = {
      title: formData.get('title') as string,
      description: formData.get('description') as string,
      discount_percent: formData.get('discount_percent') ? Number(formData.get('discount_percent')) : undefined,
      discount_amount: formData.get('discount_amount') ? Number(formData.get('discount_amount')) : undefined,
      start_date: formData.get('start_date') as string,
      end_date: formData.get('end_date') as string,
      min_purchase: formData.get('min_purchase') ? Number(formData.get('min_purchase')) : undefined,
      is_active: formData.get('is_active') === 'on',
      featured: formData.get('featured') === 'on',
      image_url: editingPromotion?.image_url,
      detail_image_url: editingPromotion?.detail_image_url
    };

    saveMutation.mutate(promotion);
  };

