import React, { useState, useMemo, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { supabase } from "../../supabaseClient";
import {
  Search,
  Filter,
  ShoppingCart,
  Package,
  Tag,
  Grid,
  List,
  X,
  Phone,
  Mail,
  MessageCircle,
} from "lucide-react";
import { formatCurrency } from "../../utils/format";
import { getCategoryColor } from "../../utils/categoryColors";
import type { Part } from "../../types";

function getFirstKey(value: unknown): string | null {
  if (!value || typeof value !== "object") return null;
  const keys = Object.keys(value as Record<string, unknown>);
  return keys.length > 0 ? keys[0] : null;
}

function getBranchKey(part: Part): string {
  return (
    (part as any).actualBranchId ||
    getFirstKey((part as any).retailPrice) ||
    getFirstKey((part as any).stock) ||
    "CN1"
  );
}

function getRetailPrice(part: Part): number {
  const retailPrice = (part as any).retailPrice;
  if (retailPrice && typeof retailPrice === "object") {
    const key = getBranchKey(part);
    const fallbackKey = getFirstKey(retailPrice);
    return Number(retailPrice[key] ?? (fallbackKey ? retailPrice[fallbackKey] : 0) ?? 0) || 0;
  }
  return Number(retailPrice) || 0;
}

export default function ProductCatalog() {
  const navigate = useNavigate();
  const [parts, setParts] = useState<Part[]>([]);
  const [loading, setLoading] = useState(true);
  const [currentBranchId, setCurrentBranchId] = useState<string>("CN1"); // Default branch key (CN1, CN2, ...)
  const [searchQuery, setSearchQuery] = useState("");
  const [selectedCategory, setSelectedCategory] = useState<string>("all");
  const [viewMode, setViewMode] = useState<"grid" | "list">("grid");
  const [cart, setCart] = useState<Map<string, number>>(new Map());
  const [showCart, setShowCart] = useState(false);
  const [displayCount, setDisplayCount] = useState(12); // Show 12 products initially

  // Fetch products from Supabase (public access)
  useEffect(() => {
    const fetchProducts = async () => {
      try {
        console.log('≡ƒöì [Shop] Bß║»t ─æß║ºu fetch sß║ún phß║⌐m...');

        // Select only existing columns: id, name, sku, category, stock, retailPrice, wholesalePrice
        const { data, error } = await supabase
          .from('parts')
          .select('id, name, sku, category, stock, retailPrice, wholesalePrice')
          .order('name');

        console.log('≡ƒôª [Shop] Kß║┐t quß║ú fetch:', {
          totalProducts: data?.length || 0,
          error: error?.message,
          sampleProduct: data?.[0],
          sampleStock: data?.[0]?.stock,
          sampleStockType: typeof data?.[0]?.stock,
          stockKeys: data?.[0]?.stock ? Object.keys(data?.[0]?.stock) : []
        });

        if (error) {
          console.error('Γ¥î [Shop] Lß╗ùi fetch:', error);
          throw error;
        }

        console.log('Γ£à [Shop] Fetch th├ánh c├┤ng!', {
          products: data?.length,
          currentBranchId
        });

        setParts(data || []);
      } catch (error) {
        console.error('Γ¥î [Shop] Error fetching products:', error);
      } finally {
        setLoading(false);
      }
    };

    fetchProducts();
  }, []);

  // Reset display count when filters change
  useEffect(() => {
    setDisplayCount(12);
  }, [searchQuery, selectedCategory]);

  // Get unique categories
  const categories = useMemo(() => {
    const cats = new Set(parts.map((p) => p.category).filter(Boolean));
    return ["all", ...Array.from(cats)];
  }, [parts]);

  // Filter products
  const filteredProducts = useMemo(() => {
    console.log('≡ƒöì [Shop] Filtering products...', {
      totalParts: parts.length,
      currentBranchId,
      searchQuery,
      selectedCategory
    });

    let filtered = parts.filter((p) => {
      // Stock is JSONB: {CN1: quantity}
      // Get actual branch ID from stock keys (CN1, CN2, etc.)
      const stockKeys = p.stock && typeof p.stock === 'object' ? Object.keys(p.stock) : [];
      const actualBranchId = stockKeys[0] || 'CN1'; // Use first branch or default to CN1

      // Calculate TOTAL stock across ALL branches
      let totalStock = 0;
      if (p.stock && typeof p.stock === 'object') {
        totalStock = Object.values(p.stock).reduce((sum: number, qty: any) => {
          const numQty = Number(qty) || 0;
          return sum + numQty;
        }, 0);
      }

      const hasStock = totalStock > 0;

      if (!hasStock) return false;

      // Store actual branch ID in product for display
      (p as any).actualBranchId = actualBranchId;

      // Filter by search
      if (searchQuery) {
        const query = searchQuery.toLowerCase();
        const matchesName = p.name?.toLowerCase().includes(query);
        const matchesSku = p.sku?.toLowerCase().includes(query);
        if (!matchesName && !matchesSku) return false;
      }

      // Filter by category
      if (selectedCategory !== "all" && p.category !== selectedCategory) {
        return false;
      }

      return true;
    });

    console.log('Γ£à [Shop] Filter result:', {
      filteredCount: filtered.length,
      sampleProduct: filtered[0]
    });

    return filtered;
  }, [parts, searchQuery, selectedCategory, currentBranchId]);

  const addToCart = (partId: string) => {
    setCart((prev) => {
      const newCart = new Map(prev);
      const currentQty = newCart.get(partId) || 0;
      newCart.set(partId, currentQty + 1);
      return newCart;
    });
  };

  const removeFromCart = (partId: string) => {
    setCart((prev) => {
      const newCart = new Map(prev);
      const currentQty = newCart.get(partId) || 0;
      if (currentQty <= 1) {
        newCart.delete(partId);
      } else {
        newCart.set(partId, currentQty - 1);
      }
      return newCart;
    });
  };

  const cartItems = useMemo(() => {
    return Array.from(cart.entries()).map(([partId, quantity]) => {
      const part = parts.find((p) => p.id === partId);
      return part ? { part, quantity } : null;
    }).filter(Boolean) as { part: Part; quantity: number }[];
  }, [cart, parts]);

  const cartTotal = useMemo(() => {
    return cartItems.reduce((sum, item) => {
      return sum + getRetailPrice(item.part) * item.quantity;
    }, 0);
  }, [cartItems]);

  const cartTotalQuantity = useMemo(() => {
    return Array.from(cart.values()).reduce((sum, qty) => sum + (Number(qty) || 0), 0);
  }, [cart]);

  const handleOrder = () => {
    if (cartItems.length === 0) return;

    // Format order message
    const orderDetails = cartItems
      .map(
        (item) =>
          `ΓÇó ${item.part.name} (${item.part.sku}) x${item.quantity} = ${formatCurrency(
            getRetailPrice(item.part) * item.quantity
          )}`
      )
      .join("\n");

    const message = `≡ƒ¢Æ ─Éß║╢T H├ÇNG Mß╗ÜI\n\n${orderDetails}\n\n≡ƒÆ░ Tß╗öNG: ${formatCurrency(
      cartTotal
    )}\n\nVui l├▓ng li├¬n hß╗ç ─æß╗â x├íc nhß║¡n ─æ╞ín h├áng!`;

    // Open Zalo chat and copy the order text for quick paste
    try {
      navigator.clipboard?.writeText(message);
    } catch {
      // ignore clipboard errors (non-HTTPS or unsupported browser)
    }

    window.open(`https://zalo.me/0947747907`, "_blank");
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 to-blue-50 dark:from-[#0a0a0f] dark:to-[#1a1a2e]">
      {loading ? (
        <div className="flex items-center justify-center min-h-screen">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
        </div>
      ) : (
        <>
          {/* Hero Section */}
          <div className="relative overflow-hidden bg-slate-900 text-white py-10 md:py-14">
            {/* Background Pattern */}
            <div className="absolute inset-0 z-0 opacity-20">
              <div className="absolute -top-24 -right-24 w-96 h-96 bg-blue-500 rounded-full blur-3xl"></div>
              <div className="absolute -bottom-24 -left-24 w-96 h-96 bg-purple-500 rounded-full blur-3xl"></div>
              <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-full h-full bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-blue-900/50 to-transparent"></div>
            </div>

            <div className="container mx-auto px-4 relative z-10 text-center">
              <h1 className="text-3xl md:text-5xl font-bold mb-4 bg-clip-text text-transparent bg-gradient-to-r from-blue-400 to-purple-400">
                Phß╗Ñ T├╣ng Xe M├íy Ch├¡nh H├úng
              </h1>
              <p className="text-base md:text-lg text-slate-300 max-w-2xl mx-auto">
                T├¼m kiß║┐m v├á ─æß║╖t h├áng phß╗Ñ t├╣ng chß║Ñt l╞░ß╗úng cao nhanh ch├│ng, tiß╗çn lß╗úi vß╗¢i mß╗⌐c gi├í tß╗æt nhß║Ñt
              </p>
            </div>
          </div>

          <div className="container mx-auto px-4 py-8">
            {/* Search & Filter Bar */}
            <div className="sticky top-4 z-40 bg-white/80 dark:bg-[#1e1e2d]/80 backdrop-blur-xl border border-white/20 dark:border-slate-700/50 rounded-2xl shadow-xl p-4 md:p-6 mb-8 transition-all duration-300">
              <div className="flex flex-col md:flex-row gap-5 md:gap-6">
                {/* Search */}
                <div className="flex-1 relative">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
                  <input
                    type="text"
                    placeholder="T├¼m theo t├¬n hoß║╖c m├ú SKU..."
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    className="w-full pl-10 pr-4 py-3 bg-slate-50 dark:bg-[#151521] border-2 border-transparent focus:border-blue-500 rounded-xl text-slate-900 dark:text-white transition-colors"
                  />
                </div>

                {/* Category Filter */}
                <div className="flex items-center gap-3">
                  <Filter className="w-5 h-5 text-slate-400" />
                  <select
                    value={selectedCategory}
                    onChange={(e) => setSelectedCategory(e.target.value)}
                    className="px-4 py-3 bg-slate-50 dark:bg-[#151521] border-2 border-transparent focus:border-blue-500 rounded-xl text-slate-900 dark:text-white transition-colors"
                  >
                    <option value="all">Tß║Ñt cß║ú danh mß╗Ñc</option>
                    {categories
                      .filter((c) => c !== "all")
                      .map((cat) => (
                        <option key={cat} value={cat}>
                          {cat}
                        </option>
                      ))}
                  </select>
                </div>

                {/* View Mode Toggle */}
                <div className="flex items-center gap-3 bg-slate-50 dark:bg-[#151521] rounded-xl p-1">
                  <button
                    onClick={() => setViewMode("grid")}
                    className={`p-2 rounded-lg transition-colors ${viewMode === "grid"
                        ? "bg-blue-500 text-white"
                        : "text-slate-400 hover:text-slate-600 dark:hover:text-slate-300"
                      }`}
                  >
                    <Grid className="w-5 h-5" />
                  </button>
                  <button
                    onClick={() => setViewMode("list")}
                    className={`p-2 rounded-lg transition-colors ${viewMode === "list"
                        ? "bg-blue-500 text-white"
                        : "text-slate-400 hover:text-slate-600 dark:hover:text-slate-300"
                      }`}
                  >
                    <List className="w-5 h-5" />
                  </button>
                </div>

                {/* Cart Button */}
                <button
                  onClick={() => setShowCart(true)}
                  className="relative px-6 py-3 bg-emerald-600 hover:bg-emerald-700 text-white rounded-xl font-bold transition-colors flex items-center gap-2"
                >
                  <ShoppingCart className="w-5 h-5" />
                  <span>Giß╗Å h├áng</span>
                  {cartTotalQuantity > 0 && (
                    <span className="absolute -top-2 -right-2 w-6 h-6 bg-red-500 text-white text-xs font-bold rounded-full flex items-center justify-center">
                      {cartTotalQuantity}
                    </span>
                  )}
                </button>
              </div>

              {/* Results count */}
              <div className="mt-4 text-sm text-slate-500 dark:text-slate-400">
                Hiß╗ân thß╗ï <span className="font-bold text-blue-600 dark:text-blue-400">{Math.min(displayCount, filteredProducts.length)}</span> / {filteredProducts.length} sß║ún phß║⌐m
              </div>
            </div>

            {/* Products Grid/List */}
            {viewMode === "grid" ? (
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 animate-fade-in">
                {filteredProducts.slice(0, displayCount).map((product) => (
                  <ProductCard
                    key={product.id}
                    product={product}
                    onAddToCart={addToCart}
                    cartQuantity={cart.get(product.id) || 0}
                    currentBranchId={currentBranchId}
                  />
                ))}
              </div>
            ) : (
              <div className="space-y-4">
                {filteredProducts.slice(0, displayCount).map((product) => (
                  <ProductListItem
                    key={product.id}
                    product={product}
                    onAddToCart={addToCart}
                    cartQuantity={cart.get(product.id) || 0}
                    currentBranchId={currentBranchId}
                  />
                ))}
              </div>
            )}

            {/* Load More Button */}
            {displayCount < filteredProducts.length && (
              <div className="flex justify-center mt-8">
                <button
                  onClick={() => setDisplayCount(prev => prev + 12)}
                  className="px-8 py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-bold text-lg transition-colors shadow-lg hover:shadow-xl"
                >
                  Xem th├¬m ({filteredProducts.length - displayCount} sß║ún phß║⌐m)
                </button>
              </div>
            )}

            {filteredProducts.length === 0 && (
              <div className="text-center py-16">
                <Package className="w-16 h-16 text-slate-300 dark:text-slate-600 mx-auto mb-4" />
                <p className="text-slate-500 dark:text-slate-400 text-lg">
                  Kh├┤ng t├¼m thß║Ñy sß║ún phß║⌐m ph├╣ hß╗úp
                </p>
              </div>
            )}
          </div>

          {/* Cart Modal */}
          {showCart && (
            <div className="fixed inset-0 bg-black/50 z-50 flex items-end md:items-center justify-center">
              <div className="bg-white dark:bg-[#1e1e2d] w-full md:max-w-2xl md:rounded-2xl max-h-[90vh] overflow-hidden flex flex-col">
                {/* Header */}
                <div className="p-6 border-b border-slate-200 dark:border-slate-700 flex items-center justify-between">
                  <h2 className="text-2xl font-bold text-slate-900 dark:text-white flex items-center gap-2">
                    <ShoppingCart className="w-6 h-6" />
                    Giß╗Å h├áng cß╗ºa bß║ín
                  </h2>
                  <button
                    onClick={() => setShowCart(false)}
                    className="w-10 h-10 rounded-full bg-slate-100 dark:bg-slate-800 flex items-center justify-center hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors"
                  >
                    <X className="w-5 h-5" />
                  </button>
                </div>

                {/* Cart Items */}
                <div className="flex-1 overflow-y-auto p-6">
                  {cartItems.length === 0 ? (
                    <div className="text-center py-12">
