export const getDateRange = (filter: string): { startDate: Date; endDate: Date; label: string } => {
    const now = new Date();
    let startDate: Date;
    let endDate: Date = new Date(now.getFullYear(), now.getMonth(), now.getDate(), 23, 59, 59);
    let label = "";

    // Handle specific month filters (month1, month2, ... month12)
    if (filter.startsWith("month") && filter.length > 5) {
        const monthNum = parseInt(filter.slice(5), 10);
        if (monthNum >= 1 && monthNum <= 12) {
            startDate = new Date(now.getFullYear(), monthNum - 1, 1);
            endDate = new Date(now.getFullYear(), monthNum, 0, 23, 59, 59);
            label = `Th├íng ${monthNum}`;
        } else {
            startDate = new Date(now.getFullYear(), now.getMonth(), 1);
            label = "Th├íng n├áy";
        }
    }
    // Handle quarter filters (q1, q2, q3, q4)
    else if (filter.startsWith("q") && filter.length === 2) {
        const quarterNum = parseInt(filter.slice(1), 10);
        if (quarterNum >= 1 && quarterNum <= 4) {
            const startMonth = (quarterNum - 1) * 3;
            startDate = new Date(now.getFullYear(), startMonth, 1);
            endDate = new Date(now.getFullYear(), startMonth + 3, 0, 23, 59, 59);
            label = `Qu├╜ ${quarterNum}`;
        } else {
            startDate = new Date(now.getFullYear(), now.getMonth(), 1);
            label = "Th├íng n├áy";
        }
    }
    // Handle standard filters
    else {
        switch (filter) {
            case "today":
                startDate = new Date(now.getFullYear(), now.getMonth(), now.getDate());
                label = "H├┤m nay";
                break;
            case "7days":
                startDate = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
                label = "7 ng├áy qua";
                break;
            case "week":
                const dayOfWeek = now.getDay();
                const diff = dayOfWeek === 0 ? 6 : dayOfWeek - 1;
                startDate = new Date(now.getFullYear(), now.getMonth(), now.getDate() - diff);
                label = "Tuß║ºn n├áy";
                break;
            case "month":
                startDate = new Date(now.getFullYear(), now.getMonth(), 1);
                label = "Th├íng n├áy";
                break;
            case "year":
                startDate = new Date(now.getFullYear(), 0, 1);
                label = `N─âm ${now.getFullYear()}`;
                break;
            default:
                startDate = new Date(now.getFullYear(), now.getMonth(), 1);
                label = "Th├íng n├áy";
        }
    }

    return { startDate, endDate, label };
};

import * as XLSX from "xlsx";
import type { Part } from "../types";
import { generateSKU, isValidSKU } from "./sku";

/**
 * Export parts to Excel file
 */
export const exportPartsToExcel = (
  parts: Part[],
  currentBranchId: string,
  filename: string = "BaoCao_TonKho.xlsx"
) => {
  // Prepare data for export
  const data = parts.map((part, index) => ({
    STT: index + 1,
    "T├¬n sß║ún phß║⌐m": part.name,
    SKU: part.sku,
    "Danh mß╗Ñc": part.category || "",
    "Tß╗ôn kho": part.stock[currentBranchId] || 0,
    "Gi├í b├ín lß║╗": part.retailPrice[currentBranchId] || 0,
    "Gi├í b├ín sß╗ë": part.wholesalePrice?.[currentBranchId] || 0,
    "Gi├í trß╗ï tß╗ôn":
      (part.stock[currentBranchId] || 0) *
      (part.retailPrice[currentBranchId] || 0),
    "M├┤ tß║ú": part.description || "",
  }));

  // Create worksheet
  const ws = XLSX.utils.json_to_sheet(data);

  // Set column widths
  ws["!cols"] = [
    { wch: 5 }, // STT
    { wch: 30 }, // T├¬n sß║ún phß║⌐m
    { wch: 15 }, // SKU
    { wch: 20 }, // Danh mß╗Ñc
    { wch: 10 }, // Tß╗ôn kho
    { wch: 15 }, // Gi├í b├ín lß║╗
    { wch: 15 }, // Gi├í b├ín sß╗ë
    { wch: 15 }, // Gi├í trß╗ï tß╗ôn
    { wch: 40 }, // M├┤ tß║ú
  ];

  // Create workbook
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, "Tß╗ôn kho");

  // Save file
  XLSX.writeFile(wb, filename);
};

