  // 1. Summary Sheet
  const totalRevenue = sales.reduce((sum, s) => sum + s.total, 0);
  const totalCost = sales.reduce((sum, s) => {
    return (
      sum +
      s.items.reduce(
        (c, it) => c + ((it as any).costPrice || 0) * it.quantity,
        0
      )
    );
  }, 0);
  const profit = totalRevenue - totalCost;
  const margin = totalRevenue > 0 ? (profit / totalRevenue) * 100 : 0;

  const summaryData = [
    ["B├üO C├üO DOANH THU"],
    [`Tß╗½ ${formatDate(startDate)} ─æß║┐n ${formatDate(endDate)}`],
    [],
    ["Chß╗ë ti├¬u", "Gi├í trß╗ï"],
    ["Tß╗òng doanh thu", formatCurrency(totalRevenue)],
    ["Tß╗òng chi ph├¡", formatCurrency(totalCost)],
    ["Lß╗úi nhuß║¡n", formatCurrency(profit)],
    ["Bi├¬n lß╗úi nhuß║¡n", `${margin.toFixed(2)}%`],
  ];

  const wsSummary = XLSX.utils.aoa_to_sheet(summaryData);
  XLSX.utils.book_append_sheet(wb, wsSummary, "Tß╗òng quan");

  // 2. Detailed Sales Sheet
  const salesData: (string | number)[][] = [
    [
      "M├ú ─æ╞ín",
      "Ng├áy",
      "Kh├ích h├áng",
      "S─ÉT",
      "Sß║ún phß║⌐m",
      "Sß╗æ l╞░ß╗úng",
      "─É╞ín gi├í",
      "Th├ánh tiß╗ün",
      "Giß║úm gi├í",
      "Tß╗òng",
      "Ph╞░╞íng thß╗⌐c",
    ],
  ];

  sales.forEach((sale) => {
    sale.items.forEach((item, idx) => {
      salesData.push([
        idx === 0 ? formatAnyId(sale.id) : "",
