// ==================== TOP SELLING PRODUCTS REPORT ====================
export const exportTopProductsReport = (
  sales: Sale[],
  startDate: string,
  endDate: string,
  limit: number = 20
) => {
  const wb = XLSX.utils.book_new();

  // T├¡nh to├ín top sß║ún phß║⌐m
  const productStats = new Map<
    string,
    {
      name: string;
      sku: string;
      quantity: number;
      revenue: number;
      orders: number;
    }
  >();

  sales.forEach((sale) => {
    sale.items.forEach((item) => {
      const existing = productStats.get(item.partId);
      if (existing) {
        existing.quantity += item.quantity;
        existing.revenue += item.sellingPrice * item.quantity;
        existing.orders += 1;
      } else {
        productStats.set(item.partId, {
          name: item.partName,
          sku: item.sku || "",
          quantity: item.quantity,
          revenue: item.sellingPrice * item.quantity,
          orders: 1,
        });
      }
    });
  });

  // Sort by quantity (best sellers)
  const topProducts = Array.from(productStats.values())
    .sort((a, b) => b.quantity - a.quantity)
    .slice(0, limit);

  // Create Excel data
  const summaryData = [
    ["TOP Sß║óN PHß║¿M B├üN CHß║áY"],
    [`Tß╗½ ${formatDate(startDate)} ─æß║┐n ${formatDate(endDate)}`],
    [],
    [
      "STT",
      "T├¬n sß║ún phß║⌐m",
      "SKU",
      "Sß╗æ l╞░ß╗úng b├ín",
      "Doanh thu",
      "Sß╗æ ─æ╞ín",
      "Trung b├¼nh/─æ╞ín",
    ],
  ];

  topProducts.forEach((product, index) => {
    summaryData.push([
      String(index + 1),
