// ==================== Sß╗ö DOANH THU Mß║¬U S1a-HKD ====================
/**
 * Xuß║Ñt Sß╗ò chi tiß║┐t doanh thu b├ín h├áng h├│a, dß╗ïch vß╗Ñ - Mß║½u S1a-HKD
 * (Theo Th├┤ng t╞░ 152/2025/TT-BTC)
 * D├ánh cho hß╗Ö kinh doanh d╞░ß╗¢i 500 triß╗çu/n─âm - kh├┤ng thuß╗Öc diß╗çn chß╗ïu thuß║┐ GTGT
 */
export interface BusinessInfo {
  businessName: string;      // Hß╗ì, c├í nh├ón kinh doanh
  taxCode: string;           // M├ú sß╗æ thuß║┐
  address: string;           // ─Éß╗ïa chß╗ë
  businessLocation?: string; // ─Éß╗ïa ─æiß╗âm kinh doanh
}

export const exportS1aHKD = (
  sales: Sale[],
  workOrders: any[],
  businessInfo: BusinessInfo,
  startDate: Date,
  endDate: Date
) => {
  const wb = XLSX.utils.book_new();

  // Format period
  const startMonth = startDate.getMonth() + 1;
  const endMonth = endDate.getMonth() + 1;
  const year = startDate.getFullYear();
  const periodText = startMonth === endMonth 
    ? `Th├íng ${startMonth}/${year}` 
    : `Tß╗½ th├íng ${startMonth} ─æß║┐n th├íng ${endMonth}/${year}`;

  // Collect all transactions
  interface RevenueEntry {
    date: Date;
    description: string;
    amount: number;
    type: "ban-hang" | "ban-phu-tung" | "sua-chua"; // Ph├ón loß║íi ─æß╗â k├¬ khai thuß║┐
  }

  const entries: RevenueEntry[] = [];

  // From sales (b├ín h├áng - b├ín lß║╗ phß╗Ñ t├╣ng)
  // L╞░u ├╜: sales ─æ├ú ─æ╞░ß╗úc lß╗ìc tß╗½ financialSummary
  sales.forEach((sale) => {
    const saleDate = new Date(sale.date);
    const itemNames = sale.items.map(i => i.partName).join(", ");
    entries.push({
      date: saleDate,
      description: `B├ín phß╗Ñ t├╣ng - ${sale.customer?.name || "Kh├ích lß║╗"}: ${itemNames.slice(0, 80)}${itemNames.length > 80 ? '...' : ''}`,
      amount: sale.total,
      type: "ban-hang",
    });
  });

  // From work orders - T├üCH RI├èNG phß╗Ñ t├╣ng v├á tiß╗ün c├┤ng
  // L╞░u ├╜: workOrders ─æ├ú ─æ╞░ß╗úc lß╗ìc tß╗½ financialSummary (chß╗ë paid v├á trong date range)
  workOrders.forEach((wo: any) => {
    const woDate = new Date(wo.paymentDate || wo.paymentdate || wo.creationDate || wo.creationdate || wo.date);
    
    // T├¡nh tiß╗ün phß╗Ñ t├╣ng tß╗½ partsUsed (kh├┤ng c├│ field totalPrice trong WorkOrder!)
    const partsUsed = wo.partsUsed || wo.partsused || [];
    const partsTotal = partsUsed.reduce((sum: number, p: any) => {
      const price = parseFloat(p.price || p.sellingPrice || p.sellingprice || 0);
      const qty = parseFloat(p.quantity || 1);
      return sum + (price * qty);
    }, 0);
    
    // T├¡nh tiß╗ün dß╗ïch vß╗Ñ gia c├┤ng tß╗½ additionalServices
    const additionalServices = wo.additionalServices || wo.additionalservices || [];
    const servicesTotal = additionalServices.reduce((sum: number, s: any) => {
      const price = parseFloat(s.price || 0);
      const qty = parseFloat(s.quantity || 1);
      return sum + (price * qty);
    }, 0);
    
    const laborCost = parseFloat(wo.laborCost || wo.laborcost || 0);
    const discount = parseFloat(wo.discount || 0);
    
    // Tß╗òng tiß╗ün = phß╗Ñ t├╣ng + tiß╗ün c├┤ng + dß╗ïch vß╗Ñ gia c├┤ng - chiß║┐t khß║Ñu
    const theoreticalTotal = partsTotal + laborCost + servicesTotal - discount;
    
    // Sß╗¡ dß╗Ñng totalPaid (sß╗æ tiß╗ün thß╗▒c thu) 
    const totalPaid = parseFloat(wo.totalPaid || wo.totalpaid || wo.total || theoreticalTotal);
    
    // T├¡nh tß╗╖ lß╗ç ph├ón bß╗ò dß╗▒a tr├¬n totalPaid
    const ratio = theoreticalTotal > 0 ? totalPaid / theoreticalTotal : 1;
    
    // Ph├ón bß╗ò theo tß╗╖ lß╗ç
    const actualPartsRevenue = Math.round(partsTotal * ratio);
    const actualServicesRevenue = Math.round(servicesTotal * ratio);
    const actualLaborRevenue = totalPaid - actualPartsRevenue - actualServicesRevenue;
    
    const vehicleInfo = wo.vehicleInfo?.licensePlate || wo.vehicleinfo?.licenseplate || wo.licensePlate || wo.licenseplate || "";
    const customerName = wo.customerName || wo.customername || "Kh├ích h├áng";
    
    // 1. Tiß╗ün phß╗Ñ t├╣ng -> B├ín phß╗Ñ t├╣ng (thuß║┐ suß║Ñt thß║Ñp)
    if (actualPartsRevenue > 0) {
      const partNames = partsUsed.map((p: any) => p.partName || p.partname || "").filter(Boolean).join(", ");
      entries.push({
        date: woDate,
        description: `B├ín phß╗Ñ t├╣ng${vehicleInfo ? ` (${vehicleInfo})` : ""} - ${customerName}${partNames ? `: ${partNames.slice(0, 60)}${partNames.length > 60 ? '...' : ''}` : ''}`,
        amount: actualPartsRevenue,
        type: "ban-phu-tung",
      });
    }
    
    // 2. Tiß╗ün dß╗ïch vß╗Ñ gia c├┤ng (outsourcing) - c┼⌐ng l├á dß╗ïch vß╗Ñ
    if (actualServicesRevenue > 0) {
      entries.push({
        date: woDate,
        description: `Dß╗ïch vß╗Ñ gia c├┤ng${vehicleInfo ? ` (${vehicleInfo})` : ""} - ${customerName}`,
        amount: actualServicesRevenue,
        type: "sua-chua",
      });
    }
    
    // 3. Tiß╗ün c├┤ng -> Sß╗¡a chß╗»a/Dß╗ïch vß╗Ñ (thuß║┐ suß║Ñt cao h╞ín)
    if (actualLaborRevenue > 0) {
      entries.push({
        date: woDate,
        description: `Dß╗ïch vß╗Ñ sß╗¡a chß╗»a${vehicleInfo ? ` (${vehicleInfo})` : ""} - ${customerName}`,
        amount: actualLaborRevenue,
        type: "sua-chua",
      });
    }
  });

  // Sort by date
  entries.sort((a, b) => a.date.getTime() - b.date.getTime());

  // Calculate totals by type
  const totalGoods = entries
    .filter(e => e.type === "ban-hang" || e.type === "ban-phu-tung")
    .reduce((sum, e) => sum + e.amount, 0);
  const totalServices = entries
    .filter(e => e.type === "sua-chua")
    .reduce((sum, e) => sum + e.amount, 0);
  const totalRevenue = totalGoods + totalServices;

  // Build sheet data according to Mß║½u S1a-HKD format
  // T├üCH RI├èNG cß╗Öt B├ín h├áng h├│a v├á Dß╗ïch vß╗Ñ ─æß╗â k├¬ khai thuß║┐ ─æ├║ng
  const sheetData: (string | number)[][] = [
    // Header section
    [`Hß╗ÿ, C├ü NH├éN KINH DOANH: ${businessInfo.businessName}`, "", "", "", "Mß║½u sß╗æ S1a-HKD"],
    [`M├ú sß╗æ thuß║┐: ${businessInfo.taxCode}`, "", "", "", "(K├¿m theo Th├┤ng t╞░ sß╗æ"],
    [`─Éß╗ïa chß╗ë: ${businessInfo.address}`, "", "", "", "152/2025/TT-BTC ng├áy 31 th├íng 12"],
    ["", "", "", "", "n─âm 2025 cß╗ºa Bß╗Ö tr╞░ß╗ƒng Bß╗Ö T├ái ch├¡nh)"],
    [],
    ["Sß╗ö CHI TIß║╛T DOANH THU B├üN H├ÇNG H├ôA, Dß╗èCH Vß╗ñ", "", "", "", ""],
    [`─Éß╗ïa ─æiß╗âm kinh doanh: ${businessInfo.businessLocation || businessInfo.address}`, "", "", "", ""],
    [`Kß╗│ k├¬ khai: ${periodText}`, "", "", "", ""],
    [],
    // Table header - T├üCH 2 Cß╗ÿT cho thuß║┐
    ["Ng├áy th├íng", "Nß╗Öi dung giao dß╗ïch", "B├ín h├áng h├│a", "Dß╗ïch vß╗Ñ", "Tß╗òng cß╗Öng"],
    ["A", "B", "1", "2", "3 = 1 + 2"],
  ];

  // Add entries with separated columns
  entries.forEach((entry) => {
    const isGoods = entry.type === "ban-hang" || entry.type === "ban-phu-tung";
    sheetData.push([
      formatDate(entry.date.toISOString()),
      entry.description,
      isGoods ? entry.amount : "",      // Cß╗Öt B├ín h├áng h├│a
      !isGoods ? entry.amount : "",     // Cß╗Öt Dß╗ïch vß╗Ñ
      entry.amount,                      // Tß╗òng
    ]);
  });

  // Add empty rows for manual entries (total 5 empty rows)
  for (let i = 0; i < Math.max(0, 5 - entries.length); i++) {
    sheetData.push(["", "", "", "", ""]);
  }

  // Total row
  sheetData.push(["", "Tß╗öNG Cß╗ÿNG", totalGoods, totalServices, totalRevenue]);
  sheetData.push([]);
  
  // Summary for tax declaration
  sheetData.push(["", "T├ôM Tß║«T K├è KHAI THUß║╛:", "", "", ""]);
  sheetData.push(["", "- Doanh thu b├ín h├áng h├│a (thuß║┐ suß║Ñt thß║Ñp):", totalGoods, "", ""]);
  sheetData.push(["", "- Doanh thu dß╗ïch vß╗Ñ (thuß║┐ suß║Ñt cao):", "", totalServices, ""]);
  sheetData.push([]);
  sheetData.push([]);

  // Signature section
  const today = new Date();
  sheetData.push(["", "", "", `Ng├áy ${today.getDate()} th├íng ${today.getMonth() + 1} n─âm ${today.getFullYear()}`, ""]);
  sheetData.push(["", "", "", "NG╞»ß╗£I ─Éß║áI DIß╗åN Hß╗ÿ KINH DOANH/", ""]);
  sheetData.push(["", "", "", "C├ü NH├éN KINH DOANH", ""]);
  sheetData.push(["", "", "", "(K├╜, hß╗ì t├¬n, ─æ├│ng dß║Ñu)", ""]);

  // Create worksheet
  const ws = XLSX.utils.aoa_to_sheet(sheetData);

  // Set column widths
  ws["!cols"] = [
    { wch: 12 },  // Ng├áy th├íng
    { wch: 55 },  // Nß╗Öi dung giao dß╗ïch
    { wch: 18 },  // B├ín h├áng h├│a
    { wch: 18 },  // Dß╗ïch vß╗Ñ
    { wch: 18 },  // Tß╗òng cß╗Öng
  ];

  // Merge cells for header
  ws["!merges"] = [
    { s: { r: 5, c: 0 }, e: { r: 5, c: 3 } }, // Title row
    { s: { r: 6, c: 0 }, e: { r: 6, c: 3 } }, // Business location
    { s: { r: 7, c: 0 }, e: { r: 7, c: 3 } }, // Period
  ];

  XLSX.utils.book_append_sheet(wb, ws, "S1a-HKD");

  // Create filename
  const monthStr = startMonth.toString().padStart(2, "0");
  const fileName = `SoDoanhThu_S1a-HKD_T${monthStr}_${year}.xlsx`;
  XLSX.writeFile(wb, fileName);

  return {
    fileName,
    totalRevenue,
    totalGoods,
    totalServices,
    transactionCount: entries.length,
    period: periodText,
  };
};

/**
 * Mobile Haptic Feedback Utility
 * Uses the Vibration API to provide tactile feedback
 */

type HapticType = 'success' | 'error' | 'warning' | 'selection' | 'light' | 'medium' | 'heavy';

export const triggerHaptic = (type: HapticType = 'selection') => {
    // Check if vibration is supported
    if (typeof navigator === 'undefined' || !navigator.vibrate) {
        return;
    }

    try {
        switch (type) {
            case 'success':
                // Two short vibrations
                navigator.vibrate([10, 50, 20]);
                break;
            case 'error':
                // Long vibration
                navigator.vibrate([50, 100, 50, 100]);
                break;
            case 'warning':
                navigator.vibrate(100);
                break;
            case 'selection':
            case 'light':
                navigator.vibrate(10);
                break;
            case 'medium':
                navigator.vibrate(20);
                break;
            case 'heavy':
                navigator.vibrate(40);
                break;
        }
    } catch (e) {
        // Ignore errors (e.g. if user interaction is required first)
        console.debug('Haptic feedback failed:', e);
    }
};

import jsPDF from "jspdf";
